// Release builds keep shell controls anchored in-header unless explicitly re-enabled.
const FLOATING_SHELL_APPLETS_ENABLED =
  process.env.NEXT_PUBLIC_FLOATING_SHELL_APPLETS === "1" ||
  process.env.NODE_ENV !== "production";
