const COFFEE_POLL_BUBBLE_DRAG_SUPPRESS_CLICK_PX = 6;

/** Browser default for Coffee table-tuning sliders before a live session loads from the API. */
const PRISM_COFFEE_SESSION_SETTINGS_STORAGE_KEY = "prism_coffee_session_settings_v1";
const PRISM_COFFEE_PAUSED_SESSION_IDS_STORAGE_KEY = "prism_coffee_paused_session_ids_v1";
const PRISM_COFFEE_PAUSED_SESSION_REMAINING_MS_STORAGE_KEY =
  "prism_coffee_paused_session_remaining_ms_v1";

function loadCoffeeSettingsFromBrowser(): CoffeeSessionSettings {
  if (typeof window === "undefined") {
    return normalizeCoffeeSessionSettings(undefined);
  }
  try {
    const raw = window.localStorage.getItem(PRISM_COFFEE_SESSION_SETTINGS_STORAGE_KEY);
    if (!raw) return normalizeCoffeeSessionSettings(undefined);
    return normalizeCoffeeSessionSettings(JSON.parse(raw) as unknown);
  } catch {
    return normalizeCoffeeSessionSettings(undefined);
  }
}

function persistCoffeeSettingsToBrowser(settings: CoffeeSessionSettings): void {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.setItem(
      PRISM_COFFEE_SESSION_SETTINGS_STORAGE_KEY,
      JSON.stringify(settings)
    );
  } catch {
    // Private mode / quota — ignore; current session state still applies.
  }
}

function loadCoffeePausedSessionIdsFromBrowser(): Set<string> {
  if (typeof window === "undefined") return new Set<string>();
  try {
    window.localStorage.removeItem(PRISM_COFFEE_PAUSED_SESSION_IDS_STORAGE_KEY);
  } catch {
    // Private mode / quota — ignore; paused sessions are no longer resumed.
  }
  return new Set<string>();
}

function persistCoffeePausedSessionIdsToBrowser(sessionIds: Set<string>): void {
  if (typeof window === "undefined") return;
  try {
    if (sessionIds.size === 0) {
      window.localStorage.removeItem(PRISM_COFFEE_PAUSED_SESSION_IDS_STORAGE_KEY);
      return;
    }
    window.localStorage.setItem(
      PRISM_COFFEE_PAUSED_SESSION_IDS_STORAGE_KEY,
      JSON.stringify(Array.from(sessionIds))
    );
  } catch {
    // Private mode / quota — ignore; in-memory state still applies.
  }
}

function loadCoffeePausedSessionRemainingMsByIdFromBrowser(): Record<string, number> {
  if (typeof window === "undefined") return {};
  try {
    window.localStorage.removeItem(PRISM_COFFEE_PAUSED_SESSION_REMAINING_MS_STORAGE_KEY);
  } catch {
    // Private mode / quota — ignore; paused sessions are no longer resumed.
  }
  return {};
}

function persistCoffeePausedSessionRemainingMsByIdToBrowser(
  remainingById: Record<string, number>
): void {
  if (typeof window === "undefined") return;
  try {
    if (Object.keys(remainingById).length === 0) {
      window.localStorage.removeItem(PRISM_COFFEE_PAUSED_SESSION_REMAINING_MS_STORAGE_KEY);
      return;
    }
    window.localStorage.setItem(
      PRISM_COFFEE_PAUSED_SESSION_REMAINING_MS_STORAGE_KEY,
      JSON.stringify(remainingById)
    );
  } catch {
    // Private mode / quota — ignore; in-memory state still applies.
  }
}

/** Treat sessions with a topic or any message as started, so preview can separate Join vs Review states. */
function coffeeSessionHasStarted(conversation: CoffeeConversationState | null): boolean {
  if (!conversation) return false;
  if (typeof conversation.coffeeTopic === "string" && conversation.coffeeTopic.trim().length > 0) {
    return true;
  }
  return conversation.messages.length > 0;
}

/** Post-send rhythm gap before the table “types” the next card (scales with breathing room). */
function coffeeSendCooldownMs(settings: CoffeeSessionSettings): number {
  const room = settings.breathingRoom / 100;
  return Math.round(COFFEE_SEND_COOLDOWN_MS * (0.82 + room * 0.45));
}

/** Formats remaining milliseconds as m:ss for the Coffee session dock timer. */
function formatCoffeeSessionRemainingMs(remainingMs: number): string {
  const totalSec = Math.max(0, Math.floor(remainingMs / 1000));
  const m = Math.floor(totalSec / 60);
  const s = totalSec % 60;
  return `${m}:${s.toString().padStart(2, "0")}`;
}

function formatMoodIgnoreRemainingMs(remainingMs: number): string {
  const totalSec = Math.max(0, Math.ceil(remainingMs / 1000));
  const m = Math.floor(totalSec / 60);
  const s = totalSec % 60;
  return `${m}:${s.toString().padStart(2, "0")}`;
}

function coffeeSessionDurationMs(
  conversation: Pick<CoffeeConversationState, "coffeeSessionDurationMinutes"> | null | undefined
): number {
  const minutes = conversation?.coffeeSessionDurationMinutes;
  if (minutes === 2 || minutes === 3 || minutes === 5) {
    return minutes * 60 * 1000;
  }
  return COFFEE_SESSION_DURATION_MS;
}

function randomCoffeeAutonomousDelayMs(
  settings: CoffeeSessionSettings,
  delayMultiplier = 1
): number {
  const speed = Math.max(0, Math.min(1, settings.responseDelayBias / 100));
  const room = Math.max(0, Math.min(1, settings.breathingRoom / 100));
  const minMs = Math.round(
    COFFEE_REPLY_DELAY_MIN_MS +
      (COFFEE_REPLY_DELAY_FAST_MIN_MS - COFFEE_REPLY_DELAY_MIN_MS) * speed
  );
  const maxMs = Math.round(
    COFFEE_REPLY_DELAY_MAX_MS +
      (COFFEE_REPLY_DELAY_FAST_MAX_MS - COFFEE_REPLY_DELAY_MAX_MS) * speed
  );
  const range = Math.max(0, maxMs - minMs);
  const delayUnit =
    settings.crossTalk === "chatty"
      ? Math.min(Math.random(), Math.random())
      : Math.max(Math.random(), Math.random());
  let ms = minMs + Math.floor(delayUnit * range);
  const crossScale =
    settings.crossTalk === "chatty" ? 0.72 : settings.crossTalk === "rare" ? 1.12 : 1;
  const roomScale = 0.82 + room * 0.55;
  ms = Math.round(ms * crossScale * roomScale * delayMultiplier);
  return Math.max(
    settings.crossTalk === "chatty" && settings.responseDelayBias >= 95 ? 450 : minMs,
    Math.min(Math.round(maxMs * 1.35), ms)
  );
}

function normalizeCoffeeTypewriterMoodKey(moodKey: BotMoodKey | undefined): BotMoodKey {
  if (
    moodKey === "joyful" ||
    moodKey === "warm" ||
    moodKey === "neutral" ||
    moodKey === "guarded" ||
    moodKey === "strained"
  ) {
    return moodKey;
  }
  return "neutral";
}

/**
 * Coffee typewriter duration is mood-driven (chars/second by mood), then lightly
 * jittered so lines feel less robotic. Message length only affects total time
 * proportionally; it does not increase typing *speed* for longer lines.
 */
function randomCoffeeRevealDelayMs(messageText: string, moodKey: BotMoodKey | undefined): number {
  const displayText = extractStageDirections(messageText).mainText;
  const charCount = Math.max(1, getBotMentionDisplayLength(displayText));
  const mood = normalizeCoffeeTypewriterMoodKey(moodKey);
  const charsPerSecond = COFFEE_MOOD_TYPEWRITER_CHARS_PER_SECOND[mood];
  const baseMs = Math.round((charCount / Math.max(1, charsPerSecond)) * 1000);
  const jitterMs = Math.round((Math.random() * 2 - 1) * 120);
  return Math.max(
    COFFEE_BOT_REVEAL_DELAY_MIN_MS,
    Math.min(COFFEE_BOT_REVEAL_DELAY_MAX_MS, baseMs + jitterMs)
  );
}

function clampCoffeePollPanelPosition(
  x: number,
  y: number,
  width: number,
  height: number,
  viewportWidth: number,
  viewportHeight: number
): CoffeePollPanelPosition {
  const margin = 12;
  return {
    x: Math.max(margin, Math.min(viewportWidth - width - margin, x)),
    y: Math.max(margin, Math.min(viewportHeight - height - margin, y)),
  };
}

function emptyCoffeeSeatBotIds(): Array<string | null> {
  return Array.from({ length: COFFEE_GROUP_MAX_SIZE_CLIENT }, () => null);
}

function coffeeSeatsFromBotIds(botIds: readonly string[] | undefined): Array<string | null> {
  const seats = emptyCoffeeSeatBotIds();
  for (let index = 0; index < Math.min(seats.length, botIds?.length ?? 0); index += 1) {
    seats[index] = botIds?.[index] ?? null;
  }
  return seats;
}

function coffeeCupRotationBias(seed: string): string {
  const unit = stableUnitValue(seed);
  const degrees = Math.round((unit * 2 - 1) * COFFEE_CUP_ROTATION_BIAS_DEGREES);
  return `${degrees}deg`;
}

