function clearLegacyZenInitialStarterCachedReply(userId: string): void {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.removeItem(zenInitialStarterCacheKey(userId));
  } catch {
    // Ignore unavailable storage.
  }
}

