function PanelSectionInfo({
  id,
  label,
  variant = "section",
  children,
}: {
  id: string;
  label: string;
  variant?: "section" | "control";
  children: string;
}): React.JSX.Element {
  return (
    <span className={styles.panelSectionInfo} data-variant={variant}>
      <span
        className={styles.panelSectionInfoButton}
        tabIndex={0}
        aria-label={label}
        aria-describedby={id}
      >
        <Info size={14} strokeWidth={2.1} aria-hidden="true" />
      </span>
      <span id={id} className={styles.panelSectionInfoTooltip} role="tooltip">
        {children}
      </span>
    </span>
  );
}

function inferDevChatDebugKind(event: DevChatDebugEvent): DevChatDebugEvent["kind"] {
  if (
    event.kind === "summary" ||
    event.kind === "memory" ||
    event.kind === "opinion" ||
    event.kind === "tool" ||
    event.kind === "backend"
  ) {
    return event.kind;
  }
  const line = event.text.toLowerCase();
  if (line.includes("backend") || line.includes("/api/") || line.includes("route")) return "backend";
  if (line.includes("tool")) return "tool";
  if (line.includes("summary")) return "summary";
  if (line.includes("memories") || line.includes("memory")) return "memory";
  return "opinion";
}

function devDebugKindForBackendEvent(
  kind: ChatBackendDebugEvent["kind"]
): DevChatDebugEvent["kind"] {
  if (kind === "memory") return "memory";
  if (kind === "summary") return "summary";
  if (kind === "tool") return "tool";
  return "backend";
}

/// Compose a single human-readable dev-metrics line for a tool-call diagnostic event.
function formatChatToolCallDebugLine(prefix: string, event: ChatToolCallEvent): string {
  const parts: string[] = [`${prefix} tool ${event.name}: ${event.status}`];
  if (event.jobId) parts.push(`jobId=${event.jobId}`);
  if (event.prompt && event.prompt.length > 0) parts.push(`prompt="${event.prompt}"`);
  if (event.detail && event.detail.length > 0) parts.push(event.detail);
  return parts.join(" — ");
}

function formatBackendDebugLine(prefix: string, event: ChatBackendDebugEvent): string {
  const parts = [`${prefix} backend ${event.kind}: ${event.message}`];
  if (event.detail && event.detail.length > 0) parts.push(event.detail);
  parts.push(`${event.elapsedMs}ms`);
  return parts.join(" — ");
}
