function normalizeCommandAliasList(
  aliases: unknown,
  primaryName: string
): string[] {
  if (!Array.isArray(aliases)) return [];
  const normalized: string[] = [];
  const seen = new Set<string>();
  for (const alias of aliases) {
    if (typeof alias !== "string") continue;
    const name = normalizeCommandNameInput(alias);
    if (!name || name === primaryName || seen.has(name)) continue;
    seen.add(name);
    normalized.push(name);
  }
  return normalized.slice(0, 8);
}

function sanitizeCommandAliasesForList(
  commands: readonly CommandCenterCommand[]
): CommandCenterCommand[] {
  const primaryNames = new Set(commands.map((command) => command.name));
  const claimedAliases = new Set<string>();
  return commands.map((command) => {
    const aliases: string[] = [];
    for (const alias of command.aliases) {
      if (!alias || alias === command.name) continue;
      if (primaryNames.has(alias)) continue;
      if (claimedAliases.has(alias)) continue;
      if (!command.builtIn && BUILT_IN_COMMAND_RESERVED_NAMES.has(alias)) continue;
      claimedAliases.add(alias);
      aliases.push(alias);
    }
    return { ...command, aliases };
  });
}

function commandInvocationNames(command: CommandCenterCommand): string[] {
  return [command.name, ...command.aliases].filter(Boolean);
}

function isCommandCenterOperationalCommand(command: CommandCenterCommand): boolean {
  return command.builtIn || command.readOnly;
}

function isCommandCenterPromptShortcut(command: CommandCenterCommand): boolean {
  return !command.builtIn && !command.readOnly;
}

function isComposerWildcardDeckPick(command: CommandCenterCommand): boolean {
  return command.id.startsWith("wildcard:");
}

function isComposerTrueWildcardSlotPick(command: CommandCenterCommand): boolean {
  return command.id.startsWith("wildcard-slot:");
}

function composerTrueWildcardSlotKey(
  command: CommandCenterCommand
): BuiltInPromptWildcardSlotKey | null {
  if (!isComposerTrueWildcardSlotPick(command)) return null;
  const key = command.id.slice("wildcard-slot:".length);
  return BUILT_IN_PROMPT_WILDCARD_SLOTS.some((slot) => slot.key === key)
    ? (key as BuiltInPromptWildcardSlotKey)
    : null;
}

function composerTrueWildcardSlotFallback(command: CommandCenterCommand): string {
  return command.command.trim() || `{${command.name}}`;
}

function composerCommandDisplayName(command: CommandCenterCommand): string {
  return command.name;
}

const PENDING_COMPOSER_WILDCARD_SLOT_TEXT = "{LOADING}";

function composerShortcutInvocationPrefix(command: CommandCenterCommand): "/" | "!" {
  return isComposerWildcardDeckPick(command) || isComposerTrueWildcardSlotPick(command)
    ? "!"
    : "/";
}

function composerCommandPickKind(
  command: CommandCenterCommand
): "command" | "prompt" | "wildcard" | "wildcard-slot" {
  if (isComposerTrueWildcardSlotPick(command)) return "wildcard-slot";
  if (isComposerWildcardDeckPick(command)) return "wildcard";
  return isCommandCenterOperationalCommand(command) ? "command" : "prompt";
}

function composerShortcutInsertionText(command: CommandCenterCommand): string {
  if (isComposerTrueWildcardSlotPick(command)) {
    return `${composerTrueWildcardSlotFallback(command)} `;
  }
  return `${composerShortcutInvocationPrefix(command)}${command.name} `;
}

const BUILT_IN_WILDCARD_SLOT_PICKS: CommandCenterCommand[] =
  BUILT_IN_PROMPT_WILDCARD_SLOTS.map((slot) => ({
    id: `wildcard-slot:${slot.key}`,
    name: slot.label,
    title: slot.title,
    command: `{${slot.label}}`,
    aliases: [...slot.aliases],
    arguments: [],
    builtIn: true,
    readOnly: true,
    createdAt: "built-in",
    updatedAt: "built-in",
  }));

function commandCenterWildcardDeckPick(deck: CommandCenterWildcardDeck): CommandCenterCommand {
  const now = deck.updatedAt || deck.createdAt || new Date().toISOString();
  const sampleValues = deck.values.slice(0, 4).join(", ");
  const itemCountLabel = `${deck.values.length} item${deck.values.length === 1 ? "" : "s"}`;
  const description = deck.description.trim();
  return {
    id: `wildcard:${deck.id}`,
    name: deck.name,
    title: description
      ? `${description} · ${itemCountLabel}`
      : sampleValues
        ? `${itemCountLabel}: ${sampleValues}`
        : itemCountLabel,
    command: sampleValues,
    ...(deck.colorTag ? { colorTag: deck.colorTag } : {}),
    aliases: deck.aliases,
    arguments: [],
    builtIn: false,
    readOnly: false,
    createdAt: deck.createdAt || now,
    updatedAt: now,
  };
}

function collapseCommandCenterPromptsForDeletedWildcardDeck(
  commands: readonly CommandCenterCommand[],
  deck: CommandCenterWildcardDeck
): CommandCenterCommand[] {
  const now = new Date().toISOString();
  return commands.map((command) => {
    if (command.builtIn || command.readOnly || !command.command.includes("!")) {
      return command;
    }
    const collapsedCommand = collapseDeletedPromptWildcardDeckReferences(
      command.command,
      deck
    );
    return collapsedCommand === command.command
      ? command
      : {
          ...command,
          command: collapsedCommand,
          updatedAt: now,
        };
  });
}

function commandMatchesInvocationName(
  command: CommandCenterCommand,
  normalizedInvocationName: string
): boolean {
  return commandInvocationNames(command).some(
    (name) => name.toLowerCase() === normalizedInvocationName.toLowerCase()
  );
}

interface LeadingCommandChipMatch {
  command: CommandCenterCommand;
  commandStart: number;
  commandEnd: number;
}

function resolveLeadingCommandChipMatch(
  value: string,
  commands: readonly CommandCenterCommand[]
): LeadingCommandChipMatch | null {
  const firstLine = value.split(/\r?\n/u, 1)[0] ?? "";
  const match = /^(\s*)\/([a-z0-9][a-z0-9-]*)(?=\s|$)/iu.exec(firstLine);
  if (!match) return null;
  const normalizedName = normalizeCommandNameInput(match[2] ?? "");
  if (!normalizedName) return null;
  const command =
    commands.find((command) => commandMatchesInvocationName(command, normalizedName)) ??
    null;
  if (!command) return null;
  return {
    command,
    commandStart: match[1]?.length ?? 0,
    commandEnd: match[0].length,
  };
}

function clampTextAfterLeadingCommandChip(
  value: string,
  commands: readonly CommandCenterCommand[]
): string {
  const match = resolveLeadingCommandChipMatch(value, commands);
  if (!match) return value;
  if (value.length <= match.commandEnd) return value;
  const nextChar = value[match.commandEnd] ?? "";
  return `${value.slice(0, match.commandEnd)}${/\s/u.test(nextChar) ? " " : ""}`;
}

function normalizeCommandCenterState(raw: unknown): {
  preferredModel: string;
  commands: CommandCenterCommand[];
  wildcardDecks: CommandCenterWildcardDeck[];
} {
  const fallbackHelp = createBuiltInHelpCommand();
  const builtInCommands = [
    fallbackHelp,
    createBuiltInCompactCommand(),
    createBuiltInClearCommand(),
    createBuiltInAtmosphereCommand(),
    createBuiltInRefreshCommand(),
    createBuiltInRestartCommand(),
    createBuiltInNewSessionCommand(),
    createBuiltInForgiveMeCommand(),
  ];
  const parsed: CommandCenterStateV1 | null =
    raw && typeof raw === "object" ? (raw as CommandCenterStateV1) : null;
  const preferredModel = normalizeCommandCenterPreferredModelChoice(
    parsed?.preferredModel
  );
  const commandListRaw = Array.isArray(parsed?.commands) ? parsed.commands : [];
  const seen = new Set<string>();
  const commands: CommandCenterCommand[] = [];
  for (const candidate of commandListRaw) {
    if (!candidate || typeof candidate !== "object") continue;
    const record = candidate as Partial<CommandCenterCommand>;
    const name = typeof record.name === "string" ? record.name.trim().toLowerCase() : "";
    const normalizedName =
      name.startsWith("/") ? name.slice(1).trim() : name.trim();
    if (!normalizedName) continue;
    if (seen.has(normalizedName)) continue;
    seen.add(normalizedName);
    const now = new Date().toISOString();
    const colorTag = normalizeCommandCenterColorTag(record.colorTag);
    commands.push({
      id:
        typeof record.id === "string" && record.id.trim().length > 0
          ? record.id.trim()
          : `cmd:${normalizedName}`,
      name: normalizedName,
      title:
        typeof record.title === "string" && record.title.trim().length > 0
          ? record.title.trim()
          : normalizedName,
      command: typeof record.command === "string" ? record.command : "",
      ...(colorTag ? { colorTag } : {}),
      aliases: normalizeCommandAliasList(
        (record as Partial<CommandCenterCommand> & { aliases?: unknown }).aliases,
        normalizedName
      ),
      arguments: [],
      builtIn: record.builtIn === true || BUILT_IN_COMMAND_RESERVED_NAMES.has(normalizedName),
      readOnly: record.readOnly === true || BUILT_IN_COMMAND_RESERVED_NAMES.has(normalizedName),
      createdAt: typeof record.createdAt === "string" ? record.createdAt : now,
      updatedAt: typeof record.updatedAt === "string" ? record.updatedAt : now,
    });
  }
  for (const builtIn of builtInCommands) {
    const existing = commands.find((command) => command.name === builtIn.name);
    if (existing) {
      existing.id = builtIn.id;
      existing.title = builtIn.title;
      existing.command = builtIn.command;
      existing.aliases = builtIn.aliases;
      existing.arguments = builtIn.arguments;
      existing.builtIn = true;
      existing.readOnly = true;
      continue;
    }
    commands.push(builtIn);
  }
  return {
    preferredModel,
    commands: sanitizeCommandAliasesForList([
      ...builtInCommands,
      ...commands.filter((command) => !BUILT_IN_COMMAND_RESERVED_NAMES.has(command.name)),
    ]),
    wildcardDecks: normalizeWildcardDecks(parsed?.wildcardDecks),
  };
}

function createUserCommandDraft(existingCommands: readonly CommandCenterCommand[]): CommandCenterCommand {
  const existing = new Set(
    existingCommands.flatMap((command) =>
      commandInvocationNames(command).map((name) => name.trim().toLowerCase())
    )
  );
  for (const reserved of BUILT_IN_COMMAND_RESERVED_NAMES) {
    existing.add(reserved);
  }
  let index = 1;
  let nextName = "prompt";
  while (existing.has(nextName)) {
    index += 1;
    nextName = `prompt-${index}`;
  }
  const now = new Date().toISOString();
  const id =
    typeof crypto !== "undefined" && typeof crypto.randomUUID === "function"
      ? `cmd:${crypto.randomUUID()}`
      : `cmd:${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
  return {
    id,
    name: nextName,
    title: nextName,
    command: "",
    colorTag: undefined,
    aliases: [],
    arguments: [],
    builtIn: false,
    readOnly: false,
    createdAt: now,
    updatedAt: now,
  };
}

function normalizeCommandNameInput(value: string): string {
  const stripped = value.trim().toLowerCase().replace(/^\/+/, "");
  return stripped.replace(/\s+/g, "-");
}

function uniqueCommandNameForList(
  requestedName: string,
  commands: readonly CommandCenterCommand[],
  editingCommandId: string
): string {
  const base = normalizeCommandNameInput(requestedName) || "prompt";
  const used = new Set(
    commands
      .filter((command) => command.id !== editingCommandId)
      .flatMap((command) =>
        commandInvocationNames(command).map((name) => name.trim().toLowerCase())
      )
      .filter(Boolean)
  );
  for (const reserved of BUILT_IN_COMMAND_RESERVED_NAMES) {
    used.add(reserved);
  }
  if (!used.has(base)) return base;
  let index = 2;
  let candidate = `${base}-${index}`;
  while (used.has(candidate)) {
    index += 1;
    candidate = `${base}-${index}`;
  }
  return candidate;
}

function commandCenterPromptHasRequiredDetails(
  command: CommandCenterCommand
): boolean {
  return (
    normalizeCommandNameInput(command.name).length > 0 &&
    command.command.trim().length > 0
  );
}

function commandCenterPromptDraftHasRequiredDetails(
  draft: CommandCenterEditableDraft | null
): boolean {
  return Boolean(
    draft &&
      normalizeCommandNameInput(draft.name).length > 0 &&
      draft.command.trim().length > 0
  );
}

function commandCenterWildcardDeckHasRequiredDetails(
  deck: CommandCenterWildcardDeck
): boolean {
  return (
    normalizeWildcardDeckNameInput(deck.name).length > 0 &&
    deck.values.length > 0
  );
}

function commandCenterWildcardDeckDraftHasRequiredDetails(
  draft: CommandCenterWildcardDeckDraft | null
): boolean {
  return Boolean(
    draft &&
      normalizeWildcardDeckNameInput(draft.name).length > 0 &&
      normalizeWildcardDeckValueList(draft.valuesText).length > 0
  );
}

function commandCenterCanAddAlias(
  aliases: readonly string[],
  primaryName: string,
  normalizeName: (value: string) => string
): boolean {
  return (
    normalizeName(primaryName).length > 0 &&
    aliases.length < 8 &&
    aliases.every((alias) => normalizeName(alias).length > 0)
  );
}

function commandCenterAliasIssueMap<T>(
  aliases: readonly string[],
  primaryName: string,
  items: readonly T[],
  editingItemId: string,
  normalizeName: (value: string) => string,
  getItemId: (item: T) => string,
  getItemInvocationNames: (item: T) => readonly string[],
  prefix: "/" | "!"
): Map<number, string> {
  const issues = new Map<number, string>();
  const primaryKey = normalizeName(primaryName).toLowerCase();
  const existingNames = new Map<string, string>();
  for (const item of items) {
    if (getItemId(item) === editingItemId) continue;
    for (const invocationName of getItemInvocationNames(item)) {
      const normalized = normalizeName(invocationName);
      if (!normalized) continue;
      const key = normalized.toLowerCase();
      if (!existingNames.has(key)) {
        existingNames.set(key, `${prefix}${normalized}`);
      }
    }
  }

  const draftNames = new Set<string>();
  aliases.forEach((alias, index) => {
    const normalized = normalizeName(alias);
    const key = normalized.toLowerCase();
    if (!normalized) {
      issues.set(index, "Finish this alias.");
      return;
    }
    if (key === primaryKey) {
      issues.set(index, `Already used by ${prefix}${normalizeName(primaryName)}.`);
      return;
    }
    const existingName = existingNames.get(key);
    if (existingName) {
      issues.set(index, `Already used by ${existingName}.`);
      return;
    }
    if (draftNames.has(key)) {
      issues.set(index, "Already added as an alias here.");
      return;
    }
    draftNames.add(key);
  });
  return issues;
}

function botImportUtf8ByteLength(text: string): number {
  return new TextEncoder().encode(text).length;
}

function stripOptionalLeadingUtf8Bom(text: string): string {
  return text.charCodeAt(0) === 0xfeff ? text.slice(1) : text;
}

function normalizeImportedBotHash(value: unknown): string | null {
  if (typeof value !== "string") return null;
  const trimmed = value.trim().toLowerCase();
  return /^[a-f0-9]{32}$/.test(trimmed) ? trimmed : null;
}

function normalizeImportedMemorySource(
  source: BotExportMemory["source"] | undefined
): "direct" | "inferred" | "compiled" {
  return source === "inferred" || source === "compiled" || source === "direct"
    ? source
    : "compiled";
}

function normalizeImportedMemoryCategory(
  category: BotExportMemory["category"] | undefined
): MemoryCategory {
  if (category === "general" || category === "user" || category === "bot_relation") {
    return category;
  }
  // Bot-export payloads often omit category; for imported bot memories, default
  // to "general" so second-person persona lines are not mistaken as "About you."
  return "general";
}

function createClientBotExportHash(): string {
  if (typeof crypto !== "undefined" && typeof crypto.getRandomValues === "function") {
    const bytes = new Uint8Array(16);
    crypto.getRandomValues(bytes);
    return Array.from(bytes, (byte) => byte.toString(16).padStart(2, "0")).join("");
  }
  // Browser crypto should always exist here; this fallback is defensive only.
  return `${Math.random().toString(16).slice(2)}${Math.random().toString(16).slice(2)}`
    .slice(0, 32)
    .padEnd(32, "0");
}

