function blankBotProfile(): BotProfileFields {
  return parseStoredBotPrompt("").fields;
}

function randomArrayItem<T>(values: readonly T[]): T {
  return values[Math.floor(Math.random() * values.length)] ?? values[0];
}

function randomBotTemperatureSetting(): number {
  return randomArrayItem(BOT_RANDOM_TEMPERATURES);
}

function randomBotReplyLengthTokens(): number {
  return randomArrayItem(BOT_REPLY_LENGTH_PRESETS).tokens;
}

function profileTextFilled(...values: Array<string | null | undefined>): number {
  return values.filter((value) => typeof value === "string" && value.trim()).length;
}

function normalizeBotBirthYearInput(value: string): string {
  return value.replace(/\D/g, "").slice(0, BOT_BIRTH_YEAR_MAX_DIGITS);
}

function displayBirthYearFromIsoDate(value: string): string {
  const match = value.match(/^(\d{4})-\d{2}-\d{2}$/);
  if (!match) return "";
  return String(Number(match[1]));
}

function isoYearFromBirthYear(value: string): string | null {
  if (!value || value.length > HTML_DATE_YEAR_DIGITS) return null;
  return value.padStart(HTML_DATE_YEAR_DIGITS, "0");
}

function profileScaleFilled(...values: Array<BotProfileScaleValue | null>): number {
  return values.filter((value) => value !== null).length;
}

function botProfileCategoryCount(
  profile: BotProfileFields,
  category: BotProfileBuilderPageId
): number {
  switch (category) {
    case "purpose":
      return profileTextFilled(profile.purpose.statement, profile.purpose.legacyNotes);
    case "personality":
      return (
        profileTextFilled(
          profile.core.traits,
          profile.core.interests,
          profile.core.boundaries,
          profile.core.quirks
        ) + profileScaleFilled(
          profile.core.openness,
          profile.core.conscientiousness,
          profile.core.extraversion,
          profile.core.agreeableness,
          profile.core.emotionalStability
        )
      );
    case "character":
      return (
        profileTextFilled(
          profile.identity.role,
          profile.identity.background,
          profile.worldview.values,
          profile.appearance.description
        )
        + profileScaleFilled(
          profile.worldview.politicalView,
          profile.worldview.optimism,
          profile.worldview.tradition
        )
      );
    case "facts":
      return botProfileFactCount(profile);
    default:
      return 0;
  }
}

function botProfileFactCount(profile: BotProfileFields): number {
  let count = 0;
  if (profile.facts?.basedOnRealPersonOrCharacter) count += 1;
  if (profile.facts?.birthday?.trim() || profile.facts?.birthYear?.trim()) count += 1;
  for (const fact of profile.facts?.customFacts ?? []) {
    if (fact?.label?.trim() || fact?.value?.trim()) count += 1;
  }
  return count;
}

function botProfileCategorySummary(
  profile: BotProfileFields,
  category: BotProfileBuilderPageId,
  botName: string
): string {
  const count = botProfileCategoryCount(profile, category);
  if (category === "purpose") {
    return profile.purpose.statement.trim() || defaultBotPurpose(botName) || "Name the bot to seed a purpose";
  }
  if (count === 0) return "No details yet";
  return count === 1 ? "1 detail set" : `${count} details set`;
}

function botProfileCategoryComplete(
  profile: BotProfileFields,
  category: BotProfileBuilderPageId,
  botName: string
): boolean {
  if (category === "purpose") {
    return Boolean(profile.purpose.statement.trim() || botName.trim());
  }
  return botProfileCategoryCount(profile, category) > 0;
}

function botProfileCompletionCount(profile: BotProfileFields): number {
  return BOT_PROFILE_BUILDER_PAGE_ORDER.reduce(
    (total, category) => total + (botProfileCategoryCount(profile, category) > 0 ? 1 : 0),
    0
  );
}

/** True if the top bot form has any user-authored create-mode content. */
function createBotFormHasEnteredData(options: {
  name: string;
  profile: BotProfileFields;
  localModel: string;
  onlineModel: string;
  onlineEnabled: boolean;
  deleteProtected: boolean;
  flirtEnabled: boolean;
  temperature: number;
  maxTokens: number;
}): boolean {
  if (options.name.trim().length > 0) return true;
  if (botProfileCompletionCount(options.profile) > 0) return true;
  if (options.localModel !== AUTO_MODEL_CHOICE) return true;
  if (options.onlineModel !== AUTO_MODEL_CHOICE) return true;
  if (!options.onlineEnabled) return true;
  if (options.deleteProtected) return true;
  if (options.flirtEnabled) return true;
  if (options.temperature !== BOT_TEMPERATURE_DEFAULT) return true;
  if (options.maxTokens !== BOT_REPLY_LENGTH_DEFAULT_TOKENS) return true;
  return false;
}

function normalizeBotTemperature(value: number | null | undefined): number {
  if (typeof value !== "number" || !Number.isFinite(value)) {
    return BOT_TEMPERATURE_DEFAULT;
  }
  const clamped = Math.min(
    BOT_TEMPERATURE_MAX,
    Math.max(BOT_TEMPERATURE_MIN, value)
  );
  return Number(clamped.toFixed(2));
}

function botTemperatureLabel(value: number): string {
  if (value <= 0.35) return "Focused";
  if (value >= 0.9) return "Adventurous";
  return "Balanced";
}

function botTemperatureDescription(value: number): string {
  if (value <= 0.35) {
    return "Stays close to your instructions and repeats itself less.";
  }
  if (value >= 0.9) {
    return "More willing to riff, surprise you, and try unusual phrasing.";
  }
  return "A middle path: steady enough for usefulness, lively enough for personality.";
}

function normalizeBotMaxTokens(value: number | null | undefined): number {
  if (typeof value !== "number" || !Number.isFinite(value) || value <= 0) {
    return BOT_REPLY_LENGTH_DEFAULT_TOKENS;
  }
  return Math.round(value);
}

function botReplyLengthPresetForTokens(tokens: number) {
  return BOT_REPLY_LENGTH_PRESETS.find((preset) => preset.tokens === tokens) ?? null;
}

function normalizeModelChoice(value: string | null | undefined): string {
  const trimmed = value?.trim() ?? "";
  return trimmed.length > 0 ? trimmed : AUTO_MODEL_CHOICE;
}

function normalizeZenWallpaperOpacitySetting(value: unknown): number {
  const parsed =
    typeof value === "number"
      ? value
      : typeof value === "string"
        ? Number(value.trim())
        : Number.NaN;
  const normalized = Number.isFinite(parsed) ? parsed : DEFAULT_ZEN_WALLPAPER_OPACITY;
  const clamped = Math.min(
    MAX_ZEN_WALLPAPER_OPACITY,
    Math.max(MIN_ZEN_WALLPAPER_OPACITY, normalized)
  );
  return Number(clamped.toFixed(2));
}

function normalizeZenWallpaperTextMaskSetting(value: unknown): boolean {
  if (typeof value === "boolean") return value;
  if (typeof value === "number" && Number.isFinite(value)) return value !== 0;
  if (typeof value === "string") {
    const normalized = value.trim().toLowerCase();
    if (normalized === "true" || normalized === "1" || normalized === "yes") {
      return true;
    }
    if (normalized === "false" || normalized === "0" || normalized === "no") {
      return false;
    }
  }
  return DEFAULT_ZEN_WALLPAPER_TEXT_MASK_ENABLED;
}

function formatZenWallpaperOpacity(value: unknown): string {
  return `${Math.round(normalizeZenWallpaperOpacitySetting(value) * 100)}%`;
}

function normalizeIntegerSetting(
  value: unknown,
  fallback: number,
  min: number,
  max: number
): number {
  const parsed =
    typeof value === "number"
      ? value
      : typeof value === "string"
        ? Number(value.trim())
        : Number.NaN;
  const normalized = Number.isFinite(parsed) ? parsed : fallback;
  return Math.min(max, Math.max(min, Math.round(normalized)));
}

function normalizeZenSessionIdleGapSetting(value: unknown): number {
  return normalizeIntegerSetting(
    value,
    DEFAULT_ZEN_SESSION_IDLE_GAP_MS,
    MIN_ZEN_SESSION_IDLE_GAP_MS,
    MAX_ZEN_SESSION_IDLE_GAP_MS
  );
}

function normalizeZenFreshStartGapSetting(
  value: unknown,
  idleGapMs = DEFAULT_ZEN_SESSION_IDLE_GAP_MS
): number {
  const normalizedIdleGapMs = normalizeZenSessionIdleGapSetting(idleGapMs);
  const minFreshStartGapMs = Math.max(
    DEFAULT_ZEN_SESSION_IDLE_GAP_MS,
    normalizedIdleGapMs
  );
  return normalizeIntegerSetting(
    value,
    Math.max(DEFAULT_ZEN_FRESH_START_GAP_MS, minFreshStartGapMs),
    minFreshStartGapMs,
    MAX_ZEN_FRESH_START_GAP_MS
  );
}

function normalizeZenRecentContextMessagesSetting(value: unknown): number {
  return normalizeIntegerSetting(
    value,
    DEFAULT_ZEN_RECENT_CONTEXT_MESSAGES,
    MIN_ZEN_RECENT_CONTEXT_MESSAGES,
    MAX_ZEN_RECENT_CONTEXT_MESSAGES
  );
}

function normalizeZenWallpaperRegenMessageIntervalSetting(value: unknown): number {
  return normalizeIntegerSetting(
    value,
    DEFAULT_ZEN_WALLPAPER_REGEN_MESSAGE_INTERVAL,
    MIN_ZEN_WALLPAPER_REGEN_MESSAGE_INTERVAL,
    MAX_ZEN_WALLPAPER_REGEN_MESSAGE_INTERVAL
  );
}

function normalizeZenWallpaperRevealDelayMessageCountSetting(value: unknown): number {
  return normalizeIntegerSetting(
    value,
    DEFAULT_ZEN_WALLPAPER_REVEAL_DELAY_MESSAGE_COUNT,
    MIN_ZEN_WALLPAPER_REVEAL_DELAY_MESSAGE_COUNT,
    MAX_ZEN_WALLPAPER_REVEAL_DELAY_MESSAGE_COUNT
  );
}

function normalizeZenWallpaperRevealSpanMessageCountSetting(value: unknown): number {
  return normalizeIntegerSetting(
    value,
    DEFAULT_ZEN_WALLPAPER_REVEAL_SPAN_MESSAGE_COUNT,
    MIN_ZEN_WALLPAPER_REVEAL_SPAN_MESSAGE_COUNT,
    MAX_ZEN_WALLPAPER_REVEAL_SPAN_MESSAGE_COUNT
  );
}

function normalizeZenMoodSensitivitySetting(value: unknown): number {
  return normalizePrismMoodSensitivity(value, DEFAULT_ZEN_MOOD_SENSITIVITY);
}

function formatZenMoodSensitivity(value: unknown): string {
  return `${Math.round(normalizeZenMoodSensitivitySetting(value) * 100)}%`;
}

function defaultZenModeSettings(): ZenModeSettingsFields {
  return {
    zenWallpaperOpacity: DEFAULT_ZEN_WALLPAPER_OPACITY,
    zenWallpaperTextMaskEnabled: DEFAULT_ZEN_WALLPAPER_TEXT_MASK_ENABLED,
    zenSessionIdleGapMs: DEFAULT_ZEN_SESSION_IDLE_GAP_MS,
    zenFreshStartGapMs: DEFAULT_ZEN_FRESH_START_GAP_MS,
    zenRecentContextMessages: DEFAULT_ZEN_RECENT_CONTEXT_MESSAGES,
    zenWallpaperRegenMessageInterval: DEFAULT_ZEN_WALLPAPER_REGEN_MESSAGE_INTERVAL,
    zenWallpaperRevealDelayMessageCount:
      DEFAULT_ZEN_WALLPAPER_REVEAL_DELAY_MESSAGE_COUNT,
    zenWallpaperRevealSpanMessageCount:
      DEFAULT_ZEN_WALLPAPER_REVEAL_SPAN_MESSAGE_COUNT,
    zenMoodSensitivity: DEFAULT_ZEN_MOOD_SENSITIVITY,
  };
}

function modelChoiceSupportsReasoningEffort(
  provider: Provider,
  modelChoice: string
): boolean {
  return (
    provider === "openai" &&
    modelChoice !== AUTO_MODEL_CHOICE &&
    openAiModelSupportsReasoningEffort(modelChoice)
  );
}

function reasoningEffortForSend(
  provider: Provider,
  modelOverride: string | undefined,
  effort: ReasoningEffort
): ReasoningEffort | undefined {
  if (effort === DEFAULT_REASONING_EFFORT) return undefined;
  if (provider !== "openai" || !modelOverride) return undefined;
  return openAiModelSupportsReasoningEffort(modelOverride) ? effort : undefined;
}

function reasoningEffortSliderPosition(value: ReasoningEffort): number {
  const sliderValue = REASONING_EFFORT_SLIDER_VALUES.includes(
    value as (typeof REASONING_EFFORT_SLIDER_VALUES)[number]
  )
    ? (value as (typeof REASONING_EFFORT_SLIDER_VALUES)[number])
    : DEFAULT_MANUAL_REASONING_EFFORT;
  const index = REASONING_EFFORT_SLIDER_VALUES.indexOf(sliderValue);
  const safeIndex = Math.max(0, index);
  return (safeIndex / (REASONING_EFFORT_SLIDER_VALUES.length - 1)) *
    REASONING_EFFORT_SLIDER_MAX;
}

function reasoningEffortFromSliderPosition(position: number): ReasoningEffort {
  const normalized = Number.isFinite(position) ? position : 0;
  const clamped = Math.min(
    REASONING_EFFORT_SLIDER_MAX,
    Math.max(0, normalized)
  );
  const index = Math.round(
    (clamped / REASONING_EFFORT_SLIDER_MAX) *
      (REASONING_EFFORT_SLIDER_VALUES.length - 1)
  );
  return REASONING_EFFORT_SLIDER_VALUES[index] ?? DEFAULT_MANUAL_REASONING_EFFORT;
}

function normalizeZenModeSettingsFields(
  settings: Partial<ZenModeSettingsFields> | null | undefined
): ZenModeSettingsFields {
  const zenSessionIdleGapMs = normalizeZenSessionIdleGapSetting(
    settings?.zenSessionIdleGapMs
  );
  return {
    zenWallpaperOpacity: normalizeZenWallpaperOpacitySetting(
      settings?.zenWallpaperOpacity
    ),
    zenWallpaperTextMaskEnabled: normalizeZenWallpaperTextMaskSetting(
      settings?.zenWallpaperTextMaskEnabled
    ),
    zenSessionIdleGapMs,
    zenFreshStartGapMs: normalizeZenFreshStartGapSetting(
      settings?.zenFreshStartGapMs,
      zenSessionIdleGapMs
    ),
    zenRecentContextMessages: normalizeZenRecentContextMessagesSetting(
      settings?.zenRecentContextMessages
    ),
    zenWallpaperRegenMessageInterval:
      normalizeZenWallpaperRegenMessageIntervalSetting(
        settings?.zenWallpaperRegenMessageInterval
      ),
    zenWallpaperRevealDelayMessageCount:
      normalizeZenWallpaperRevealDelayMessageCountSetting(
        settings?.zenWallpaperRevealDelayMessageCount
      ),
    zenWallpaperRevealSpanMessageCount:
      normalizeZenWallpaperRevealSpanMessageCountSetting(
        settings?.zenWallpaperRevealSpanMessageCount
      ),
    zenMoodSensitivity: normalizeZenMoodSensitivitySetting(
      settings?.zenMoodSensitivity
    ),
  };
}

function formatZenDuration(value: unknown, kind: "idle" | "fresh" = "idle"): string {
  const ms =
    kind === "fresh"
      ? normalizeZenFreshStartGapSetting(value)
      : normalizeZenSessionIdleGapSetting(value);
  const hours = ms / (60 * 60 * 1000);
  if (hours < 24) return `${Math.round(hours * 10) / 10}h`;
  const days = ms / (24 * 60 * 60 * 1000);
  return `${Math.round(days * 10) / 10}d`;
}

function formatZenSessionMemoryExpiry(expiresAt: string): string {
  const expiresMs = Date.parse(expiresAt);
  if (!Number.isFinite(expiresMs)) return "expires soon";
  const remainingMs = expiresMs - Date.now();
  if (remainingMs <= 0) return "expired";
  const hours = remainingMs / (60 * 60 * 1000);
  if (hours < 1) {
    return "expires in under 1 hour";
  }
  if (hours < 24) {
    const roundedHours = Math.max(1, Math.round(hours));
    return `expires in ${roundedHours} hour${roundedHours === 1 ? "" : "s"}`;
  }
  const days = Math.ceil(hours / 24);
  return `expires in ${days} day${days === 1 ? "" : "s"}`;
}

function parseCommandCenterModelChoice(
  value: string
): { provider: Provider; modelId: string } | null {
  const normalized = normalizeModelChoice(value);
  if (normalized === AUTO_MODEL_CHOICE) return null;
  const separatorIndex = normalized.indexOf(":");
  if (separatorIndex <= 0) return null;
  const providerRaw = normalized.slice(0, separatorIndex).trim().toLowerCase();
  const modelId = normalized.slice(separatorIndex + 1).trim();
  if (!modelId) return null;
  if (providerRaw !== "local") return null;
  return {
    provider: "local",
    modelId,
  };
}

function normalizeCommandCenterPreferredModelChoice(value: string | null | undefined): string {
  const normalized = normalizeModelChoice(value);
  if (normalized === AUTO_MODEL_CHOICE) return AUTO_MODEL_CHOICE;
  const parsed = parseCommandCenterModelChoice(normalized);
  return parsed ? `local:${parsed.modelId}` : AUTO_MODEL_CHOICE;
}

function commandCenterAuxiliaryModelId(settings: UserSettings | null): string {
  const accountOverride = settings?.prismDefaultLlmModel?.trim() ?? "";
  if (accountOverride.length > 0) return accountOverride;
  const serverAuxiliary = settings?.ollamaAuxiliaryModel?.trim() ?? "";
  return serverAuxiliary.length > 0 ? serverAuxiliary : "llama3.2";
}

function resolveCommandCenterModelChoiceForSend(
  value: string,
  settings: UserSettings | null,
  catalog: ModelCatalog | null
): string {
  const normalized = normalizeCommandCenterPreferredModelChoice(value);
  const parsed = parseCommandCenterModelChoice(normalized);
  if (parsed) {
    const visibleChoice = visibleModelChoiceForProvider(
      catalog,
      settings,
      "local",
      parsed.modelId
    );
    if (visibleChoice !== AUTO_MODEL_CHOICE) {
      return `local:${visibleChoice}`;
    }
  }
  return `local:${commandCenterAuxiliaryModelId(settings)}`;
}

/** Row to badge in chat model menus: the concrete id saved in Settings (no badge when Auto). */
function chatSettingsSavedDefaultModelId(
  settings: UserSettings | null,
  provider: Provider | "online"
): string | null {
  if (!settings) return null;
  const raw =
    provider === "local" ? settings.preferredLocalModel : settings.preferredOnlineModel;
  const normalized = normalizeModelChoice(raw);
  return normalized === AUTO_MODEL_CHOICE ? null : normalized;
}

/** Row to badge in image model menus from Settings image preferences. */
function imageSettingsSavedDefaultModelId(
  settings: UserSettings | null,
  provider: Provider
): string | null {
  if (!settings) return null;
  if (provider === "local") {
    const n = normalizeModelChoice(settings.preferredLocalImageModel);
    return n === AUTO_MODEL_CHOICE ? null : n;
  }
  const trimmed = settings.preferredOpenAiImageModel?.trim() ?? "";
  if (trimmed.length === 0) return null;
  return isAllowedOpenAiImageModelId(trimmed) || isElevenLabsImageModelId(trimmed)
    ? trimmed
    : null;
}

const SECONDARY_OLLAMA_MODEL_PREFIX = "ollama-secondary:";
const REQUIRED_PRIMARY_LOCAL_MODEL_ID = "llama3.2";

function titleCaseModelToken(token: string): string {
  const lower = token.toLowerCase();
  const known: Record<string, string> = {
    api: "API",
    b: "B",
    chatgpt: "ChatGPT",
    code: "Code",
    codellama: "Code Llama",
    codex: "Codex",
    deepseek: "DeepSeek",
    distill: "Distill",
    flux: "FLUX",
    gemma: "Gemma",
    gpt: "GPT",
    instruct: "Instruct",
    llama: "Llama",
    llava: "LLaVA",
    mini: "Mini",
    mistral: "Mistral",
    mixtral: "Mixtral",
    nano: "Nano",
    opus: "Opus",
    phi: "Phi",
    pro: "Pro",
    qwen: "Qwen",
    r1: "R1",
    search: "Search",
    sonnet: "Sonnet",
    tinyllama: "TinyLlama",
    vl: "VL",
  };
  if (known[lower]) return known[lower];
  if (/^\d+(?:\.\d+)?b$/i.test(token)) return token.toUpperCase();
  if (/^o\d/.test(lower)) return lower;
  const alphaNumber = token.match(/^([a-z]+)(\d+(?:\.\d+)?)$/i);
  if (alphaNumber) return `${titleCaseModelToken(alphaNumber[1]!)} ${alphaNumber[2]}`;
  return token.toUpperCase() === token
    ? token
    : `${token.slice(0, 1).toUpperCase()}${token.slice(1)}`;
}

function modelSnapshotSuffix(datePart: string | undefined): string {
  if (!datePart) return "";
  const isoDate = datePart.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (isoDate) return ` (${isoDate[1]}-${isoDate[2]}-${isoDate[3]})`;
  const compactDate = datePart.match(/^(\d{4})(\d{2})(\d{2})$/);
  if (compactDate) return ` (${compactDate[1]}-${compactDate[2]}-${compactDate[3]})`;
  return ` (${datePart})`;
}

function openAiTextModelLabelFromId(id: string): string | null {
  const normalized = id.trim().toLowerCase();
  if (!normalized) return null;
  if (normalized === "chatgpt-4o-latest") return "ChatGPT-4o";
  const oSeries = normalized.match(/^(o\d)(?:-(mini))?$/);
  if (oSeries) return [oSeries[1], oSeries[2] ? "Mini" : ""].filter(Boolean).join(" ");
  const codex = normalized.match(/^gpt-(\d+(?:\.\d+)?)-codex(?:-(max|mini))?$/);
  if (codex) {
    return [`GPT-${codex[1]}`, "Codex", codex[2] ? titleCaseModelToken(codex[2]) : ""]
      .filter(Boolean)
      .join(" ");
  }
  const search = normalized.match(/^gpt-(\d+(?:\.\d+)?)-search-api(?:-(\d{4}-\d{2}-\d{2}))?$/);
  if (search) return `GPT-${search[1]} Search${modelSnapshotSuffix(search[2])}`;
  const chatLatest = normalized.match(/^gpt-(\d+(?:\.\d+)?)-chat-latest$/);
  if (chatLatest) return `GPT-${chatLatest[1]}`;
  const versioned = normalized.match(
    /^gpt-(\d+(?:\.\d+)?)(?:-(mini|nano|pro))?(?:-(\d{4}-\d{2}-\d{2}))?$/
  );
  if (versioned) {
    return [`GPT-${versioned[1]}`, versioned[2] ? titleCaseModelToken(versioned[2]) : ""]
      .filter(Boolean)
      .join(" ") + modelSnapshotSuffix(versioned[3]);
  }
  return null;
}

function anthropicTextModelLabelFromId(id: string): string | null {
  const normalized = id.trim().toLowerCase();
  if (!normalized.startsWith("claude-")) return null;
  const latest = normalized.match(/^claude-(\d)-(\d)-(sonnet|haiku)-latest$/);
  if (latest) return `Claude ${latest[1]}.${latest[2]} ${titleCaseModelToken(latest[3]!)}`;
  const named = normalized.match(
    /^claude-(opus|sonnet|haiku)-(\d+)(?:-(\d+))?(?:-(\d{8}))?$/
  );
  if (named) {
    const version = named[3] ? `${named[2]}.${named[3]}` : named[2]!;
    return `Claude ${titleCaseModelToken(named[1]!)} ${version}${modelSnapshotSuffix(named[4])}`;
  }
  return null;
}

function modelLabelFromId(id: string): string {
  const providerLabel = openAiTextModelLabelFromId(id) ?? anthropicTextModelLabelFromId(id);
  if (providerLabel) return providerLabel;
  const parts = id
    .replace(SECONDARY_OLLAMA_MODEL_PREFIX, "")
    .split(/[-_:]/)
    .filter(Boolean)
    .filter((part, index, allParts) =>
      !(index === allParts.length - 1 && part.toLowerCase() === "latest")
    );
  const displayParts = parts.length > 0 ? parts : [id];
  return displayParts.map(titleCaseModelToken).join(" ");
}

function isRequiredPrimaryLocalModel(model: ModelCatalogEntry): boolean {
  return (
    model.provider === "local" &&
    model.localHost !== "secondary" &&
    model.id === REQUIRED_PRIMARY_LOCAL_MODEL_ID
  );
}

function normalizeApiKeySource(value: unknown, hasSavedKey: boolean): ApiKeySource {
  return value === "saved" || value === "server" || value === "none"
    ? value
    : hasSavedKey
      ? "saved"
      : "none";
}

function apiKeySourceAvailable(source: ApiKeySource | null | undefined): boolean {
  return source === "saved" || source === "server";
}

function apiKeySourceModelGroupMeta(source: ApiKeySource): string {
  return source === "server" ? "Server key connected" : "Saved key connected";
}

function normalizeSavedApiKeySettingsState(
  state: Partial<SavedApiKeySettingsState>
): SavedApiKeySettingsState {
  const hasOpenAiApiKey = state.hasOpenAiApiKey === true;
  const hasAnthropicApiKey = state.hasAnthropicApiKey === true;
  const hasElevenLabsApiKey = state.hasElevenLabsApiKey === true;
  return {
    hasOpenAiApiKey,
    hasAnthropicApiKey,
    hasElevenLabsApiKey,
    openAiApiKeySource: normalizeApiKeySource(
      state.openAiApiKeySource,
      hasOpenAiApiKey
    ),
    anthropicApiKeySource: normalizeApiKeySource(
      state.anthropicApiKeySource,
      hasAnthropicApiKey
    ),
    elevenLabsApiKeySource: normalizeApiKeySource(
      state.elevenLabsApiKeySource,
      hasElevenLabsApiKey
    ),
  };
}

function apiKeySourceStatusLabel(providerLabel: string, source: ApiKeySource): string {
  if (source === "saved") return `${providerLabel} saved`;
  if (source === "server") return `${providerLabel} server key`;
  return `${providerLabel} unset`;
}

function createApiKeyDraftValidationMap(): ApiKeyDraftValidationMap {
  return {
    openai: { value: "", status: "idle", detail: null },
    anthropic: { value: "", status: "idle", detail: null },
    elevenlabs: { value: "", status: "idle", detail: null },
  };
}

function apiKeyConnectionDisplay(
  providerLabel: string,
  source: ApiKeySource,
  draft: ApiKeyDraftValidation
): ApiKeyConnectionDisplay {
  if (draft.value.length > 0) {
    if (draft.status === "connected") {
      return {
        overviewStatus: "connected",
        overviewText: `${providerLabel} connected`,
        fieldStatus: "connected",
        fieldText: "Connected",
        detail: draft.detail,
      };
    }
    if (draft.status === "error") {
      return {
        overviewStatus: "error",
        overviewText: `${providerLabel} invalid`,
        fieldStatus: "error",
        fieldText: "Invalid",
        detail: draft.detail,
      };
    }
    return {
      overviewStatus: "checking",
      overviewText: `${providerLabel} checking...`,
      fieldStatus: "checking",
      fieldText: "Checking...",
      detail: draft.detail,
    };
  }

  if (source !== "none") {
    return {
      overviewStatus: "ready",
      overviewText: apiKeySourceStatusLabel(providerLabel, source),
      fieldStatus: "connected",
      fieldText: source === "server" ? "Server key" : "Saved",
      detail: null,
    };
  }

  return {
    overviewStatus: "idle",
    overviewText: apiKeySourceStatusLabel(providerLabel, source),
    fieldStatus: "idle",
    fieldText: "Optional",
    detail: null,
  };
}

function onlineProviderCanPreserveModelChoice(
  catalog: ModelCatalog | null,
  provider: Provider
): boolean {
  return (catalog?.online ?? []).some((model) => model.provider === provider);
}

function isHiddenBotModelId(
  settings: UserSettings | null,
  modelId: string | null | undefined
): boolean {
  const normalized = modelId?.trim() ?? "";
  if (!normalized) return false;
  return (settings?.hiddenBotModelIds ?? []).includes(normalized);
}

function modelOptionsForProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider
): ModelCatalogEntry[] {
  if (provider === "local") {
    const fallbackId = settings?.ollamaModel?.trim() || "Local default";
    return catalog?.local.length
      ? catalog.local
      : [{
          id: fallbackId,
          label: fallbackId,
          provider: "local",
          isDefault: true,
          hostLabel: "Primary host",
        }];
  }
  const onlineOptions = (catalog?.online ?? []).filter(
    (model) => model.provider === provider
  );
  if (onlineOptions.length > 0) {
    return onlineOptions.map((model) => ({
      ...model,
      hostLabel: model.hostLabel ?? providerDisplayLabel(provider),
    }));
  }
  return [];
}

function chatModelOptionsForProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider
): ModelCatalogEntry[] {
  return filterVisibleModelOptions(
    modelOptionsForProvider(catalog, settings, provider),
    settings?.hiddenBotModelIds ?? []
  );
}

function botCustomizerModelOptionsForProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider
): ModelCatalogEntry[] {
  return chatModelOptionsForProvider(catalog, settings, provider);
}

function availableModelOptionsForProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider
): ModelCatalogEntry[] {
  return modelOptionsForProvider(catalog, settings, provider);
}

function defaultModelChoiceForProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider
): string {
  const options = chatModelOptionsForProvider(catalog, settings, provider).filter(
    (model) => !model.disabledReason
  );
  return options.find((model) => model.isDefault)?.id ?? options[0]?.id ?? AUTO_MODEL_CHOICE;
}

function visibleConcreteModelChoiceForProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider,
  choice: string | null | undefined
): string {
  const visibleChoice = normalizeModelChoice(choice);
  if (visibleChoice === AUTO_MODEL_CHOICE) {
    return defaultModelChoiceForProvider(catalog, settings, provider);
  }
  return chatModelOptionsForProvider(catalog, settings, provider).some(
    (model) => model.id === visibleChoice
  )
    ? visibleChoice
    : defaultModelChoiceForProvider(catalog, settings, provider);
}

function defaultOnlineModelChoice(
  catalog: ModelCatalog | null,
  settings: UserSettings | null
): string {
  const options = onlineModelOptionsForPicker(catalog, settings).filter(
    (model) => !model.disabledReason
  );
  return options.find((model) => model.isDefault)?.id ?? options[0]?.id ?? AUTO_MODEL_CHOICE;
}

function visibleConcreteOnlineModelChoice(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  choice: string | null | undefined
): string {
  const visibleChoice = normalizeModelChoice(choice);
  if (visibleChoice === AUTO_MODEL_CHOICE) {
    return defaultOnlineModelChoice(catalog, settings);
  }
  if (isHiddenBotModelId(settings, visibleChoice)) {
    return defaultOnlineModelChoice(catalog, settings);
  }
  const options = onlineModelOptionsForPicker(catalog, settings);
  const provider = inferOnlineProviderForModelId(visibleChoice);
  return options.some((model) => model.id === visibleChoice) ||
    onlineProviderCanPreserveModelChoice(catalog, provider)
    ? visibleChoice
    : defaultOnlineModelChoice(catalog, settings);
}

function visibleModelChoiceForProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider,
  choice: string | null | undefined
): string {
  const visibleChoice = normalizeModelChoice(choice);
  if (visibleChoice === AUTO_MODEL_CHOICE) {
    return visibleChoice;
  }
  return chatModelOptionsForProvider(catalog, settings, provider).some(
    (model) => model.id === visibleChoice
  )
    ? visibleChoice
    : AUTO_MODEL_CHOICE;
}

function visibleOptionalModelChoiceForProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider,
  choice: string | null | undefined
): string {
  const visibleChoice = choice?.trim() ?? "";
  if (!visibleChoice) return "";
  return chatModelOptionsForProvider(catalog, settings, provider).some(
    (model) => model.id === visibleChoice
  )
    ? visibleChoice
    : "";
}

function visiblePreferredOnlineModelChoice(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  choice: string | null | undefined
): string {
  const visibleChoice = normalizeModelChoice(choice);
  if (visibleChoice === AUTO_MODEL_CHOICE) return AUTO_MODEL_CHOICE;
  if (isHiddenBotModelId(settings, visibleChoice)) return AUTO_MODEL_CHOICE;
  const provider = inferOnlineProviderForModelId(visibleChoice);
  return onlineProviderCanPreserveModelChoice(catalog, provider)
    ? visibleChoice
    : AUTO_MODEL_CHOICE;
}

function visibleModelChoicesByProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  choices: Record<Provider, string>
): Record<Provider, string> {
  return {
    local: visibleModelChoiceForProvider(catalog, settings, "local", choices.local),
    openai: visibleModelChoiceForProvider(catalog, settings, "openai", choices.openai),
    anthropic: visibleModelChoiceForProvider(
      catalog,
      settings,
      "anthropic",
      choices.anthropic
    ),
  };
}

function onlineModelOptionsForPicker(
  catalog: ModelCatalog | null,
  settings: UserSettings | null
): ModelCatalogEntry[] {
  return withOnlineProviderHostLabels(combinedOnlineModelOptions(
    chatModelOptionsForProvider(catalog, settings, "openai"),
    chatModelOptionsForProvider(catalog, settings, "anthropic")
  ));
}

function withOnlineProviderHostLabels(options: ModelCatalogEntry[]): ModelCatalogEntry[] {
  return options.map((model) => ({
    ...model,
    hostLabel: model.hostLabel ?? providerDisplayLabel(model.provider),
  }));
}

function modelOptionsForResponseMode(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  responseMode: ResponseMode
): ModelCatalogEntry[] {
  return responseMode === "local"
    ? chatModelOptionsForProvider(catalog, settings, "local")
    : onlineModelOptionsForPicker(catalog, settings);
}

function includeSelectedModelOption(
  options: ModelCatalogEntry[],
  choice: string,
  provider: Provider
): ModelCatalogEntry[] {
  const normalizedChoice = choice.trim();
  if (
    !normalizedChoice ||
    normalizedChoice === AUTO_MODEL_CHOICE ||
    options.some((model) => model.id === normalizedChoice)
  ) {
    return options;
  }
  return [
    ...options,
    { id: normalizedChoice, label: normalizedChoice, provider },
  ];
}

function includeSelectedOnlineModelOption(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  options: ModelCatalogEntry[],
  choice: string
): ModelCatalogEntry[] {
  const normalizedChoice = normalizeModelChoice(choice);
  if (
    normalizedChoice === AUTO_MODEL_CHOICE ||
    options.some((model) => model.id === normalizedChoice)
  ) {
    return options;
  }
  if (isHiddenBotModelId(settings, normalizedChoice)) return options;
  const provider = inferOnlineProviderForModelId(normalizedChoice);
  return onlineProviderCanPreserveModelChoice(catalog, provider)
    ? includeSelectedModelOption(options, normalizedChoice, provider)
    : options;
}

function includeSelectedResponseModeModelOption(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  responseMode: ResponseMode,
  options: ModelCatalogEntry[],
  choice: string,
  provider: Provider
): ModelCatalogEntry[] {
  return responseMode === "online"
    ? includeSelectedOnlineModelOption(catalog, settings, options, choice)
    : isHiddenBotModelId(settings, choice)
      ? options
      : includeSelectedModelOption(options, choice, provider);
}

function visibleLocalImageModelSelectValue(value: string | null | undefined): string {
  const trimmed = value?.trim() ?? "";
  return isComfyUiModelId(trimmed) ? "" : trimmed;
}

function includeSelectedLocalImageModelOption(
  options: ModelCatalogEntry[],
  choice: string | null | undefined
): ModelCatalogEntry[] {
  return includeSelectedModelOption(
    options,
    visibleLocalImageModelSelectValue(choice),
    "local"
  );
}

function uniqueModelOptions(options: ModelCatalogEntry[]): ModelCatalogEntry[] {
  const seen = new Set<string>();
  return options.filter((model) => {
    const key = `${model.provider}:${model.id}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

type SettingsModelEligibilityGroupId = "ollama" | "openai" | "anthropic" | "elevenlabs";

interface SettingsModelEligibilityGroup {
  id: SettingsModelEligibilityGroupId;
  label: string;
  meta: string;
  models: ModelCatalogEntry[];
}

function settingsModelGroupOptions(options: ModelCatalogEntry[]): ModelCatalogEntry[] {
  const seen = new Set<string>();
  return options.filter((model) => {
    const id = model.id.trim();
    if (!id || seen.has(id)) return false;
    seen.add(id);
    return true;
  });
}

function settingsOllamaGroupMeta(models: ModelCatalogEntry[]): string {
  const hasSecondaryHost = models.some((model) => model.localHost === "secondary");
  if (!hasSecondaryHost) return "Local Ollama host";
  const hostCount = new Set(
    models.map((model) => model.localHost ?? model.hostLabel ?? "primary")
  ).size;
  return `${hostCount} connected Ollama hosts`;
}

function settingsModelEligibilityGroups(args: {
  catalog: ModelCatalog | null;
  settings: UserSettings;
  openAiImageModels: ModelCatalogEntry[];
  elevenLabsImageModels: ModelCatalogEntry[];
}): SettingsModelEligibilityGroup[] {
  const groups: SettingsModelEligibilityGroup[] = [];
  const ollama = settingsModelGroupOptions(
    modelOptionsForProvider(args.catalog, args.settings, "local")
  );
  if (ollama.length > 0) {
    groups.push({
      id: "ollama",
      label: "Ollama",
      meta: settingsOllamaGroupMeta(ollama),
      models: ollama,
    });
  }

  if (apiKeySourceAvailable(args.settings.openAiApiKeySource)) {
    const openAi = settingsModelGroupOptions([
      ...modelOptionsForProvider(args.catalog, args.settings, "openai"),
      ...args.openAiImageModels,
    ]);
    if (openAi.length > 0) {
      groups.push({
        id: "openai",
        label: "OpenAI",
        meta: `${apiKeySourceModelGroupMeta(args.settings.openAiApiKeySource)} - Chat and image`,
        models: openAi,
      });
    }
  }

  if (apiKeySourceAvailable(args.settings.anthropicApiKeySource)) {
    const anthropic = settingsModelGroupOptions(
      modelOptionsForProvider(args.catalog, args.settings, "anthropic")
    );
    if (anthropic.length > 0) {
      groups.push({
        id: "anthropic",
        label: "Anthropic",
        meta: `${apiKeySourceModelGroupMeta(args.settings.anthropicApiKeySource)} - Chat`,
        models: anthropic,
      });
    }
  }

  if (apiKeySourceAvailable(args.settings.elevenLabsApiKeySource)) {
    const elevenLabs = settingsModelGroupOptions(args.elevenLabsImageModels);
    if (elevenLabs.length > 0) {
      groups.push({
        id: "elevenlabs",
        label: "ElevenLabs",
        meta: `${apiKeySourceModelGroupMeta(args.settings.elevenLabsApiKeySource)} - Image & Video`,
        models: elevenLabs,
      });
    }
  }

  return groups;
}

function settingsModelToggleMeta(
  groupId: SettingsModelEligibilityGroupId,
  model: ModelCatalogEntry,
  required: boolean
): string {
  if (required) return "Required";
  if (groupId === "ollama") {
    return `Offline${model.hostLabel ? ` - ${model.hostLabel}` : ""}`;
  }
  if (groupId === "anthropic") return "Chat";
  if (groupId === "elevenlabs") return "Image & Video";
  const id = model.id.toLowerCase();
  return id.includes("image") || id.startsWith("dall-e") ? "Image" : "Chat";
}

function inferOnlineProviderForModelId(modelId: string): Provider {
  return modelId.trim().toLowerCase().startsWith("claude-") ? "anthropic" : "openai";
}

function blendToward(value: number, target: number, amount: number): number {
  return value + (target - value) * amount;
}

function botColorFamilyGroup(hue: number): number {
  if (hue < 15 || hue >= 345) return 0; // red
  if (hue < 45) return 1; // orange
  if (hue < 75) return 2; // yellow
  if (hue < 110) return 3; // lime
  if (hue < 155) return 4; // green
  if (hue < 240) return 5; // cyan/blue
  if (hue < 275) return 7; // indigo
  if (hue < 315) return 8; // violet
  return 9; // magenta
}

function botHueSortValue(hue: number): number {
  return hue >= 345 ? hue - 360 : hue;
}

// Smallest angular distance between two hues on the 360° wheel. Both
// inputs are normalized into [0, 360) first so callers don't have to
// pre-clamp slider values that drift slightly outside the range.
function circularHueDistance(a: number, b: number): number {
  const wrap = (value: number): number => {
    const mod = value % 360;
    return mod < 0 ? mod + 360 : mod;
  };
  const diff = Math.abs(wrap(a) - wrap(b));
  return Math.min(diff, 360 - diff);
}

// True when a bot has a usable, non-grayscale color the hue lens can
// match against. Uncolored or near-grayscale bots intentionally fall
// out of the filter so the lens reads as "show me bots in this hue
// band" rather than "show me everything tinted at all".
function botHasFilterableColor(bot: Bot): boolean {
  const raw = bot.color?.trim();
  if (!raw || !hexChannels(raw)) return false;
  const { s } = hexToHsl(raw);
  return s > BOT_COLOR_SORT_GRAYSCALE_SATURATION_MAX;
}

// Hue availability buckets — the lens slider's gradient and the dense
// color-map's snap behavior both need a histogram of which hue families
// the user actually owns. Twelve 30° buckets keep adjacent families
// (red/orange/yellow) visually distinct on the slider while still being
// coarse enough that snapping to a region doesn't feel jittery near a
// boundary.
const HUE_BUCKET_COUNT = 12;
const HUE_BUCKET_WIDTH_DEG = 360 / HUE_BUCKET_COUNT;

interface HueBucket {
  /** Hue (degrees) at the center of this bucket. */
  center: number;
  /** Number of filterable bots whose color falls in this bucket. */
  count: number;
}

interface HueLensTrackSegment {
  prismIndex: number;
  color: string;
}

const EMPTY_HUE_LENS_TRACK_SEGMENTS: readonly HueLensTrackSegment[] = [];
const PRISM_HUE_LENS_TRACK_SEGMENTS: readonly HueLensTrackSegment[] =
  PRISM_WORDMARK_PALETTE.map((color, prismIndex) => ({ prismIndex, color }));

function hueBucketIndex(hue: number): number {
  const wrapped = ((hue % 360) + 360) % 360;
  return Math.min(
    HUE_BUCKET_COUNT - 1,
    Math.floor(wrapped / HUE_BUCKET_WIDTH_DEG)
  );
}

function hueBucketCenter(index: number): number {
  return index * HUE_BUCKET_WIDTH_DEG + HUE_BUCKET_WIDTH_DEG / 2;
}

// Tally bot hues into a fixed-width bucket histogram, ignoring
// uncolored/grayscale bots so the lens reflects only the population it
// can actually filter against.
function computeHueBuckets(bots: readonly Bot[]): HueBucket[] {
  const counts = new Array<number>(HUE_BUCKET_COUNT).fill(0);
  for (const bot of bots) {
    if (!botHasFilterableColor(bot)) continue;
    const { h } = hexToHsl(bot.color!.trim());
    counts[hueBucketIndex(h)] += 1;
  }
  return counts.map((count, i) => ({ center: hueBucketCenter(i), count }));
}

function hueLensSegmentIndexForHue(hue: number): number {
  const prismHues = PRISM_WORDMARK_PALETTE.map((color) => hexToHsl(color).h);
  let segmentIndex = 0;
  let bestDistance = Infinity;
  for (let i = 0; i < prismHues.length; i += 1) {
    const distance = circularHueDistance(prismHues[i], hue);
    if (distance < bestDistance) {
      bestDistance = distance;
      segmentIndex = i;
    }
  }
  return segmentIndex;
}

function hueLensPositionForHue(hue: number): number {
  const prismHues = PRISM_WORDMARK_PALETTE.map((color) => hexToHsl(color).h);
  const segmentIndex = hueLensSegmentIndexForHue(hue);
  const segmentWidth = 360 / prismHues.length;
  const center = segmentIndex * segmentWidth + segmentWidth / 2;
  const signedHueOffset =
    (((hue - prismHues[segmentIndex] + 540) % 360) - 180) /
    (PRISM_BOT_SEED_HUE_SPREAD_DEG / 2);
  const maxOffset = segmentWidth / 2 - 1;
  const offset = Math.max(-maxOffset, Math.min(maxOffset, signedHueOffset * maxOffset));
  return Math.max(0, Math.min(359, center + offset));
}

function computeHueLensTrackSegments(bots: readonly Bot[]): HueLensTrackSegment[] {
  const populatedSegments = new Array<boolean>(PRISM_WORDMARK_PALETTE.length).fill(false);
  for (const bot of bots) {
    if (!botHasFilterableColor(bot)) continue;
    const { h } = hexToHsl(bot.color!.trim());
    populatedSegments[hueLensSegmentIndexForHue(h)] = true;
  }
  return populatedSegments.flatMap((populated, prismIndex) =>
    populated
      ? [{ prismIndex, color: PRISM_WORDMARK_PALETTE[prismIndex] }]
      : []
  );
}

// Build the lens track from the bot colors that actually exist. Populated
// families expand to fill the whole rail, so a one-green-bot library paints
// one full-width green bar instead of a green island with empty gaps.
function hueLensGradient(
  segments: readonly HueLensTrackSegment[],
  theme: "light" | "dark"
): string {
  if (segments.length === 0) {
    return "linear-gradient(to right, transparent 0%, transparent 100%)";
  }
  const stops: string[] = [];
  for (let i = 0; i < segments.length; i += 1) {
    const color = normalizeAccentForTheme(segments[i].color, theme);
    const start = (i / segments.length) * 100;
    const end = ((i + 1) / segments.length) * 100;
    stops.push(`${color} ${start.toFixed(2)}%`);
    stops.push(`${color} ${end.toFixed(2)}%`);
  }
  return `linear-gradient(to right, ${stops.join(", ")})`;
}

function hueLensFilterCenterForSliderValue(
  sliderValue: number,
  segments: readonly HueLensTrackSegment[]
): number {
  if (segments.length === 0) return sliderValue;
  const clamped = Math.max(0, Math.min(359, sliderValue));
  const compactSegmentWidth = 360 / segments.length;
  const compactIndex = Math.min(
    segments.length - 1,
    Math.floor(clamped / compactSegmentWidth)
  );
  const compactStart = compactIndex * compactSegmentWidth;
  const progress = (clamped - compactStart) / compactSegmentWidth;
  const prismSegmentWidth = 360 / PRISM_WORDMARK_PALETTE.length;
  const prismStart = segments[compactIndex].prismIndex * prismSegmentWidth;
  return Math.max(0, Math.min(359, prismStart + progress * prismSegmentWidth));
}

function hueLensSliderValueForFilterCenter(
  hueCenter: number,
  segments: readonly HueLensTrackSegment[]
): number {
  if (segments.length === 0) return hueCenter;
  const prismSegmentWidth = 360 / PRISM_WORDMARK_PALETTE.length;
  const compactSegmentWidth = 360 / segments.length;
  const prismIndex = Math.min(
    PRISM_WORDMARK_PALETTE.length - 1,
    Math.floor(Math.max(0, Math.min(359, hueCenter)) / prismSegmentWidth)
  );
  let compactIndex = segments.findIndex((segment) => segment.prismIndex === prismIndex);
  if (compactIndex < 0) {
    compactIndex = 0;
    let bestDistance = Infinity;
    for (let i = 0; i < segments.length; i += 1) {
      const center = segments[i].prismIndex * prismSegmentWidth + prismSegmentWidth / 2;
      const distance = Math.abs(center - hueCenter);
      if (distance < bestDistance) {
        bestDistance = distance;
        compactIndex = i;
      }
    }
    return compactIndex * compactSegmentWidth + compactSegmentWidth / 2;
  }
  const prismStart = prismIndex * prismSegmentWidth;
  const progress = (hueCenter - prismStart) / prismSegmentWidth;
  return Math.max(
    0,
    Math.min(359, compactIndex * compactSegmentWidth + progress * compactSegmentWidth)
  );
}

function compareBotsByHueRibbonPosition(a: Bot, b: Bot): number {
  const aColor = a.color?.trim();
  const bColor = b.color?.trim();
  const aPosition = aColor ? hueLensPositionForHue(hexToHsl(aColor).h) : 0;
  const bPosition = bColor ? hueLensPositionForHue(hexToHsl(bColor).h) : 0;
  return (
    aPosition - bPosition ||
    a.name.localeCompare(b.name) ||
    a.id.localeCompare(b.id)
  );
}

function hueRibbonWindowSize(
  totalBots: number,
  viewportWidth: number,
  viewportHeight: number,
  preferredRows?: number,
  preferredCols?: number
): number {
  if (totalBots <= 0) return 0;
  if (preferredRows && preferredCols) {
    return Math.min(totalBots, preferredRows * preferredCols);
  }
  const { flatTileCountMin } = pickerDensityBreakpoints(
    viewportWidth,
    viewportHeight
  );
  const showAllMax = Math.max(
    HUE_RIBBON_MIN_VISIBLE_BOTS,
    flatTileCountMin - 1
  );
  const targetCount =
    totalBots <= showAllMax
      ? totalBots
      : Math.min(
          totalBots,
          Math.max(HUE_RIBBON_MIN_VISIBLE_BOTS, flatTileCountMin)
        );

  for (let offset = 0; offset < totalBots; offset += 1) {
    const larger = targetCount + offset;
    if (
      larger <= totalBots &&
      hueRibbonWindowFillsGrid(larger, viewportWidth, viewportHeight, preferredRows)
    ) {
      return larger;
    }

    const smaller = targetCount - offset;
    if (
      smaller >= HUE_RIBBON_MIN_VISIBLE_BOTS &&
      hueRibbonWindowFillsGrid(smaller, viewportWidth, viewportHeight, preferredRows)
    ) {
      return smaller;
    }
  }

  return targetCount;
}

function hueRibbonWindowFillsGrid(
  count: number,
  viewportWidth: number,
  viewportHeight: number,
  preferredRows?: number
): boolean {
  const geom = pickerGeometry(count, viewportWidth, viewportHeight, {
    balanceOddRows: false,
    preferredRows,
  });
  return geom.fillerCells === 0;
}

function hueRibbonWindowBots(
  bots: Bot[],
  hueCenter: number | null,
  trackSegments: readonly HueLensTrackSegment[],
  viewportWidth: number,
  viewportHeight: number,
  preferredRows?: number,
  preferredCols?: number
): Bot[] {
  if (hueCenter === null) return bots;

  const ribbon = bots
    .filter(botHasFilterableColor)
    .sort(compareBotsByHueRibbonPosition);
  const windowSize = hueRibbonWindowSize(
    ribbon.length,
    viewportWidth,
    viewportHeight,
    preferredRows,
    preferredCols
  );
  if (windowSize <= 0) return [];
  if (windowSize >= ribbon.length) return ribbon;

  const sliderValue = hueLensSliderValueForFilterCenter(
    hueCenter,
    trackSegments
  );
  const sliderProgress = Math.max(
    0,
    Math.min(1, sliderValue / HUE_LENS_SLIDER_RANGE)
  );
  const centerIndex = Math.floor(sliderProgress * ribbon.length) % ribbon.length;
  const startIndex =
    centerIndex - Math.floor(windowSize / 2) + ribbon.length;

  return Array.from({ length: windowSize }, (_, offset) => (
    ribbon[(startIndex + offset) % ribbon.length]
  ));
}

// Slider's native [0..359] range maps linearly to a 0..100 percentage that
// approximates the thumb's center as a fraction of the track. The native
// thumb has a small inset relative to the track ends, so this isn't pixel-
// perfect at the extremes — but the orb it drives in `.messagesFrame::after`
// is a wide, soft radial gradient masked at the rails, so visually 1px of
// thumb-vs-orb offset reads as zero. `null` filter parks the orb at 50%,
// which lines up with the slider's 180-resting position.
const HUE_LENS_SLIDER_RANGE = 359;
function hueLensSliderPercent(
  hueCenter: number | null,
  segments: readonly HueLensTrackSegment[]
): number {
  if (hueCenter === null) return 50;
  const sliderValue = hueLensSliderValueForFilterCenter(hueCenter, segments);
  return Math.max(0, Math.min(100, (sliderValue / HUE_LENS_SLIDER_RANGE) * 100));
}

// Match the page accent to the compacted PRISM track segment currently
// under the slider thumb. This keeps the hero triangle and ambient glow
// visually anchored to the user's actual thumb position instead of drifting
// around a separate full-spectrum hue wheel.
function hueLensSliderTintHex(
  hueCenter: number | null,
  segments: readonly HueLensTrackSegment[]
): string | null {
  if (hueCenter === null) return null;
  const sliderValue = hueLensSliderValueForFilterCenter(hueCenter, segments);
  if (segments.length === 0) return null;
  const compactSegmentWidth = 360 / segments.length;
  const compactIndex = Math.min(
    segments.length - 1,
    Math.floor(Math.max(0, Math.min(359, sliderValue)) / compactSegmentWidth)
  );
  return segments[compactIndex]?.color ?? null;
}

function panelBotDisplayAccent(
  rawHex: string,
  theme: "light" | "dark",
  harmonyActive: boolean
): string {
  const normalized = normalizeAccentForTheme(rawHex, theme);
  if (!harmonyActive) return normalized;

  const { h, s, l } = hexToHsl(normalized);
  const targetLightness = theme === "dark"
    ? BOT_PANEL_COLOR_HARMONY_LIGHTNESS_TARGET_DARK
    : BOT_PANEL_COLOR_HARMONY_LIGHTNESS_TARGET_LIGHT;
  return normalizeAccentForTheme(
    hslToHex(
      h,
      blendToward(s, BOT_PANEL_COLOR_HARMONY_SATURATION_TARGET, BOT_PANEL_COLOR_HARMONY_STRENGTH),
      blendToward(l, targetLightness, BOT_PANEL_COLOR_HARMONY_STRENGTH)
    ),
    theme
  );
}

function botColorSortKey(
  bot: Bot,
  theme: "light" | "dark",
  harmonyActive: boolean
): {
  hueGroup: number;
  hue: number;
  luminance: number;
  saturation: number;
  name: string;
} {
  const rawColor = bot.color?.trim();
  if (!rawColor || !hexChannels(rawColor)) {
    return {
      hueGroup: BOT_COLOR_SORT_COLORLESS_GROUP,
      hue: 0,
      luminance: 0,
      saturation: 0,
      name: bot.name,
    };
  }

  const displayColor = panelBotDisplayAccent(rawColor, theme, harmonyActive);
  const { h, s } = hexToHsl(displayColor);
  const isGrayscale = s <= BOT_COLOR_SORT_GRAYSCALE_SATURATION_MAX;
  return {
    hueGroup: isGrayscale
      ? BOT_COLOR_SORT_GRAYSCALE_GROUP
      : botColorFamilyGroup(h),
    hue: botHueSortValue(h),
    luminance: relativeLuminance(displayColor),
    saturation: s,
    name: bot.name,
  };
}

function compareBotsByColor(
  a: Bot,
  b: Bot,
  theme: "light" | "dark",
  harmonyActive: boolean
): number {
  const aKey = botColorSortKey(a, theme, harmonyActive);
  const bKey = botColorSortKey(b, theme, harmonyActive);
  if (aKey.hueGroup !== bKey.hueGroup) return aKey.hueGroup - bKey.hueGroup;
  if (aKey.luminance !== bKey.luminance) return bKey.luminance - aKey.luminance;
  if (aKey.hue !== bKey.hue) return aKey.hue - bKey.hue;
  if (aKey.saturation !== bKey.saturation) return bKey.saturation - aKey.saturation;
  return aKey.name.localeCompare(bKey.name, undefined, { sensitivity: "base" });
}

// At high bot counts the right drawer stops being a list and becomes a
// Prism-colored dashboard. The five wordmark letters give us five
// semantic buckets for the user's bots: P/R/I/S/M. randomHex() now
// always seeds saturated colors inside the accent band, so every
// newly generated bot lands in one of these five buckets — there is
// no separate neutral group.
type PrismGroupId = "p" | "r" | "i" | "s" | "m";
type BotLibraryFilterId = "all" | PrismGroupId;
const BOT_LIBRARY_FILTER_ALL = "all" as const;
const BOT_LIBRARY_DRAWER_ANIMATION_MS = 220;
const PANEL_CLOSE_ANIMATION_MS = 180;

interface PrismGroupDef {
  id: PrismGroupId;
  letter: string;
  label: string;
  swatch: string;
}

const PRISM_GROUPS: readonly PrismGroupDef[] = [
  { id: "p", letter: "P", label: "Pink & red", swatch: PRISM_COLORS.p },
  { id: "r", letter: "R", label: "Orange & yellow", swatch: PRISM_COLORS.r },
  { id: "i", letter: "I", label: "Lime & green", swatch: PRISM_COLORS.i },
  { id: "s", letter: "S", label: "Cyan & blue", swatch: PRISM_COLORS.s },
  { id: "m", letter: "M", label: "Indigo & violet", swatch: PRISM_COLORS.m },
] as const;

// The bot-library color-group dashboard renders the All-bots △ tile in
// row 1 col 1, then the five PRISM_GROUPS in iteration order across a
// 2-column grid: pink/red (r1c2), orange/yellow (r2c1), lime/green
// (r2c2), cyan/blue (r3c1), indigo/violet (r3c2). Read column-major
// (left col r2→r3, then right col r1→r3) the five color tiles arrive
// in the sequence orange, cyan, pink, green, violet — so we override
// each tile's displayed glyph below to spell the PRISM brand wordmark
// in that reading order. The underlying group ids, labels, swatches,
// and aria-labels still carry the canonical color identity; only the
// visible letter glyph is remapped for the wordmark layout.
const GROUP_LETTER_OVERRIDES: Record<PrismGroupId, string> = {
  r: "P", // orange/yellow → 1st in column-major reading
  s: "R", // cyan/blue     → 2nd
  p: "I", // pink/red      → 3rd
  i: "S", // lime/green    → 4th
  m: "M", // indigo/violet → 5th
};

interface MemoryClusterInnerBubble {
  id: string;
  style: React.CSSProperties;
}

interface MemoryFamilyDirectory {
  id: PrismGroupId;
  letter: string;
  label: string;
  color: string;
  itemCount: number;
  memoryCount: number;
  innerBubbles: MemoryClusterInnerBubble[];
  style: React.CSSProperties;
}

interface MemoryFamilyBotCluster {
  id: string;
  botId: string | null;
  botName: string;
  botGlyph: string | null;
  color: string;
  memoryCount: number;
  style: React.CSSProperties;
  innerBubbles: MemoryClusterInnerBubble[];
}

const MEMORY_FAMILY_DIRECTORY_SLOTS: readonly (readonly [number, number])[] = [
  [50, 28],
  [87, 43],
  [73, 68],
  [27, 68],
  [13, 43],
] as const;

const MEMORY_BUBBLE_CLOUD_SLOTS: readonly (readonly [number, number])[] = [
  [18, 22],
  [48, 17],
  [79, 24],
  [24, 50],
  [52, 46],
  [78, 52],
  [18, 76],
  [48, 80],
  [74, 75],
] as const;

const MEMORY_UNCERTAIN_CONFIDENCE_MAX = 0.48;
// Individual memory bubbles are intentionally compact. The prose can trail
// off at rest; clicking a bubble opens a full-text detail card below.
const MEMORY_BUBBLE_MIN_SIZE = 82;
const MEMORY_BUBBLE_MAX_SIZE = 136;
const MEMORY_UNCERTAIN_BUBBLE_MIN_SIZE = 38;
const MEMORY_UNCERTAIN_BUBBLE_MAX_SIZE = 68;
const LONG_TERM_MEMORY_CATEGORIES: Array<{ id: MemoryCategory; label: string }> = [
  { id: "general", label: "General" },
  { id: "user", label: "About you" },
  { id: "bot_relation", label: "Other bots" },
];

function memoryConfidenceValue(memory: UserMemory): number {
  return Number.isFinite(memory.confidence) ? Math.max(0, Math.min(1, memory.confidence)) : 0.5;
}

function isAssumptionMemory(memory: UserMemory): boolean {
  return memory.source === "inferred" || memory.source === "compiled";
}

function assumptionMemoryOpacity(memory: UserMemory): number {
  const certainty = Number.isFinite(memory.certainty)
    ? Math.max(0, Math.min(1, memory.certainty as number))
    : memoryConfidenceValue(memory);
  return 0.2 + certainty * 0.8;
}

function memoryBubbleSignalValue(memory: UserMemory): number {
  if (!isAssumptionMemory(memory)) return memoryConfidenceValue(memory);
  return Number.isFinite(memory.certainty)
    ? Math.max(0, Math.min(1, memory.certainty as number))
    : memoryConfidenceValue(memory);
}

const MEMORY_BUBBLE_DEDUP_EPSILON = 0.0001;
const MEMORY_DUPLICATE_CONFIDENCE_MAX_BOOST = 0.22;
const MEMORY_DUPLICATE_CONFIDENCE_BOOST_DECAY = 0.62;

function normalizeMemoryBubbleDedupKey(text: string): string {
  return text.trim().replace(/\s+/g, " ").toLocaleLowerCase();
}

function chooseMemoryBubbleRepresentative(current: UserMemory, candidate: UserMemory): UserMemory {
  const currentSignal = memoryBubbleSignalValue(current);
  const candidateSignal = memoryBubbleSignalValue(candidate);
  if (candidateSignal > currentSignal + MEMORY_BUBBLE_DEDUP_EPSILON) return candidate;
  if (currentSignal > candidateSignal + MEMORY_BUBBLE_DEDUP_EPSILON) return current;

  const currentDurability = Number.isFinite(current.durability)
    ? Math.max(0, Math.min(1, current.durability as number))
    : 0;
  const candidateDurability = Number.isFinite(candidate.durability)
    ? Math.max(0, Math.min(1, candidate.durability as number))
    : 0;
  if (candidateDurability > currentDurability + MEMORY_BUBBLE_DEDUP_EPSILON) return candidate;
  if (currentDurability > candidateDurability + MEMORY_BUBBLE_DEDUP_EPSILON) return current;

  const currentCreatedAtMs = Date.parse(current.createdAt);
  const candidateCreatedAtMs = Date.parse(candidate.createdAt);
  if (Number.isFinite(candidateCreatedAtMs) && Number.isFinite(currentCreatedAtMs)) {
    if (candidateCreatedAtMs > currentCreatedAtMs) return candidate;
    if (currentCreatedAtMs > candidateCreatedAtMs) return current;
  }

  return current;
}

function applyDuplicateConfidenceBoost(memory: UserMemory, duplicateCount: number): UserMemory {
  if (duplicateCount <= 1) return memory;
  const baseSignal = memoryBubbleSignalValue(memory);
  const boostProgress = 1 - Math.pow(MEMORY_DUPLICATE_CONFIDENCE_BOOST_DECAY, duplicateCount - 1);
  const boostedSignal = Math.max(
    0,
    Math.min(
      1,
      baseSignal + (1 - baseSignal) * MEMORY_DUPLICATE_CONFIDENCE_MAX_BOOST * boostProgress
    )
  );
  if (isAssumptionMemory(memory)) {
    return {
      ...memory,
      confidence: boostedSignal,
      certainty: boostedSignal,
    };
  }
  return {
    ...memory,
    confidence: boostedSignal,
  };
}

function estimateMemoryDurabilityForDisplay(text: string): number {
  const normalized = text.trim();
  if (!normalized) return 0.25;
  let score = 0.46;
  const cat = classifyMemoryCategoryFromText(normalized);
  if (cat === "user") score += 0.16;
  if (cat === "bot_relation") score += 0.18;
  const durablePatternHits = [
    /\b(?:always|never|do not|don't|like|likes|love|loves|enjoy|enjoys|prefer|prefers|favorite|favourite|need|needs|want|wants|value|values|care about|cares about)\b/i,
    /\b(?:identity|personality|character|believes?|principles?|boundary|boundaries|comfort|safe|safety)\b/i,
    /\b(?:sees|treats|uses|understands)\s+.+\s+as\s+/i,
    /\b(?:born|founded|created|developed|built|grew|became|known for|signature|method|career|company|inc\.?|workshops?|instructors?|instructional|materials?|art supplies)\b/i,
  ].reduce((count, pattern) => count + (pattern.test(normalized) ? 1 : 0), 0);
  if (durablePatternHits > 0) {
    score += Math.min(0.44, durablePatternHits * 0.24);
  }
  if (/\b(?:remember|don't forget|do not forget|keep in mind|make a note)\b/i.test(normalized) || /\b[A-Z][A-Za-z'.-]+(?:\s+[A-Z][A-Za-z'.-]+){1,3}\b/.test(normalized)) {
    score += 0.3;
  }
  if (/\b(?:currently|today|right now|this moment|for now|temporarily|seems|might|maybe|probably)\b/i.test(normalized)) {
    score -= 0.22;
  }
  return Math.max(0.1, Math.min(1, score));
}

function memoryTier(memory: UserMemory): MemoryTier {
  const confidence = Number.isFinite(memory.confidence) ? Math.max(0, Math.min(1, memory.confidence)) : 0;
  const certainty = Number.isFinite(memory.certainty) ? Math.max(0, Math.min(1, memory.certainty as number)) : confidence;
  const estimatedDurability = estimateMemoryDurabilityForDisplay(memory.text);
  const storedDurability = Number.isFinite(memory.durability)
    ? Math.max(0, Math.min(1, memory.durability as number))
    : 0;
  const durability = Math.max(storedDurability, estimatedDurability);
  return memory.tier === "long_term" ||
    memoryQualifiesLongTerm({
      confidence,
      certainty,
      durability,
      source: memory.source ?? "direct",
    })
    ? "long_term"
    : "short_term";
}

function memoryCategory(memory: UserMemory): MemoryCategory {
  if (memory.category === "general" || memory.category === "user" || memory.category === "bot_relation") {
    return memory.category;
  }
  return memory.botId ? classifyMemoryCategoryFromText(memory.text) : "user";
}

function toPossessiveLabel(label: string): string {
  const trimmed = label.trim();
  if (!trimmed) return "User's";
  return trimmed.endsWith("s") ? `${trimmed}'` : `${trimmed}'s`;
}

function toThirdPersonVerb(verb: string): string {
  const lower = verb.toLowerCase();
  const irregular = new Map<string, string>([
    ["am", "is"],
    ["are", "is"],
    ["were", "was"],
    ["have", "has"],
    ["do", "does"],
  ]);
  const irregularMatch = irregular.get(lower);
  if (irregularMatch) return irregularMatch;
  const doNotTransform = new Set([
    "can",
    "can't",
    "cannot",
    "could",
    "couldn't",
    "did",
    "didn't",
    "does",
    "doesn't",
    "had",
    "has",
    "is",
    "might",
    "must",
    "shall",
    "should",
    "shouldn't",
    "was",
    "will",
    "won't",
    "would",
    "wouldn't",
  ]);
  if (doNotTransform.has(lower)) return lower;
  if (lower.endsWith("ies") || lower.endsWith("s")) return lower;
  if (lower.endsWith("y") && lower.length > 1 && !/[aeiou]y$/.test(lower)) {
    return `${lower.slice(0, -1)}ies`;
  }
  if (/(ch|sh|x|z|o)$/.test(lower)) return `${lower}es`;
  return `${lower}s`;
}

function formatMemoryPanelText(
  text: string,
  subjectLabel: string,
  category: MemoryCategory
): string {
  const normalized = text.trim();
  if (!normalized) return normalized;
  if (category !== "user") return normalized;
  const subject = subjectLabel.trim() || "User";
  const possessive = toPossessiveLabel(subject);
  const subjectPattern = subject.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const rewritten = normalized
    .replace(/^the user's\b/i, possessive)
    .replace(/^user's\b/i, possessive)
    .replace(/^your\b/i, possessive)
    .replace(/^the user\b/i, subject)
    .replace(/^user\b/i, subject)
    .replace(/^you(?:'re| are)\b/i, `${subject} is`)
    .replace(/^you(?:'ve| have)\b/i, `${subject} has`)
    .replace(/^you(?:'d| would)\b/i, `${subject} would`)
    .replace(/^you(?:'ll| will)\b/i, `${subject} will`)
    .replace(/^you don't\b/i, `${subject} doesn't`)
    .replace(/^you do\b/i, `${subject} does`)
    .replace(/^you were\b/i, `${subject} was`)
    .replace(/^you\b/i, subject);

  const lead = rewritten.match(new RegExp(`^${subjectPattern}\\s+([A-Za-z']+)\\b`, "i"));
  const verb = lead?.[1];
  if (!verb) return rewritten;
  const thirdPerson = toThirdPersonVerb(verb);
  return rewritten.replace(
    new RegExp(`^(${subjectPattern}\\s+)${verb}\\b`, "i"),
    `$1${thirdPerson}`
  );
}

function stableUnitValue(seed: string): number {
  let hash = 2166136261;
  for (let i = 0; i < seed.length; i += 1) {
    hash ^= seed.charCodeAt(i);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0) / 0xffffffff;
}

/**
 * Floating orbit dots for zoomed-out PRISM directory bubbles — one dot per bot
 * (up to {@link MEMORY_FAMILY_BOT_INNER_DOT_MAX}), matching the drill-down bot orbs.
 */
function buildFamilyDirectoryBotInnerBubbles(
  familyId: string,
  botCount: number,
  familySizePx: number
): MemoryClusterInnerBubble[] {
  if (botCount <= 0) return [];
  const capped = Math.min(botCount, MEMORY_FAMILY_BOT_INNER_DOT_MAX);
  const orbitScale = Math.max(0.38, Math.min(1.12, familySizePx / MEMORY_RATIO_LARGE_MAX_SIZE));
  const placed: Array<{ x: number; y: number; radius: number }> = [];
  const bubbles: MemoryClusterInnerBubble[] = [];
  const density = Math.min(1, capped / Math.max(1, MEMORY_FAMILY_BOT_INNER_DOT_MAX));

  for (let i = 0; i < capped; i += 1) {
    const size = 3.8 + density * 2.6 + ((i + capped) % 3) * 0.95;
    const radius = size / 2;
    const minCenterRadius = (9 + radius) * orbitScale;
    const maxCenterRadius = Math.max(minCenterRadius + 1, (30 - radius) * orbitScale);
    let candidate: { x: number; y: number; radius: number } | null = null;

    for (let attempt = 0; attempt < 48; attempt += 1) {
      const angle = stableUnitValue(`family:${familyId}:bot-dot:${i}:a:${attempt}`) * Math.PI * 2;
      const radialSeed = stableUnitValue(`family:${familyId}:bot-dot:${i}:r:${attempt}`);
      const radialT = Math.pow(radialSeed, 0.36);
      const distance = minCenterRadius + radialT * (maxCenterRadius - minCenterRadius);
      const x = Math.cos(angle) * distance;
      const y = Math.sin(angle) * distance;
      const overlaps = placed.some((other) => {
        const dx = x - other.x;
        const dy = y - other.y;
        const minDistance = radius + other.radius + 2;
        return dx * dx + dy * dy < minDistance * minDistance;
      });
      if (!overlaps) {
        candidate = { x, y, radius };
        break;
      }
    }

    if (!candidate) {
      const fallbackAngle = ((i * 137.50776405) % 360) * (Math.PI / 180);
      const fallbackDistance = Math.min(maxCenterRadius, 12 + i * 1.85);
      candidate = {
        x: Math.cos(fallbackAngle) * fallbackDistance,
        y: Math.sin(fallbackAngle) * fallbackDistance,
        radius,
      };
    }

    placed.push(candidate);
    bubbles.push({
      id: `${familyId}-family-bot-${i}`,
      style: {
        ["--memory-inner-x" as string]: `${candidate.x.toFixed(2)}px`,
        ["--memory-inner-y" as string]: `${candidate.y.toFixed(2)}px`,
        ["--memory-inner-size" as string]: `${size.toFixed(2)}px`,
        ["--memory-inner-dx" as string]: `${(
          (stableUnitValue(`family:${familyId}:bot-dot:${i}:dx`) - 0.5) *
          6
        ).toFixed(2)}px`,
        ["--memory-inner-dy" as string]: `${(
          (stableUnitValue(`family:${familyId}:bot-dot:${i}:dy`) - 0.5) *
          6
        ).toFixed(2)}px`,
        ["--memory-inner-duration" as string]: `${(
          2.8 + stableUnitValue(`family:${familyId}:bot-dot:${i}:dur`) * 2.2
        ).toFixed(2)}s`,
        ["--memory-inner-delay" as string]: `${(i * 0.14).toFixed(2)}s`,
      } as React.CSSProperties,
    });
  }

  return bubbles;
}

// Build a left-to-right gradient from up to N bot colors in a group so
// each editor dashboard button reads as an ordered slice of its bucket's
// actual spectrum. Stops are color-mixed against `--bg` so the tile still
// feels like a calm card.
// Returns null when no bot has a usable color.
function buildBotGroupGradient(
  groupBots: readonly Bot[],
  theme: "light" | "dark",
  harmonyActive: boolean,
  mixPercent: number
): string | null {
  if (groupBots.length === 0) return null;
  const sampleSize = Math.min(groupBots.length, 6);
  const stride = groupBots.length / sampleSize;
  const stops: string[] = [];
  for (let i = 0; i < sampleSize; i++) {
    const idx = Math.min(groupBots.length - 1, Math.floor(i * stride));
    const bot = groupBots[idx];
    const accent = bot.color
      ? panelBotDisplayAccent(bot.color, theme, harmonyActive)
      : null;
    if (!accent) continue;
    stops.push(
      `color-mix(in srgb, ${accent} ${mixPercent}%, var(--bg) ${100 - mixPercent}%)`
    );
  }
  if (stops.length === 0) return null;
  if (stops.length === 1) return stops[0];
  return `linear-gradient(to right, ${stops.join(", ")})`;
}

// Map a hex color to one of the five Prism letter buckets. Hue cuts
// mirror botColorFamilyGroup but collapse adjacent fine-grained
// families into the closest wordmark letter so the dashboard reads
// as the Prism color family the user already sees in the brand mark.
// Invalid/grayscale legacy colors still classify by hue so every bot
// can find a home in one of the five letters — randomHex() prevents
// new bots from ever being grayscale in the first place.
function botPrismGroup(hex: string | null | undefined): PrismGroupId {
  const raw = hex?.trim();
  if (!raw || !hexChannels(raw)) return "p";
  const { h } = hexToHsl(raw);
  if (h >= 315) return "p";
  if (h < 15) return "p";
  if (h < 75) return "r"; // orange + yellow
  if (h < 165) return "i"; // lime + green
  if (h < 245) return "s"; // cyan + blue
  return "m"; // indigo + violet + magenta-leaning purple
}

// Accent color for new bots defaults to randomHex() via component state on
// first paint. Subsequent random seeds run only when the Bots panel opens
// in create mode before the user has typed anything — closing the panel and
// reopening preserves picks + text (see bots-panel seed useEffect below).
interface ImageRecord {
  id: string;
  prompt: string;
  url: string;
  createdAt: string;
  botId?: string | null;
  /** Prefer for rendering — points at authenticated `/api/images/:id/file` when durably stored. */
  displayUrl?: string;
  hasLocalFile?: boolean;
  revisedPrompt?: string | null;
  size?: string;
  quality?: string;
  provider?: string;
  model?: string | null;
  localRelPath?: string | null;
  purpose?: "gallery" | "wallpaper" | string | null;
}

/** Authenticated WebP thumbnail for a locally stored generated image (`images.id`). */
function apiGeneratedImageThumbUrl(imageId: string): string {
  return `/api/images/${encodeURIComponent(imageId)}/thumb`;
}

/** Images panel grid tile: prefer `/thumb` for local files; remote-only rows keep full URL. */
function galleryTileImageSrc(img: ImageRecord): string {
  if (img.hasLocalFile === true) {
    return apiGeneratedImageThumbUrl(img.id);
  }
  return img.displayUrl ?? img.url;
}

/** Short label for gallery thumbnails — catalog match when possible, else raw id. */
function galleryImageThumbModelLabel(
  img: ImageRecord,
  localCatalog: ModelCatalogEntry[],
  openAiCatalog: ModelCatalogEntry[]
): string {
  const raw = img.model?.trim();
  if (!raw) return "Unknown model";
  const catalog = img.provider === "openai" ? openAiCatalog : localCatalog;
  return catalog.find((e) => e.id === raw)?.label ?? raw;
}

type ImagePanelScope = "all" | "bot" | "general";

type ScopedImageKeywords = {
  positive: string[];
  negative: string[];
};

type ImageKeywordDragMode = "add" | "remove";

const IMAGE_KEYWORD_CHIP_ROW_GAP_PX = 4;
const IMAGE_KEYWORD_CHIP_BASE_WIDTH_PX = 26;
const IMAGE_KEYWORD_CHIP_CHAR_WIDTH_PX = 7.1;
const IMAGE_KEYWORD_CHIP_MIN_PACK_WIDTH_PX = 120;
const IMAGE_KEYWORD_EDITOR_KINDS = ["negative", "positive"] as const;

/** Sandbox hero mini library: newest saved images for the visually selected bot. */
const HERO_MINI_LIBRARY_MAX_TILES = 12;

const EMPTY_SCOPED_IMAGE_KEYWORDS: ScopedImageKeywords = {
  positive: [],
  negative: [],
};

function estimateImageKeywordChipWidthPx(tag: string): number {
  const normalizedLength = tag.trim().length;
  return Math.max(
    56,
    Math.round(IMAGE_KEYWORD_CHIP_BASE_WIDTH_PX + normalizedLength * IMAGE_KEYWORD_CHIP_CHAR_WIDTH_PX)
  );
}

function buildPackedImageKeywordDisplayOrder(
  tags: string[],
  containerWidthPx: number,
  measuredChipWidths: Record<string, number>
): string[] {
  if (tags.length <= 2) return tags.slice();
  const rowCapacity = Math.max(IMAGE_KEYWORD_CHIP_MIN_PACK_WIDTH_PX, Math.floor(containerWidthPx));
  if (rowCapacity <= IMAGE_KEYWORD_CHIP_MIN_PACK_WIDTH_PX) return tags.slice();
  const weighted = tags
    .map((tag, index) => ({
      tag,
      index,
      width: measuredChipWidths[tag] ?? estimateImageKeywordChipWidthPx(tag),
    }))
    .sort((left, right) => right.width - left.width || left.index - right.index);
  const pool = weighted.slice();
  const rows: Array<{ tags: string[] }> = [];
  while (pool.length > 0) {
    const anchor = pool.shift();
    if (!anchor) break;
    const rowTags = [anchor.tag];
    let remainingWidth = Math.max(0, rowCapacity - anchor.width);
    while (pool.length > 0) {
      const neededForGap = rowTags.length > 0 ? IMAGE_KEYWORD_CHIP_ROW_GAP_PX : 0;
      const allowedWidth = remainingWidth - neededForGap;
      if (allowedWidth <= 0) break;
      let candidateIndex = -1;
      // Back-fill gaps with smaller chips first.
      for (let index = pool.length - 1; index >= 0; index -= 1) {
        const candidate = pool[index];
        if (!candidate) continue;
        if (candidate.width <= allowedWidth) {
          candidateIndex = index;
          break;
        }
      }
      if (candidateIndex < 0) break;
      const [picked] = pool.splice(candidateIndex, 1);
      if (!picked) break;
      rowTags.push(picked.tag);
      remainingWidth = Math.max(0, remainingWidth - (picked.width + neededForGap));
    }
    rows.push({
      tags: rowTags,
    });
  }
  return rows.flatMap((row) => row.tags);
}

const DEFAULT_ASSISTANT_NAME = "Prism";
const PRISM_MESSAGE_ROLE_LETTERS = ["P", "R", "I", "S", "M"] as const;
const DEFAULT_MESSAGE_MOOD: NonNullable<Message["moodKey"]> = "neutral";

function normalizeAssistantMoodKey(
  moodKey: Message["moodKey"] | undefined
): NonNullable<Message["moodKey"]> {
  if (
    moodKey === "joyful" ||
    moodKey === "warm" ||
    moodKey === "neutral" ||
    moodKey === "guarded" ||
    moodKey === "strained"
  ) {
    return moodKey;
  }
  return DEFAULT_MESSAGE_MOOD;
}

function coffeeSocialByIdToPrismMood(
  socialById: Record<string, CoffeeBotSocialSnapshot> | null | undefined
): PrismMoodSnapshot | null {
  const snapshots = Object.values(socialById ?? {});
  if (snapshots.length === 0) return null;
  const aggregate = snapshots.reduce(
    (acc, social) => ({
      disposition: acc.disposition + social.disposition,
      valuesFriction: acc.valuesFriction + social.valuesFriction,
      restraint: acc.restraint + social.restraint,
      engagement: acc.engagement + social.engagement,
      leavePressure: acc.leavePressure + social.leavePressure,
    }),
    {
      disposition: 0,
      valuesFriction: 0,
      restraint: 0,
      engagement: 0,
      leavePressure: 0,
    }
  );
  const count = snapshots.length;
  return coffeeSocialSnapshotToPrismMoodState({
    disposition: aggregate.disposition / count,
    valuesFriction: aggregate.valuesFriction / count,
    restraint: aggregate.restraint / count,
    engagement: aggregate.engagement / count,
    leavePressure: aggregate.leavePressure / count,
  });
}

function messageHasCustomBotIdentity(message: Message): boolean {
  return Boolean(
    message.botName?.trim() ||
    message.botColor?.trim() ||
    message.botGlyph?.trim()
  );
}

function shouldRenderPrismMessageRoleLabel(message: Message, incognito: boolean): boolean {
  return (
    message.role === "assistant" &&
    !incognito &&
    !messageHasCustomBotIdentity(message)
  );
}

function PrismMessageRoleLabel(): React.JSX.Element {
  return (
    <span className={styles.prismMessageRoleLabel}>
      <span className={styles.messageRoleVisuallyHidden}>
        {DEFAULT_ASSISTANT_NAME}
      </span>
      <span className={styles.prismMessageRoleLetters} aria-hidden="true">
        {PRISM_MESSAGE_ROLE_LETTERS.map((letter) => (
          <span
            key={letter}
            className={styles.prismMessageRoleLetter}
          >
            {letter}
          </span>
        ))}
      </span>
    </span>
  );
}

function resolveMessageMoodKey(message: Message): NonNullable<Message["moodKey"]> {
  if (message.role !== "assistant") return DEFAULT_MESSAGE_MOOD;
  return normalizeAssistantMoodKey(message.moodKey);
}

function messageMoodLabel(moodKey: NonNullable<Message["moodKey"]>): string {
  switch (moodKey) {
    case "joyful":
      return "Joyful";
    case "warm":
      return "Warm";
    case "guarded":
      return "Guarded";
    case "strained":
      return "Strained";
    default:
      return "Neutral";
  }
}

function MessageMoodFace(props: {
  moodKey: NonNullable<Message["moodKey"]>;
  variant?: "classic" | "prism";
  placement?: "leading" | "trailing";
  color?: string | null;
  voicePreset?: BotVoicePreset;
}): React.JSX.Element {
  const variant = props.variant ?? "classic";
  const placement = props.placement ?? "trailing";
  const moodKey = props.moodKey;
  const seatEmojiTier = coffeeSeatEmojiMoodFromPrism(moodKey);
  const seatPlateGlyph = coffeeSeatPlateGlyph(seatEmojiTier, false);
  const color = props.color?.trim();
  const style = color
    ? ({ ["--coffee-bot-color" as string]: color } as React.CSSProperties)
    : undefined;
  return (
    <span
      className={styles.messageMoodBadge}
      data-mood={moodKey}
      data-placement={placement}
      data-face="coffee"
      data-variant={variant}
      style={style}
      aria-hidden="true"
    >
      <CoffeeSeatPlateEmoji
        enabled={variant === "prism"}
        isTalking={false}
        scheduleKey={`message-mood-${variant}-${moodKey}`}
        baseText={seatPlateGlyph.text}
        rotateDeg={seatPlateGlyph.rotateDeg}
        voicePreset={props.voicePreset ?? "neutral"}
        className={styles.messageMoodCoffeeFace}
      />
    </span>
  );
}

// PRISM fallback for non-private Default/no-bot surfaces that still need a
// single accent token. Private/incognito remains the only monochrome path.
const PRISM_DEFAULT_ACCENT = PRISM_COLORS.s;

function neutralRowColor(resolvedTheme: "light" | "dark"): string {
  return resolvedTheme === "dark" ? "#ffffff" : "#000000";
}

// Resolve a sidebar conversation row's custom-bot tint color from the server-side
// denormalized `lastBotColor`. Default/no-bot chats are handled separately so
// they can keep the same row-gradient structure with a neutral black/white tint.
//
// Order matters:
//   1. Incognito wins — private rows never pick up a hue (grayscale
//      styling comes from the private-row CSS, not from this resolver).
//   2. `lastBotColor` is the server's denormalized color at the time it
//      responded, so it stays correct even if the bot was later deleted
//      or recolored.
//   3. `hasAssistantReply && !lastBotColor` means the last reply came
//      from the Default bot (no bot_id) — no custom hue.
//   4. `botId` → live bots[] lookup. Catches the pre-reply window where
//      a conversation has a locked bot but no assistant message yet.
//   5. No locked bot and no reply either — no custom hue.
function resolveRowColor(
  c: ConversationSummary,
  bots: Bot[]
): string | null {
  if (c.incognito) return null;
  if (c.lastBotColor) return c.lastBotColor;
  if (c.hasAssistantReply) return null;
  if (c.botId) {
    const live = bots.find((b) => b.id === c.botId)?.color;
    if (live) return live;
  }
  return null;
}

function conversationGroupKey(c: ConversationSummary): string {
  const effectiveBotId = conversationEffectiveBotId(c);
  return effectiveBotId ? `bot:${effectiveBotId}` : "default";
}

function conversationEffectiveBotId(c: ConversationSummary): string | null {
  // Group rows by the same "active identity" users see in sidebar tinting:
  // - after at least one assistant reply, follow the last speaking bot
  // - before first reply, fall back to the conversation's locked starter bot
  return c.hasAssistantReply ? c.lastBotId : c.botId;
}

/** Mirror of `conversationGroupKey` for cases where only the bot id is in
 *  hand — e.g. picking a panel to auto-open after a new chat is committed. */
function conversationGroupKeyForBotId(botId: string): string {
  return `bot:${botId}`;
}

function conversationGroupBotId(key: string): string | null {
  return key.startsWith("bot:") ? key.slice("bot:".length) : null;
}

function conversationGroupDeleteKey(key: string): string {
  return `group:${key}`;
}

/** Namespaces a single chat row delete in `pendingDeleteKey` (sidebar ×). */
function conversationRowDeleteKey(conversationId: string): string {
  return `chatdel:${conversationId}`;
}

/** HTML `id` slug — `group.key` may contain `:` (e.g. `bot:uuid`). */
function conversationGroupDomSafeSlug(key: string): string {
  return key.replace(/[^a-zA-Z0-9_-]/g, "_");
}

function conversationGroupNestedListId(key: string): string {
  return `conversation-group-chats-${conversationGroupDomSafeSlug(key)}`;
}

function conversationGroupHeaderButtonId(key: string): string {
  return `conversation-group-toggle-${conversationGroupDomSafeSlug(key)}`;
}

function conversationGroupOrderStorageKey(userId: string): string {
  return `${CONVERSATION_GROUP_ORDER_STORAGE_KEY}:${userId}`;
}

function botLibraryGroupsStorageKey(userId: string): string {
  return `${BOT_LIBRARY_GROUPS_STORAGE_KEY}:${userId}`;
}

function commandCenterStateStorageKey(userId: string): string {
  return `${COMMAND_CENTER_STATE_STORAGE_KEY}:${userId}`;
}

function loadConversationGroupOrder(userId: string): string[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = window.localStorage.getItem(conversationGroupOrderStorageKey(userId));
    const parsed: unknown = raw ? JSON.parse(raw) : [];
    return Array.isArray(parsed)
      ? parsed.filter((key): key is string => typeof key === "string")
      : [];
  } catch {
    return [];
  }
}

function persistConversationGroupOrder(userId: string, order: string[]): void {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.setItem(
      conversationGroupOrderStorageKey(userId),
      JSON.stringify(order)
    );
  } catch {
    // Non-fatal: drag ordering still works for the current page session.
  }
}

function reorderConversationGroupKeys(
  currentOrder: string[],
  draggedKey: string,
  targetKey: string,
  position: ConversationGroupDropPosition
): string[] {
  if (draggedKey === targetKey) return currentOrder;
  const withoutDragged = currentOrder.filter((key) => key !== draggedKey);
  const targetIndex = withoutDragged.indexOf(targetKey);
  if (targetIndex === -1) return currentOrder;
  const insertIndex = position === "after" ? targetIndex + 1 : targetIndex;
  return [
    ...withoutDragged.slice(0, insertIndex),
    draggedKey,
    ...withoutDragged.slice(insertIndex),
  ];
}

function buildConversationGroupSummary(
  key: string,
  conversations: ConversationSummary[],
  bots: Bot[],
  unreadConversationIds: Set<string>
): ConversationGroupSummary {
  const botId = conversationGroupBotId(key);
  const bot = botId ? bots.find((candidate) => candidate.id === botId) : null;
  const fallbackColor =
    conversations.find((conversation) => conversation.lastBotColor)?.lastBotColor ?? null;
  return {
    key,
    botId,
    name: bot?.name?.trim() || (botId ? "Deleted bot" : DEFAULT_ASSISTANT_NAME),
    glyph: bot
      ? isBotGlyphName(bot.glyph)
        ? bot.glyph
        : DEFAULT_BOT_GLYPH
      : "triangle",
    color: bot?.color ?? fallbackColor,
    count: conversations.length,
    conversations,
    latestUpdatedAt: conversations[0]?.updatedAt ?? "",
    unread: conversations.some((conversation) => unreadConversationIds.has(conversation.id)),
  };
}

function buildConversationGroups(
  conversations: ConversationSummary[],
  bots: Bot[],
  unreadConversationIds: Set<string>
): ConversationGroupSummary[] {
  const grouped = new Map<string, ConversationSummary[]>();
  for (const conversation of conversations) {
    const key = conversationGroupKey(conversation);
    const existing = grouped.get(key);
    if (existing) {
      if (!existing.some((c) => c.id === conversation.id)) {
        existing.push(conversation);
      }
    } else {
      grouped.set(key, [conversation]);
    }
  }
  return [...grouped.entries()]
    .filter(([, rows]) => rows.length > 0)
    .map(([key, rows]) =>
      buildConversationGroupSummary(key, rows, bots, unreadConversationIds)
    );
}

function ThemeGlyph({ mode }: { mode: Theme }): React.ReactElement {
  // Stroke-only 16x16 glyphs that take their color from currentColor, so the
  // same button can shift between muted/hover/locked hues purely via CSS.
  // Matches the lock glyph's visual weight (14px glyph inside a 30px button).
  return (
    <svg
      className={styles.themeToggleGlyph}
      viewBox="0 0 16 16"
      aria-hidden="true"
    >
      {mode === "light" && (
        <>
          {/* Sun: central disc + 8 radial rays. */}
          <circle cx="8" cy="8" r="3" suppressHydrationWarning />
          <path
            d="M8 1v2M8 13v2M1 8h2M13 8h2M3 3l1.5 1.5M11.5 11.5l1.5 1.5M3 13l1.5-1.5M11.5 4.5l1.5-1.5"
            suppressHydrationWarning
          />
        </>
      )}
      {mode === "dark" && (
        /* Crescent moon: one arc carved out of a larger one. */
        <path
          d="M13 9A5.5 5.5 0 1 1 7 3a4.5 4.5 0 0 0 6 6Z"
          suppressHydrationWarning
        />
      )}
      {mode === "system" && (
        <>
          {/* Half-filled circle: outline the full disc, then fill the right
             hemisphere so it reads as "sun on one side, moon on the other". */}
          <circle cx="8" cy="8" r="5.5" suppressHydrationWarning />
          <path
            d="M8 2.5A5.5 5.5 0 0 1 8 13.5Z"
            fill="currentColor"
            stroke="none"
            suppressHydrationWarning
          />
        </>
      )}
    </svg>
  );
}

