  const renderProviderModeToggle = (extraClassName = ""): React.ReactNode => {
    // The toggle simply mirrors `effectivePreferredProvider`, which is
    // already pinned to "local" when the active chat bot is offline-only.
    // We keep the lock indicator + disabled flag tied to that same source
    // of truth so it can never disagree with the model pickers below it.
    const lockedByActiveBot = activeBot?.online_enabled === 0;
    const responseMode = responseModeForProvider(effectivePreferredProvider);
    const isLocal = responseMode === "local";
    const nextMode = nextResponseMode(responseMode);
    const nextResolvedProvider = resolveModelChoiceForResponseMode({
      responseMode: nextMode,
      providerPreference: effectivePreferredProvider,
      choices: visibleModelChoicesByProvider(
        modelCatalog,
        settings,
        chatModelChoiceByProvider
      ),
      onlineOptions: onlineChatModelOptions,
    }).provider;
    const providerDisabled = !settings || lockedByActiveBot;
    const activeModeLabel = responseModeDisplayLabel(responseMode);
    const nextModeLabel = responseModeDisplayLabel(nextMode);
    const lockTitle = lockedByActiveBot
      ? `🔒 Locked to LOCAL — ${activeBot?.name ?? "this bot"} is set to Offline only.`
      : null;
    return (
      <div
        className={`${styles.modeControl} ${
          providerDisabled ? styles.modeControlLocked : ""
        } ${extraClassName}`}
        data-protected={lockedByActiveBot ? "true" : undefined}
      >
        <button
          type="button"
          className={`${styles.modeToggleTrack} ${
            providerDisabled ? styles.modeToggleTrackLocked : ""
          }`}
          data-response-mode={isLocal ? "local" : "online"}
          data-protected={lockedByActiveBot ? "true" : undefined}
          onClick={() => {
            if (providerDisabled) return;
            void switchProvider(nextResolvedProvider);
          }}
          aria-label={
            lockTitle
              ? `${lockTitle} Toggle disabled.`
              : `Response mode: ${activeModeLabel}. Click to switch to ${nextModeLabel}.`
          }
          aria-pressed={!isLocal}
          aria-disabled={providerDisabled}
          title={lockTitle ?? `Switch to ${nextModeLabel}`}
          disabled={providerDisabled}
        >
          <span
            className={`${styles.modeThumb} ${
              isLocal ? styles.modeThumbLocal : styles.modeThumbOnline
            }`}
          >
            {lockedByActiveBot ? (
              <span
                className={styles.modeThumbLockGlyph}
                aria-hidden="true"
              >
                🔒
              </span>
            ) : (
              <span
                className={`${styles.providerDot} ${
                  isLocal ? styles.providerDotLocal : styles.providerDotOnline
                }`}
                aria-hidden="true"
              />
            )}
            <span className={styles.modeThumbLabel}>
              {responseModeShortLabel(responseMode)}
            </span>
          </span>
        </button>
      </div>
    );
  };
  /** Coffee-only provider rail: same `chatHeaderModeToggle` styling as the main
   *  chat header (bot-tinted rail + flush geometry); routes `coffeeProvider`
   *  instead of mutating global Settings.
   *
   *  Lock semantics: when at least one seated/selected bot is "Offline only",
   *  the toggle is forced to LOCAL and disabled. The matching coercion
   *  effect above keeps `coffeeProvider` itself pinned to "local" so request
   *  bodies never disagree with the visible state. */
  const renderCoffeeProviderModeToggle = (): React.ReactNode => {
    const lockedByProtectedBot = coffeeAnyOfflineProtected;
    const effectiveCoffeeProvider = lockedByProtectedBot ? "local" : coffeeProvider;
    const responseMode = responseModeForProvider(effectiveCoffeeProvider);
    const isLocal = responseMode === "local";
    const nextMode = nextResponseMode(responseMode);
    const nextResolvedProvider = resolveModelChoiceForResponseMode({
      responseMode: nextMode,
      providerPreference: effectiveCoffeeProvider,
      choices: visibleModelChoicesByProvider(
        modelCatalog,
        settings,
        coffeeModelChoiceByProvider
      ),
      onlineOptions: onlineChatModelOptions,
    }).provider;
    const activeModeLabel = responseModeDisplayLabel(responseMode);
    const nextModeLabel = responseModeDisplayLabel(nextMode);
    const providerDisabled = !settings || lockedByProtectedBot;
    const lockTitle = lockedByProtectedBot
      ? "🔒 Locked to LOCAL — at least one seated bot is set to Offline only."
      : null;
    return (
      <div
        className={`${styles.modeControl} ${
          providerDisabled ? styles.modeControlLocked : ""
        } ${styles.chatHeaderModeToggle}`}
        data-protected={lockedByProtectedBot ? "true" : undefined}
      >
        <button
          type="button"
          className={`${styles.modeToggleTrack} ${
            providerDisabled ? styles.modeToggleTrackLocked : ""
          }`}
          data-response-mode={isLocal ? "local" : "online"}
          data-protected={lockedByProtectedBot ? "true" : undefined}
          onClick={() => {
            if (providerDisabled) return;
            setCoffeeProvider(nextResolvedProvider);
            setCoffeeProviderTouched(true);
          }}
          aria-label={
            lockTitle
              ? `${lockTitle} Toggle disabled.`
              : `Response mode: ${activeModeLabel}. Click to switch to ${nextModeLabel}.`
          }
          aria-pressed={!isLocal}
          aria-disabled={providerDisabled}
          title={lockTitle ?? `Switch to ${nextModeLabel}`}
          disabled={providerDisabled}
        >
          <span
            className={`${styles.modeThumb} ${
              isLocal ? styles.modeThumbLocal : styles.modeThumbOnline
            }`}
          >
            {lockedByProtectedBot ? (
              <span
                className={styles.modeThumbLockGlyph}
                aria-hidden="true"
              >
                🔒
              </span>
            ) : (
              <span
                className={`${styles.providerDot} ${
                  isLocal ? styles.providerDotLocal : styles.providerDotOnline
                }`}
                aria-hidden="true"
              />
            )}
            <span className={styles.modeThumbLabel}>
              {responseModeShortLabel(responseMode)}
            </span>
          </span>
        </button>
      </div>
    );
  };
  const renderCoffeeHeaderModelPicker = (): React.ReactNode => {
    if (!settings) return null;
    const lockedByProtectedBot = coffeeAnyOfflineProtected;
    const effectiveProvider = lockedByProtectedBot ? "local" : coffeeProvider;
    const responseMode = responseModeForProvider(effectiveProvider);
    const isLocal = responseMode === "local";
    const resolvedChoice = resolveModelChoiceForResponseMode({
      responseMode,
      providerPreference: effectiveProvider,
      choices: visibleModelChoicesByProvider(
        modelCatalog,
        settings,
        coffeeModelChoiceByProvider
      ),
      onlineOptions: onlineChatModelOptions,
    });
    const modelProvider = resolvedChoice.provider;
    const visibleModelChoice = resolvedChoice.modelChoice;
    const modelOptions = includeSelectedResponseModeModelOption(
      modelCatalog,
      settings,
      responseMode,
      modelOptionsForResponseMode(modelCatalog, settings, responseMode),
      visibleModelChoice,
      modelProvider
    );
    return (
      <ComposerModelPicker
        value={visibleModelChoice}
        onChange={(nextChoice) => {
          const appliedOnline =
            responseMode === "online"
              ? applyOnlineModelChoice({
                  currentChoices: coffeeModelChoiceByProvider,
                  nextChoice,
                  onlineOptions: onlineChatModelOptions,
                  providerPreference: effectiveProvider,
                })
              : null;
          setCoffeeModelChoiceByProvider((previous) => {
            const next =
              responseMode === "local"
                ? { ...previous, local: nextChoice }
                : applyOnlineModelChoice({
                    currentChoices: previous,
                    nextChoice,
                    onlineOptions: onlineChatModelOptions,
                    providerPreference: effectiveProvider,
                  }).choices;
            persistCoffeeModelChoicesForScope(next);
            return next;
          });
          if (appliedOnline) {
            setCoffeeProvider(appliedOnline.provider);
            setCoffeeProviderTouched(true);
          }
        }}
        options={modelOptions}
        provider={isLocal ? "local" : "online"}
        disabled={coffeeBusy || coffeeAutoBusy}
        title={`Coffee model (${responseModeShortLabel(responseMode)} — overrides each seated bot)`}
        ariaLabel={`Coffee session model for ${
          isLocal ? "local" : "online"
        } replies`}
        dismissPopoversSignal={composerPopoverDismissSignal}
        placement="down"
        minMenuWidthPx={180}
        settingsDefaultModelId={chatSettingsSavedDefaultModelId(
          settings,
          isLocal ? "local" : "online"
        )}
        effortControl={
          modelChoiceSupportsReasoningEffort(modelProvider, visibleModelChoice)
            ? {
                value: coffeeReasoningEffort,
                onChange: (next) => {
                  setCoffeeReasoningEffort(next);
                  persistCoffeeReasoningEffortForScope(next);
                },
              }
            : undefined
        }
      />
    );
  };
  const renderHeaderModelPicker = (
    options: {
      modelMenuClassName?: string;
      modelMenuWidthPx?: number;
    } = {}
  ): React.ReactNode => {
    // Use the effective provider so the picker shows local options whenever
    // the active bot is locked offline-only — even if the user's saved
    // global preference is online.
    const responseMode = responseModeForProvider(effectivePreferredProvider);
    const isLocal = responseMode === "local";
    const resolvedChoice = resolveModelChoiceForResponseMode({
      responseMode,
      providerPreference: effectivePreferredProvider,
      choices: visibleModelChoicesByProvider(
        modelCatalog,
        settings,
        chatModelChoiceByProvider
      ),
      onlineOptions: onlineChatModelOptions,
    });
    const modelProvider = resolvedChoice.provider;
    const visibleModelChoice = resolvedChoice.modelChoice;
    const modelOptions = includeSelectedResponseModeModelOption(
      modelCatalog,
      settings,
      responseMode,
      modelOptionsForResponseMode(modelCatalog, settings, responseMode),
      visibleModelChoice,
      modelProvider
    );
    const botHasCommenced = !!detail && detail.messages.length > 0;
    const botDisabled = view === "chat" ? !detail : false;
    const zenPersonaPickerDisabled =
      view === "chat" &&
      (pendingReplyVisible || (!detail && !forceNewConversationOnNextSend));
    const botPickerBots = botHasCommenced ? bots : filteredBots;
    return (
      <div className={styles.chatHeaderModelPicker}>
        {renderProviderModeToggle(styles.chatHeaderModeToggle)}
        <ComposerModelPicker
          value={visibleModelChoice}
          onChange={(nextChoice) => {
            const appliedOnline =
              responseMode === "online"
                ? applyOnlineModelChoice({
                    currentChoices: chatModelChoiceByProvider,
                    nextChoice,
                    onlineOptions: onlineChatModelOptions,
                    providerPreference: effectivePreferredProvider,
                  })
                : null;
            setChatModelChoiceByProvider((previous) => {
              const next =
                responseMode === "local"
                  ? { ...previous, local: nextChoice }
                  : applyOnlineModelChoice({
                      currentChoices: previous,
                      nextChoice,
                      onlineOptions: onlineChatModelOptions,
                      providerPreference: effectivePreferredProvider,
                    }).choices;
              persistChatModelChoicesForActiveScope(next);
              return next;
            });
            if (appliedOnline) {
              void switchProvider(appliedOnline.provider);
            }
          }}
          options={modelOptions}
          provider={isLocal ? "local" : "online"}
          disabled={!settings || pendingReplyVisible}
          title={`Model for ${responseModeShortLabel(responseMode)} replies`}
          ariaLabel={`Model for ${
            isLocal ? "local" : "online"
          } replies`}
          dismissPopoversSignal={composerPopoverDismissSignal}
          placement="down"
          minMenuWidthPx={options.modelMenuWidthPx ?? 180}
          menuClassName={options.modelMenuClassName}
          settingsDefaultModelId={chatSettingsSavedDefaultModelId(
            settings,
            isLocal ? "local" : "online"
          )}
          effortControl={
            modelChoiceSupportsReasoningEffort(modelProvider, visibleModelChoice)
              ? {
                  value: chatReasoningEffort,
                  onChange: (next) => {
                    setChatReasoningEffort(next);
                    persistChatReasoningEffortForActiveScope(next);
                  },
                }
              : undefined
          }
        />
        {view === "chat" && zenPersonaPickerBots.length > 0 ? (
          <ComposerBotPicker
            value={zenPersonaBotId ?? ""}
            onChange={handleZenPersonaSelectionChange}
            bots={zenPersonaPickerBots}
            resolvedTheme={resolvedTheme}
            placement="down"
            disabled={zenPersonaPickerDisabled}
            title={
              pendingReplyVisible
                ? "Wait for the current reply before changing Persona."
                : !detail && !forceNewConversationOnNextSend
                ? "Zen is opening."
                : "Persona for Zen replies"
            }
            ariaLabel="Zen Persona"
            showName
            enableFilters
            hueFilterCenter={hueFilterCenter}
            onHueChange={setHueFilterCenter}
            hueLensAvailable={hueLensAvailable}
            hueLensTrackGradient={hueLensTrackGradient}
            hueLensTrackSegments={hueLensTrackSegments}
            dismissPopoversSignal={composerPopoverDismissSignal}
          />
        ) : null}
        {view === "sandbox" && bots.length > 0 ? (
          <ComposerBotPicker
            value={selectedBotId ?? ""}
            onChange={handleComposerBotSelectionChange}
            bots={botPickerBots}
            resolvedTheme={resolvedTheme}
            placement="down"
            disabled={botDisabled}
            title={
              !detail
                ? "Pick a bot from the grid above to start the chat. You can swap here between sends once it begins."
                : undefined
            }
            ariaLabel="Bot for the next message"
            showName={botHasCommenced}
            enableFilters={view === "sandbox" || botHasCommenced}
            hueFilterCenter={hueFilterCenter}
            onHueChange={setHueFilterCenter}
            hueLensAvailable={hueLensAvailable}
            hueLensTrackGradient={hueLensTrackGradient}
            hueLensTrackSegments={hueLensTrackSegments}
            dismissPopoversSignal={composerPopoverDismissSignal}
          />
        ) : null}
      </div>
    );
  };

  const renderImagesPanelModelPicker = (): React.ReactNode => {
    // Image panel inherits the chat-side lock: when the active chat bot is
    // offline-only, every image generation surface (including this picker)
    // should show local options only. A future refinement can lock based
    // on `imagePanelBot` independently when scope === "bot"; for now the
    // chat-context lock covers the common case (user opens Images while
    // chatting with a protected bot).
    const isLocal = effectivePreferredProvider === "local";
    const modelProvider: Provider = isLocal ? "local" : "openai";
    const rawChoice = imageGenModelChoiceByProvider[modelProvider];
    const trimmedChoice = rawChoice?.trim() ?? "";

    if (modelProvider === "local" && localImageModelCatalogEntries.length === 0) {
      return (
        <div
          className={`${styles.chatHeaderModelPicker} ${styles.panelImagesHeaderModelPicker}`}
        >
          {renderProviderModeToggle(styles.chatHeaderModeToggle)}
          <ComposerModelPicker
            value={NO_LOCAL_IMAGE_MODEL_CHOICE}
            onChange={() => {}}
            options={[
              {
                id: NO_LOCAL_IMAGE_MODEL_CHOICE,
                label: "No image models detected",
                provider: "local",
              },
            ]}
            provider="local"
            disabled
            title="Install an image model via Ollama (for example: ollama pull flux2-klein), or add your ComfyUI server URL in Settings."
            ariaLabel="No local image models — configure Ollama or ComfyUI in Settings"
            placement="down"
            minMenuWidthPx={180}
            showAutoOption={false}
            settingsDefaultModelId={null}
            dismissPopoversSignal={composerPopoverDismissSignal}
          />
        </div>
      );
    }

    const openAiSeedForMenu =
      modelProvider === "openai"
        ? trimmedChoice === AUTO_MODEL_CHOICE || trimmedChoice === ""
          ? firstRunnableOnlineImageModelId
          : trimmedChoice
        : firstRunnableOnlineImageModelId;
    const visibleOpenAiSeedForMenu =
      visibleOnlineImageModelIdOrEmpty(openAiSeedForMenu) ||
      firstRunnableOnlineImageModelId ||
      "";
    const onlineOpts = includeSelectedModelOption(
      onlineImageModelCatalogEntries,
      visibleOpenAiSeedForMenu,
      "openai"
    );
    const visibleLocalChoice =
      trimmedChoice === AUTO_MODEL_CHOICE || trimmedChoice === ""
        ? AUTO_MODEL_CHOICE
        : localImageModelCatalogEntries.some((entry) => entry.id === trimmedChoice)
          ? trimmedChoice
          : localImageModelCatalogEntries[0]?.id ?? AUTO_MODEL_CHOICE;
    const localOpts = includeSelectedLocalImageModelOption(
      localImageModelCatalogEntries,
      visibleLocalChoice
    );

    const modelOptions = modelProvider === "openai" ? onlineOpts : localOpts;
    const visibleChoice =
      modelProvider === "openai"
        ? trimmedChoice === AUTO_MODEL_CHOICE || trimmedChoice === ""
          ? AUTO_MODEL_CHOICE
          : visibleOnlineImageModelIdOrEmpty(trimmedChoice) || AUTO_MODEL_CHOICE
        : visibleLocalChoice;

    return (
      <div
        className={`${styles.chatHeaderModelPicker} ${styles.panelImagesHeaderModelPicker}`}
      >
        {renderProviderModeToggle(styles.chatHeaderModeToggle)}
        <ComposerModelPicker
          value={visibleChoice}
          onChange={(nextChoice) => {
            setImageGenModelChoiceByProvider((previous) => ({
              ...previous,
              [modelProvider]: nextChoice,
            }));
            void persistPreferredImageModel(modelProvider, nextChoice);
          }}
          options={modelOptions}
          provider={isLocal ? "local" : "online"}
          disabled={
            !settings ||
            (!isLocal && !hasVisibleOnlineImageModels)
          }
          title={
            isLocal
              ? "Image model (LOCAL)"
              : hasRunnableOnlineImageModels
                ? "Image model (ONLINE)"
                : hasVisibleOnlineImageModels
                  ? "Online image models are visible, but no runnable model is available yet."
                  : "Add an OpenAI or ElevenLabs key in Settings to enable online image models."
          }
          ariaLabel={`Image generation model for ${isLocal ? "local" : "online"}`}
          placement="down"
          minMenuWidthPx={180}
          showAutoOption
          settingsDefaultModelId={imageSettingsSavedDefaultModelId(
            settings,
            modelProvider
          )}
          dismissPopoversSignal={composerPopoverDismissSignal}
        />
      </div>
    );
  };

  // The sidebar is primarily a place to leave the current chat, but grouped
  // histories need the active row as a stable "you are here" marker. Keep
  // saved non-private chats in the grouping input, then hide only lone active
  // rows when rendering the final sidebar list.
  // Private rows are filtered here as a client-side guard for older API
  // payloads or pre-ephemeral rows that should never reach the sidebar UI.
  const visibleConversations = useMemo(
    () => {
      const order = new Map(
        unreadConversationOrder.map((conversationId, index) => [conversationId, index])
      );
      return conversations
        .filter((conversation) => {
          if (conversation.incognito) return false;
          if (
            view === "sandbox" &&
            (conversation.mode === "zen" || conversation.mode === "chat")
          ) {
            return false;
          }
          return true;
        })
        .slice()
        .sort((a, b) => {
          const aOrder = order.get(a.id);
          const bOrder = order.get(b.id);
          if (aOrder !== undefined && bOrder !== undefined) return aOrder - bOrder;
          if (aOrder !== undefined) return -1;
          if (bOrder !== undefined) return 1;
          return 0;
        });
    },
    [conversations, unreadConversationOrder, view]
  );
  const conversationGroups = useMemo(
    () => buildConversationGroups(visibleConversations, bots, unreadConversationIds),
    [visibleConversations, bots, unreadConversationIds]
  );
  const conversationGroupsByKey = useMemo(
    () => new Map(conversationGroups.map((group) => [group.key, group])),
    [conversationGroups]
  );
  const hasSweepEligibleConversations = useMemo(
    () => conversationGroups.some((group) => group.count > 1),
    [conversationGroups]
  );
  const availableConversationGroupKeys = useMemo(
    () => conversationGroups.map((group) => group.key),
    [conversationGroups]
  );
  const sidebarConversationItems = useMemo<SidebarConversationItem[]>(() => {
    const renderedGroupKeys = new Set<string>();
    const baseItems = visibleConversations.flatMap((conversation): SidebarConversationItem[] => {
      const key = conversationGroupKey(conversation);
      const group = conversationGroupsByKey.get(key);
      if (group) {
        if (renderedGroupKeys.has(key)) return [];
        renderedGroupKeys.add(key);
        return [{ kind: "group", group }];
      }
      if (conversation.id === selectedId) return [];
      return [{ kind: "conversation", conversation }];
    });
    const orderIndex = new Map(
      conversationGroupOrder.map((groupKey, index) => [groupKey, index])
    );
    const orderedGroups = baseItems
      .filter((item): item is { kind: "group"; group: ConversationGroupSummary } =>
        item.kind === "group"
      )
      .map((item, baseIndex) => ({ item, baseIndex }))
      .sort((a, b) => {
        const aOrder = orderIndex.get(a.item.group.key);
        const bOrder = orderIndex.get(b.item.group.key);
        if (aOrder !== undefined && bOrder !== undefined) return aOrder - bOrder;
        if (aOrder !== undefined) return -1;
        if (bOrder !== undefined) return 1;
        return a.baseIndex - b.baseIndex;
      })
      .map(({ item }) => item);
    let nextGroupIndex = 0;
    return baseItems.map((item) =>
      item.kind === "group" ? orderedGroups[nextGroupIndex++] ?? item : item
    );
  }, [conversationGroupOrder, conversationGroupsByKey, selectedId, visibleConversations]);

  useEffect(() => {
    if (!user) {
      setConversationGroupOrder([]);
      return;
    }
    setConversationGroupOrder(loadConversationGroupOrder(user.id));
  }, [user]);

  useEffect(() => {
    if (!user) {
      setBotLibraryGroups([createFavoritesBotGroup()]);
      return;
    }
    if (typeof window === "undefined") return;
    try {
      const raw = window.localStorage.getItem(botLibraryGroupsStorageKey(user.id));
      const parsed: unknown = raw ? JSON.parse(raw) : [];
      setBotLibraryGroups(normalizeBotLibraryGroups(parsed));
    } catch {
      setBotLibraryGroups([createFavoritesBotGroup()]);
    }
  }, [user]);

  useEffect(() => {
    if (!user || typeof window === "undefined") return;
    try {
      window.localStorage.setItem(
        botLibraryGroupsStorageKey(user.id),
        JSON.stringify(botLibraryGroups)
      );
    } catch {
      // Non-fatal: groups still work for this page session.
    }
  }, [botLibraryGroups, user]);

  useEffect(() => {
    if (!user) {
      const defaults = normalizeCommandCenterState(null);
      setCommandCenterPreferredModel(defaults.preferredModel);
      setCommandCenterCommands(defaults.commands);
      setCommandCenterWildcardDecks(defaults.wildcardDecks);
      return;
    }
    if (typeof window === "undefined") return;
    try {
      const raw = window.localStorage.getItem(commandCenterStateStorageKey(user.id));
      const parsed: unknown = raw ? JSON.parse(raw) : null;
      const normalized = normalizeCommandCenterState(parsed);
      setCommandCenterPreferredModel(normalized.preferredModel);
      setCommandCenterCommands(normalized.commands);
      setCommandCenterWildcardDecks(normalized.wildcardDecks);
    } catch {
      const defaults = normalizeCommandCenterState(null);
      setCommandCenterPreferredModel(defaults.preferredModel);
      setCommandCenterCommands(defaults.commands);
      setCommandCenterWildcardDecks(defaults.wildcardDecks);
    }
  }, [user]);

  useEffect(() => {
    if (!user || typeof window === "undefined") return;
    const normalized = normalizeCommandCenterState({
      schema: "prism-command-center-v1",
      preferredModel: commandCenterPreferredModel,
      commands: commandCenterCommands,
      wildcardDecks: commandCenterWildcardDecks,
    });
    try {
      window.localStorage.setItem(
        commandCenterStateStorageKey(user.id),
        JSON.stringify({
          schema: "prism-command-center-v1",
          preferredModel: normalized.preferredModel,
          commands: normalized.commands,
          wildcardDecks: normalized.wildcardDecks,
        })
      );
    } catch {
      // Non-fatal: command center still works for this page session.
    }
  }, [commandCenterCommands, commandCenterPreferredModel, commandCenterWildcardDecks, user]);

  useEffect(() => {
    if (!commandCenterSelectedCommandId) return;
    const stillExists = commandCenterCommands.some(
      (command) => command.id === commandCenterSelectedCommandId
    );
    if (!stillExists) setCommandCenterSelectedCommandId(null);
  }, [commandCenterCommands, commandCenterSelectedCommandId]);

  useEffect(() => {
    if (!commandCenterSelectedWildcardDeckId) return;
    const stillExists = commandCenterWildcardDecks.some(
      (deck) => deck.id === commandCenterSelectedWildcardDeckId
    );
    if (!stillExists) setCommandCenterSelectedWildcardDeckId(null);
  }, [commandCenterWildcardDecks, commandCenterSelectedWildcardDeckId]);

  useEffect(() => {
    const selectedCommand =
      commandCenterCommands.find((command) => command.id === commandCenterSelectedCommandId) ??
      null;
    if (!selectedCommand || selectedCommand.builtIn || selectedCommand.readOnly) {
      setCommandCenterDraft(null);
      setCommandCenterSaveNotice(null);
      return;
    }
    setCommandCenterDraft({
      id: selectedCommand.id,
      name: selectedCommand.name,
      command: selectedCommand.command,
      colorTag: selectedCommand.colorTag,
      aliases: selectedCommand.aliases,
    });
    setCommandCenterSaveNotice(null);
  }, [commandCenterCommands, commandCenterSelectedCommandId]);

  useEffect(() => {
    const selectedDeck =
      commandCenterWildcardDecks.find((deck) => deck.id === commandCenterSelectedWildcardDeckId) ??
      null;
    if (!selectedDeck) {
      setCommandCenterWildcardDraft(null);
      return;
    }
    setCommandCenterWildcardDraft(wildcardDeckToDraft(selectedDeck));
    setCommandCenterSaveNotice(null);
  }, [commandCenterWildcardDecks, commandCenterSelectedWildcardDeckId]);

  useEffect(() => {
    if (!commandCenterSpecsCommandId) return;
    const stillExists = commandCenterCommands.some(
      (command) => command.id === commandCenterSpecsCommandId
    );
    if (!stillExists) setCommandCenterSpecsCommandId(null);
  }, [commandCenterCommands, commandCenterSpecsCommandId]);

  useEffect(() => {
    if (!commandCenterSpecsCommandId) return;
    const handleWindowKeyDown = (event: KeyboardEvent): void => {
      if (event.key === "Escape") {
        setCommandCenterSpecsCommandId(null);
      }
    };
    window.addEventListener("keydown", handleWindowKeyDown);
    return () => window.removeEventListener("keydown", handleWindowKeyDown);
  }, [commandCenterSpecsCommandId]);

  useEffect(() => {
    if (!commandCenterHelpModalOpen) return;
    const handleWindowKeyDown = (event: KeyboardEvent): void => {
      if (event.key === "Escape") {
        setCommandCenterHelpModalOpen(false);
      }
    };
    window.addEventListener("keydown", handleWindowKeyDown);
    return () => window.removeEventListener("keydown", handleWindowKeyDown);
  }, [commandCenterHelpModalOpen]);

  useEffect(() => {
    if (!expandedPromptShortcutMessageId || typeof document === "undefined") return;
    const handlePointerDown = (event: PointerEvent): void => {
      const target = event.target;
      if (
        target instanceof Element &&
        target.closest("[data-prompt-shortcut-preview='true']")
      ) {
        return;
      }
      setExpandedPromptShortcutMessageId(null);
    };
    const handleKeyDown = (event: KeyboardEvent): void => {
      if (event.key === "Escape") {
        setExpandedPromptShortcutMessageId(null);
      }
    };
    document.addEventListener("pointerdown", handlePointerDown, true);
    window.addEventListener("keydown", handleKeyDown);
    return () => {
      document.removeEventListener("pointerdown", handlePointerDown, true);
      window.removeEventListener("keydown", handleKeyDown);
    };
  }, [expandedPromptShortcutMessageId]);

  useEffect(() => {
    if (!user) return;
    setConversationGroupOrder((previous) => {
      const next = previous.filter((key) => conversationGroupsByKey.has(key));
      if (next.length === previous.length) return previous;
      persistConversationGroupOrder(user.id, next);
      return next;
    });
  }, [conversationGroupsByKey, user]);

  useEffect(() => {
    const existingBotIds = new Set(bots.map((bot) => bot.id));
    setBotLibraryGroups((current) =>
      normalizeBotLibraryGroups(
        current.map((group) => ({
          ...group,
          botIds: group.botIds.filter((botId) => existingBotIds.has(botId)),
          updatedAt: group.updatedAt,
        }))
      )
    );
  }, [bots]);

  useEffect(() => {
    if (
      expandedConversationGroupKey &&
      !conversationGroupsByKey.has(expandedConversationGroupKey)
    ) {
      setExpandedConversationGroupKey(null);
    }
  }, [conversationGroupsByKey, expandedConversationGroupKey]);

  const chatEphemeralMode = view === "chat";
  const effectiveChatPresentation = view === "chat";
  const chatLikeSurface = effectiveChatPresentation;
  const zenPersonaInkSegmentByMessageId = useMemo(
    () =>
      buildZenPersonaInkSegmentMap(detail?.messages ?? [], {
        trailingUserTarget:
          view === "chat"
            ? { botId: zenPersonaBot?.id ?? null, color: zenPersonaBot?.color ?? null }
            : null,
      }),
    [detail?.messages, view, zenPersonaBot?.color, zenPersonaBot?.id]
  );
  const chatMentionsEnabled = true;
  /** Autoscroll + dynamic type on Zen's chat-like surface. */
  const assistantRevealActive = chatEphemeralMode;
  /**
   * Word-at-a-time / token-scheduled reveals, fenced-code progressive unveil,
   * and the tap-to-interrupt typing pill — Zen chat mode only.
   */
  const chatAssistantTypingMechanicsActive = chatEphemeralMode;
  const chatComposerChromePinned =
    composerFocused ||
    draft.trim().length > 0 ||
    editingMessageId !== null ||
    composerCleanupBusy ||
    mobileKeyboardInset > 0;
  const chatHeaderChromePinned = chatOverflowMenuOpen;

  const setChatHeaderChromeVisibleState = useCallback((visible: boolean) => {
    if (chatHeaderChromeVisibleRef.current === visible) return;
    chatHeaderChromeVisibleRef.current = visible;
    setChatHeaderChromeVisible(visible);
  }, []);

  const setChatComposerChromeVisibleState = useCallback((visible: boolean) => {
    if (chatComposerChromeVisibleRef.current === visible) return;
    chatComposerChromeVisibleRef.current = visible;
    setChatComposerChromeVisible(visible);
  }, []);

  const revealChatHeaderChrome = useCallback(() => {
    setChatHeaderChromeVisibleState(true);
  }, [setChatHeaderChromeVisibleState]);

  const revealChatComposerChrome = useCallback(() => {
    setChatComposerChromeVisibleState(true);
  }, [setChatComposerChromeVisibleState]);

  const hideChatChromeAfterThreadScroll = useCallback(() => {
    if (!effectiveChatPresentation) return;
    chatChromeAutoHiddenRef.current = true;
    if (!chatHeaderChromePinned) {
      setChatHeaderChromeVisibleState(false);
    }
    if (!chatComposerChromePinned) {
      setChatComposerChromeVisibleState(false);
    }
  }, [
    chatComposerChromePinned,
    chatHeaderChromePinned,
    effectiveChatPresentation,
    setChatComposerChromeVisibleState,
    setChatHeaderChromeVisibleState,
  ]);

  useEffect(() => {
    if (!effectiveChatPresentation) {
      chatChromeAutoHiddenRef.current = false;
      setChatHeaderChromeVisibleState(true);
      setChatComposerChromeVisibleState(true);
      return;
    }
    if (chatHeaderChromePinned) {
      setChatHeaderChromeVisibleState(true);
    }
    if (chatComposerChromePinned) {
      setChatComposerChromeVisibleState(true);
    }
  }, [
    chatComposerChromePinned,
    chatHeaderChromePinned,
    effectiveChatPresentation,
    setChatComposerChromeVisibleState,
    setChatHeaderChromeVisibleState,
  ]);

  useEffect(() => {
    if (!effectiveChatPresentation) return;
    chatChromeAutoHiddenRef.current = false;
    setChatHeaderChromeVisibleState(true);
    setChatComposerChromeVisibleState(true);
  }, [
    detail?.id,
    effectiveChatPresentation,
    setChatComposerChromeVisibleState,
    setChatHeaderChromeVisibleState,
  ]);

  useEffect(() => {
    if (!effectiveChatPresentation) return;

    const handlePointerMove = (event: PointerEvent): void => {
      if (event.pointerType && event.pointerType !== "mouse") return;
      const viewportHeight =
        window.innerHeight || document.documentElement.clientHeight;
      if (viewportHeight <= 0) return;

      const headerInRevealZone =
        event.clientY <= viewportHeight * CHAT_MODE_HEADER_REVEAL_RATIO;
      const composerInRevealZone =
        event.clientY >= viewportHeight * (1 - CHAT_MODE_COMPOSER_REVEAL_RATIO);

      if (!chatChromeAutoHiddenRef.current) {
        if (headerInRevealZone) {
          setChatHeaderChromeVisibleState(true);
        }
        if (composerInRevealZone || chatComposerChromePinned) {
          setChatComposerChromeVisibleState(true);
        }
        return;
      }

      const headerVisible =
        chatHeaderChromePinned ||
        headerInRevealZone;
      const composerVisible =
        chatComposerChromePinned ||
        composerInRevealZone;

      setChatHeaderChromeVisibleState(headerVisible);
      setChatComposerChromeVisibleState(composerVisible);
    };

    const handleViewportLeave = (event: MouseEvent): void => {
      if (event.relatedTarget !== null) return;
      if (!chatChromeAutoHiddenRef.current) return;
      if (!chatHeaderChromePinned) {
        setChatHeaderChromeVisibleState(false);
      }
      if (!chatComposerChromePinned) {
        setChatComposerChromeVisibleState(false);
      }
    };

    window.addEventListener("pointermove", handlePointerMove, { passive: true });
    document.documentElement.addEventListener("mouseleave", handleViewportLeave);
    return () => {
      window.removeEventListener("pointermove", handlePointerMove);
      document.documentElement.removeEventListener("mouseleave", handleViewportLeave);
    };
  }, [
    chatComposerChromePinned,
    chatHeaderChromePinned,
    effectiveChatPresentation,
    setChatComposerChromeVisibleState,
    setChatHeaderChromeVisibleState,
  ]);

  const showPrivateConversationEmptyState =
    privateChatActive && visibleConversations.length === 0;
  const pendingReplyVisible =
    pendingReply &&
    (
      (pendingReplyConversationId !== null && detail?.id === pendingReplyConversationId) ||
      (pendingReplyIsNewConversation && detail?.id === "pending")
    );
  /** Wordmark header only (Chat / Sandbox pre-thread): surface full bot grid when picker is narrowed or a bot is armed. */
  const showHeaderShowAllBotsLink = useMemo(() => {
    if (bots.length === 0 || pendingReplyVisible || detail) return false;
    return (
      selectedBotId !== null ||
      composerPrimed ||
      hueFilterCenter !== null
    );
  }, [
    bots.length,
    pendingReplyVisible,
    detail,
    selectedBotId,
    composerPrimed,
    hueFilterCenter,
  ]);
  const hasLenientFallbackConfigured =
    typeof settings?.lenientLocalFallbackModel === "string" &&
    settings.lenientLocalFallbackModel.trim().length > 0;
  const configuredFallbackModelId = settings?.lenientLocalFallbackModel?.trim() ?? "";
  useEffect(() => {
    if (!pendingReply) return;
    setPendingReplyNowMs(Date.now());
    const timer = window.setInterval(() => {
      setPendingReplyNowMs(Date.now());
    }, FALLBACK_PROCESSING_TICK_MS);
    return () => {
      window.clearInterval(timer);
    };
  }, [pendingReply]);
  const pendingReplyLikelyFallbackProcessing =
    pendingReplyVisible &&
    hasLenientFallbackConfigured &&
    pendingReplyDenialRisk &&
    pendingReplyStartedAtMs !== null &&
    (
      view === "chat" ||
      pendingReplyNowMs - pendingReplyStartedAtMs >= FALLBACK_PROCESSING_HINT_DELAY_MS
    );
  const stopPendingReply = useCallback((): void => {
    const activeController = pendingReplyAbortControllerRef.current;
    if (activeController) {
      activeController.abort();
      pendingReplyAbortControllerRef.current = null;
    }
    setPendingReply(false);
    setPendingReplyStartedAtMs(null);
    setPendingReplyDenialRisk(false);
    setPendingReplyConversationId(null);
    setPendingReplyIsNewConversation(false);
    if (chatEphemeralMode && detail?.id) {
      chatArchiveRevealByConversationRef.current.set(detail.id, false);
      chatArchiveLoadingByConversationRef.current.set(detail.id, false);
      chatArchiveAnchorMessageByConversationRef.current.delete(detail.id);
      chatArchivePullPxByConversationRef.current.set(detail.id, 0);
      chatArchiveParagraphQuotaByConversationRef.current.set(detail.id, 0);
      const loadingTimer = chatArchiveLoadTimerByConversationRef.current.get(detail.id);
      if (loadingTimer !== undefined) {
        window.clearTimeout(loadingTimer);
        chatArchiveLoadTimerByConversationRef.current.delete(detail.id);
      }
      setChatArchiveRevealEpoch((value) => value + 1);
    } else {
      // Non-ephemeral surfaces: aborting a send leaves the optimistic `pending-*`
      // user row in memory — strip it so Resend / Edit never POST /rewind with a
      // client-only id (server throws "Message not found in conversation.").
      setDetail((current) => {
        if (!current) return current;
        const msgs = current.messages;
        if (msgs.length === 0) return current;
        const last = msgs[msgs.length - 1];
        if (last.role === "user" && String(last.id).startsWith("pending-")) {
          return { ...current, messages: msgs.slice(0, -1) };
        }
        return current;
      });
    }
    setError(null);
  }, [chatEphemeralMode, detail?.id]);

  const clearPendingReplyState = useCallback((): void => {
    setPendingReply(false);
    setPendingReplyStartedAtMs(null);
    setPendingReplyDenialRisk(false);
    setPendingReplyConversationId(null);
    setPendingReplyIsNewConversation(false);
  }, []);

  const clearZenInitialStarterSurface = useCallback((): void => {
    setChatAutoRestoreSuppressed(true);
    setSelectedId(null);
    setDetail(null);
    setSessionOpinion(null);
    setBotOpinion(null);
    setDraft("");
    setComposerSendTintActive(false);
    setComposerPrimed(false);
    setStarterComposerRevealed(false);
    setAskQuestionComposerRevealed(false);
    setZenInitialStarterOverlayActive(false);
    setConversationStarterPrompts(null);
    setChatStartupSummary(null);
    setPendingZenSessionBreak(null);
    setPendingZenSessionResumeContext(null);
    zenInitialStarterLiveEnvelopeRef.current = null;
    chatSummaryRefreshMarkerRef.current = null;
    setError(null);
  }, []);

  const handleZenInitialThinkingCancel = useCallback(
    (event?: React.MouseEvent<HTMLButtonElement>): void => {
      event?.preventDefault();
      event?.stopPropagation();
      const starterRequest = zenInitialStarterRequestRef.current;
      const activeController = pendingReplyAbortControllerRef.current;
      if (starterRequest && activeController === starterRequest.controller) {
        starterRequest.cancelled = true;
        pendingReplyAbortControllerRef.current = null;
        clearPendingReplyState();
      } else {
        zenInitialThinkingCancelControllerRef.current = activeController;
        stopPendingReply();
      }
      clearZenInitialStarterSurface();
    },
    [clearPendingReplyState, clearZenInitialStarterSurface, stopPendingReply]
  );
  const resolveCommittedChatFontLineCount = useCallback(
    (temporalKey: string | null, lineCount: number): number => {
      if (!temporalKey) return lineCount;
      const committedLineCount = chatCommittedFontLineCountByKeyRef.current.get(temporalKey);
      return Math.max(lineCount, committedLineCount ?? 0);
    },
    []
  );
  function resolveAssistantRevealVisibleTokenCount({
    revealKey,
    displayContent,
    nowMs,
    completed,
    cancelledTokenCount,
    moodKey,
  }: {
    revealKey: string;
    displayContent: string;
    nowMs: number;
    completed: boolean;
    cancelledTokenCount?: number;
    moodKey: NonNullable<Message["moodKey"]>;
  }): number {
    const revealTokens = tokenizeMessageReveal(displayContent);
    const tokenTotal = Math.max(1, revealTokens.length);
    if (completed) {
      chatRevealPaceByKeyRef.current.delete(revealKey);
      return tokenTotal;
    }
    if (typeof cancelledTokenCount === "number") {
      chatRevealPaceByKeyRef.current.delete(revealKey);
      return Math.min(tokenTotal, Math.max(1, cancelledTokenCount));
    }
    return resolvePacedChatRevealVisibleTokenCount({
      revealKey,
      tokenCount: tokenTotal,
      tokenSignature: displayContent,
      nowMs,
      stateByRevealKey: chatRevealPaceByKeyRef.current,
      resolveStepDelayMs: (previousTokenIndex) =>
        resolveRevealStepDelayMs(
          revealTokens[previousTokenIndex] ?? "",
          moodKey,
          effectiveChatRevealTiming
        ),
    });
  }
  useEffect(() => {
    return () => {
      for (const timer of chatInterruptedSettleTimerByKeyRef.current.values()) {
        window.clearTimeout(timer);
      }
      chatInterruptedSettleTimerByKeyRef.current.clear();
    };
  }, []);

  function pulseChatInterruptionSettle(revealKey: string): void {
    const existingTimer = chatInterruptedSettleTimerByKeyRef.current.get(revealKey);
    if (existingTimer !== undefined) {
      window.clearTimeout(existingTimer);
    }
    setChatInterruptedSettleKeys((current) => {
      if (current.has(revealKey)) return current;
      const next = new Set(current);
      next.add(revealKey);
      return next;
    });
    const timer = window.setTimeout(() => {
      chatInterruptedSettleTimerByKeyRef.current.delete(revealKey);
      setChatInterruptedSettleKeys((current) => {
        if (!current.has(revealKey)) return current;
        const next = new Set(current);
        next.delete(revealKey);
        return next;
      });
    }, CHAT_MODE_INTERRUPTION_SETTLE_MS);
    chatInterruptedSettleTimerByKeyRef.current.set(revealKey, timer);
  }

  const assistantWordByWordMode = chatAssistantTypingMechanicsActive;
  const chatMessageTemporalById = useMemo(() => {
    const temporal = new Map<string, { phase: ChatMessageTemporalPhase; ageMs: number }>();
    const source = detail?.messages ?? [];
    if (!chatEphemeralMode || !detail?.id) {
      for (const message of source) {
        temporal.set(message.id, { phase: "visible", ageMs: 0 });
      }
      return temporal;
    }
    const firstSeen = chatMessageFirstSeenAtRef.current;
    const offscreenSinceById = chatMessageOffscreenSinceRef.current;
    const now = chatEphemeralNowMs;
    const scrollRoot = messagesScrollRef.current;
    const viewportRect = scrollRoot?.getBoundingClientRect() ?? null;
    let expiredForConversation = chatExpiredMessageIdsByConversationRef.current.get(detail.id);
    if (!expiredForConversation) {
      expiredForConversation = new Set<string>();
      chatExpiredMessageIdsByConversationRef.current.set(detail.id, expiredForConversation);
    }
    const revealArchived =
      chatArchiveRevealByConversationRef.current.get(detail.id) === true;
    const latestUserIndex = (() => {
      for (let i = source.length - 1; i >= 0; i -= 1) {
        if (source[i]?.role === "user") return i;
      }
      return -1;
    })();
    const effectiveSource =
      !revealArchived && latestUserIndex > 0
        ? source.slice(latestUserIndex)
        : source;
    const latestAssistantId = (() => {
      for (let i = effectiveSource.length - 1; i >= 0; i -= 1) {
        if (effectiveSource[i]?.role === "assistant") return effectiveSource[i]!.id;
      }
      return null;
    })();
    for (const message of effectiveSource) {
      if (expiredForConversation.has(message.id) && !revealArchived) {
        continue;
      }
      const temporalKey = `${detail.id}:${message.id}`;
      let firstSeenAt = firstSeen.get(temporalKey);
      if (firstSeenAt === undefined) {
        firstSeenAt = now;
        firstSeen.set(temporalKey, firstSeenAt);
      }
      const messageViewportMeta = (() => {
        if (!scrollRoot || !viewportRect) return false;
        const row = findMessageRowById(scrollRoot, message.id);
        if (!row) return false;
        const rect = row.getBoundingClientRect();
        return {
          isOnScreen: rect.bottom > viewportRect.top && rect.top < viewportRect.bottom,
          top: rect.top,
          bottom: rect.bottom,
        };
      })();
      const messageIsOnScreen =
        messageViewportMeta !== false && messageViewportMeta.isOnScreen;
      const lineCount = countEphemeralLines(resolveMessageVisualSizingContent(message));
      const dissolveDurationMs =
        CHAT_MODE_OFFSCREEN_DISSOLVE_MS +
        Math.max(0, lineCount - 1) * CHAT_MODE_LINE_DISSOLVE_STAGGER_MS;
      let offscreenAgeMs = 0;
      if (messageIsOnScreen) {
        offscreenSinceById.delete(message.id);
      } else {
        let offscreenSince = offscreenSinceById.get(message.id);
        if (offscreenSince === undefined) {
          offscreenSince = now;
          offscreenSinceById.set(message.id, offscreenSince);
        }
        offscreenAgeMs = Math.max(0, now - offscreenSince);
      }
      if (!messageIsOnScreen && offscreenAgeMs >= CHAT_MODE_OFFSCREEN_VISIBLE_MS + dissolveDurationMs) {
        expiredForConversation.add(message.id);
        if (!revealArchived) continue;
      }
      const revealGatedAssistant =
        message.role === "assistant" &&
        message.id === latestAssistantId &&
        chatAssistantRevealEligibleKeysRef.current.has(temporalKey) &&
        !chatCompletedRevealKeysRef.current.has(temporalKey) &&
        !chatCancelledRevealTokenCountByKeyRef.current.has(temporalKey);
      const estimatedRevealDoneAt = revealGatedAssistant
        ? firstSeenAt +
          resolveRevealDurationMsForTokens(
            tokenizeMessageReveal(resolveMessageDisplayContent(message)),
            resolveMessageMoodKey(message),
            effectiveChatRevealTiming
          )
        : firstSeenAt;
      const revealReadyAt = revealGatedAssistant ? estimatedRevealDoneAt : firstSeenAt;
      const effectiveStartAt =
        revealGatedAssistant && now < revealReadyAt
          ? now
          : revealReadyAt;
      const ageMs = Math.max(0, now - effectiveStartAt);
      const phase: ChatMessageTemporalPhase =
        messageIsOnScreen
          ? (
            revealGatedAssistant
              ? "visible"
              : ageMs < CHAT_MODE_MESSAGE_MANIFEST_MS
                ? "manifest"
                : "visible"
          )
          : offscreenAgeMs >= CHAT_MODE_OFFSCREEN_VISIBLE_MS
            ? "dissolving"
            : "visible";
      temporal.set(message.id, { phase, ageMs: messageIsOnScreen ? ageMs : offscreenAgeMs });
    }
    return temporal;
  }, [
    chatEphemeralMode,
    chatEphemeralNowMs,
    detail?.id,
    detail?.messages,
    effectiveChatRevealTiming,
    chatArchiveRevealEpoch,
  ]);
  const chatArchiveLoadingActive =
    Boolean(chatEphemeralMode && detail?.id) &&
    (detail?.id ? chatArchiveLoadingByConversationRef.current.get(detail.id) === true : false);
  const visibleDetailMessages = useMemo(() => {
    const source = detail?.messages ?? [];
    if (!chatEphemeralMode) return source;
    return source;
  }, [chatEphemeralMode, detail?.messages]);
  const promptShortcutColorIndexByMessageId = useMemo(() => {
    const colorIndexes = new Map<string, number>();
    let promptShortcutIndex = 0;
    for (const message of visibleDetailMessages) {
      if (!message.promptShortcut && !message.promptWildcards) continue;
      colorIndexes.set(message.id, promptShortcutIndex);
      promptShortcutIndex += 1;
    }
    return colorIndexes;
  }, [visibleDetailMessages]);
  const zenUserMessagePrismColorById = useMemo(() => {
    const colors = new Map<string, (typeof ZEN_USER_MESSAGE_PRISM_PALETTE)[number]>();
    if (view !== "chat" || !detail) return colors;
    let userMessageIndex = 0;
    for (const message of detail.messages) {
      if (message.role !== "user") continue;
      const personaInkSegment = zenPersonaInkSegmentByMessageId.get(message.id);
      if (personaInkSegment?.variant !== "default") continue;
      colors.set(
        message.id,
        ZEN_USER_MESSAGE_PRISM_PALETTE[
          userMessageIndex % ZEN_USER_MESSAGE_PRISM_PALETTE.length
        ]!
      );
      userMessageIndex += 1;
    }
    return colors;
  }, [view, detail?.messages, zenPersonaInkSegmentByMessageId]);
  const zenEraBoundaryLabelByMessageId = useMemo(() => {
    const labels = new Map<string, string>();
    if (view !== "chat" || detail?.mode !== "zen") return labels;
    const source = detail.messages;
    for (let i = 1; i < source.length; i += 1) {
      const previousMs = messageCreatedAtMs(source[i - 1]!);
      const current = source[i]!;
      const currentMs = messageCreatedAtMs(current);
      if (previousMs === null || currentMs === null) continue;
      if (currentMs - previousMs < zenSessionIdleGapMs) continue;
      labels.set(current.id, formatZenEraBoundaryLabel(current));
    }
    return labels;
  }, [view, detail?.mode, detail?.messages, zenSessionIdleGapMs]);
  const zenLatestIdleEraBoundaryMessageCount = useMemo(() => {
    if (view !== "chat" || detail?.mode !== "zen") return null;
    const source = detail.messages;
    for (let i = source.length - 1; i > 0; i -= 1) {
      const current = source[i]!;
      if (current.role !== "user") continue;
      const previousMs = messageCreatedAtMs(source[i - 1]!);
      const currentMs = messageCreatedAtMs(current);
      if (previousMs === null || currentMs === null) continue;
      if (currentMs - previousMs >= zenSessionIdleGapMs) return i + 1;
    }
    return null;
  }, [view, detail?.mode, detail?.messages, zenSessionIdleGapMs]);
  const chatStartupSummaryIsDefault =
    chatStartupSummary === DEFAULT_CHAT_STARTUP_SUMMARY;
  const chatStartupSummaryVisible = Boolean(
    chatStartupSummary &&
    !chatStartupSummaryIsDefault &&
    !pendingReplyVisible &&
    (!detail || visibleDetailMessages.length === 0)
  );
  const activeZenConversationId =
    view === "chat"
      ? detail?.id && detail.id !== "pending"
        ? detail.id
        : selectedId
      : null;
  const summaryDebugMatchesActiveZen =
    activeZenConversationId !== null &&
    summaryDebug?.conversationId === activeZenConversationId &&
    (summaryDebug.mode === "zen" || summaryDebug.mode === "chat");
  const currentZenInternalSummary =
    summaryDebugMatchesActiveZen ? summaryDebug.latestSummary?.trim() || null : null;
  const currentZenDisplaySummary =
    summaryDebugMatchesActiveZen
      ? summaryDebug.latestDisplaySummary?.trim() ||
        summaryDebug.latestSummary?.trim() ||
        null
      : !chatStartupSummaryIsDefault
        ? chatStartupSummary?.trim() || null
        : null;
  const activeZenSessionBreak = useMemo(() => {
    if (
      view !== "chat" ||
      detail?.mode !== "zen" ||
      !detail.id ||
      detail.id === "pending" ||
      !zenSessionBreak ||
      zenSessionBreak.conversationId !== detail.id
    ) {
      return null;
    }
    return zenSessionBreak;
  }, [detail?.id, detail?.mode, view, zenSessionBreak]);
  const zenSessionBreakAnchorIndex = useMemo(() => {
    if (!activeZenSessionBreak) return null;
    if (visibleDetailMessages.length === 0) return -1;
    if (activeZenSessionBreak.anchorMessageId) {
      const byId = visibleDetailMessages.findIndex(
        (message) => message.id === activeZenSessionBreak.anchorMessageId
      );
      if (byId >= 0) return byId;
    }
    if (activeZenSessionBreak.anchorMessageCount <= 0) return -1;
    return Math.min(
      activeZenSessionBreak.anchorMessageCount - 1,
      visibleDetailMessages.length - 1
    );
  }, [activeZenSessionBreak, visibleDetailMessages]);
  const renderZenSessionBreakNode = useCallback((sessionBreak: ZenSessionBreakState) => {
    const effectiveGapMs = effectiveZenSessionBreakGapMs(sessionBreak);
    const awayLabel = formatZenSessionAwayLabel(
      effectiveGapMs,
      sessionBreak.previousActiveAt
    );
    return (
      <div
        className={styles.zenSessionBreak}
        data-source={sessionBreak.source}
        role="note"
      >
        <div className={styles.zenSessionBreakRule}>
          <span>{awayLabel}</span>
        </div>
        <div
          className={styles.zenSessionBreakScrollAnchor}
          data-zen-session-break-anchor="true"
          aria-hidden="true"
        />
      </div>
    );
  }, []);
  const zenSessionBreakNode = useMemo(() => {
    if (!activeZenSessionBreak) return null;
    return renderZenSessionBreakNode(activeZenSessionBreak);
  }, [activeZenSessionBreak, renderZenSessionBreakNode]);
  const pendingZenSessionBreakNode = useMemo(() => {
    if (!pendingZenSessionBreak || detail?.id !== "pending") return null;
    return renderZenSessionBreakNode(pendingZenSessionBreak);
  }, [detail?.id, pendingZenSessionBreak, renderZenSessionBreakNode]);
  useLayoutEffect(() => {
    if (!activeZenSessionBreak) {
      zenSessionBreakAutoScrollKeyRef.current = null;
      return;
    }
    const key = `${activeZenSessionBreak.conversationId}:${activeZenSessionBreak.createdAt}`;
    if (zenSessionBreakAutoScrollKeyRef.current === key) return;
    zenSessionBreakAutoScrollKeyRef.current = key;
    requestAnimationFrame(() => {
      const scrollRoot = messagesScrollRef.current;
      const target = scrollRoot?.querySelector<HTMLElement>(
        "[data-zen-session-break-anchor='true']"
      );
      if (!scrollRoot || !target) return;
      const rootRect = scrollRoot.getBoundingClientRect();
      const targetRect = target.getBoundingClientRect();
      const targetInsetPx = Math.max(54, Math.min(86, scrollRoot.clientHeight * 0.1));
      const targetTop =
        scrollRoot.scrollTop +
        (targetRect.top - rootRect.top) -
        targetInsetPx;
      const maxScrollTop = Math.max(0, scrollRoot.scrollHeight - scrollRoot.clientHeight);
      const nextTop = Math.max(0, Math.min(maxScrollTop, targetTop));
      chatProgrammaticScrollUntilMsRef.current = Date.now() + 180;
      scrollRoot.scrollTo({ top: nextTop, behavior: "auto" });
      chatLastScrollTopByConversationRef.current.set(
        activeZenSessionBreak.conversationId,
        scrollRoot.scrollTop
      );
      chatLastScrollHeightByConversationRef.current.set(
        activeZenSessionBreak.conversationId,
        scrollRoot.scrollHeight
      );
    });
  }, [activeZenSessionBreak]);
  const latestAssistantMessageId = useMemo<string | null>(() => {
    const source = detail?.messages ?? [];
    for (let i = source.length - 1; i >= 0; i -= 1) {
      if (source[i]?.role === "assistant") return source[i]!.id;
    }
    return null;
  }, [detail?.messages]);
  const markLatestAssistantRevealEligible = useCallback(
    (conversation: ConversationDetail): void => {
      if (!chatAssistantTypingMechanicsActive || !conversation.id) return;
      const latestAssistant = (() => {
        for (let i = conversation.messages.length - 1; i >= 0; i -= 1) {
          if (conversation.messages[i]?.role === "assistant") return conversation.messages[i]!;
        }
        return null;
      })();
      if (!latestAssistant) return;
      const revealKey = `${conversation.id}:${latestAssistant.id}`;
      chatAssistantRevealEligibleKeysRef.current.add(revealKey);
      chatCompletedRevealKeysRef.current.delete(revealKey);
      chatCancelledRevealTokenCountByKeyRef.current.delete(revealKey);
      chatRevealPaceByKeyRef.current.delete(revealKey);
      chatMessageFirstSeenAtRef.current.set(revealKey, Date.now());
    },
    [chatAssistantTypingMechanicsActive]
  );
  const latestUserMessageId = useMemo<string | null>(() => {
    const source = detail?.messages ?? [];
    for (let i = source.length - 1; i >= 0; i -= 1) {
      if (source[i]?.role === "user") return source[i]!.id;
    }
    return null;
  }, [detail?.messages]);
  const latestUserMessageIndex = useMemo<number>(() => {
    const source = detail?.messages ?? [];
    for (let i = source.length - 1; i >= 0; i -= 1) {
      if (source[i]?.role === "user") return i;
    }
    return -1;
  }, [detail?.messages]);
  const latestUserMessageAsQuestion = useMemo(() => {
    if (!detail?.messages || !latestUserMessageId) return false;
    const latestUserMessage = detail.messages.find((message) => message.id === latestUserMessageId);
    if (!latestUserMessage || latestUserMessage.role !== "user") return false;
    return isQuestionLikeChatTurn(resolveMessageDisplayContent(latestUserMessage));
  }, [detail?.messages, latestUserMessageId]);
  const shouldFadeInLatestUserMessage = (message: Message): boolean => {
    if (!chatEphemeralMode || !detail?.id) return false;
    if (message.role !== "user" || message.id !== latestUserMessageId) return false;
    const fadeKey = `${detail.id}:${message.id}`;
    const fadeStartAt = chatUserMessageFadeStartByKeyRef.current.get(fadeKey);
    // Restored Zen messages should never inherit the entrance fade. Without
    // a seeded timestamp, the latest user row can remain visually dimmed.
    if (fadeStartAt === undefined) return false;
    return Math.max(0, chatEphemeralNowMs - fadeStartAt) < CHAT_MODE_USER_MESSAGE_FADE_MS;
  };
  const latestMessageRole =
    detail && detail.messages.length > 0
      ? detail.messages[detail.messages.length - 1]?.role
      : null;
  const activeChatExchangeDynamicType = useMemo(() => {
    if (!assistantRevealActive || !detail?.id || latestUserMessageIndex < 0) {
      return null;
    }

    const activeMessages = detail.messages.slice(latestUserMessageIndex);
    if (activeMessages.length === 0) return null;

    let visualLineCount = 0;
    for (const message of activeMessages) {
      const displayContent = resolveMessageVisualSizingContent(message);
      const sizingContent =
        chatAssistantTypingMechanicsActive &&
        message.role === "assistant" &&
        message.id === latestAssistantMessageId
          ? (() => {
              const revealKey = `${detail.id}:${message.id}`;
              const revealTokens = tokenizeMessageReveal(displayContent);
              const tokenTotal = Math.max(1, revealTokens.length);
              const cancelledTokenCount =
                chatCancelledRevealTokenCountByKeyRef.current.get(revealKey);
              const revealCompleted =
                chatCompletedRevealKeysRef.current.has(revealKey);
              if (typeof cancelledTokenCount === "number") {
                return revealTokens
                  .slice(0, Math.min(tokenTotal, Math.max(1, cancelledTokenCount)))
                  .join("");
              }
              if (revealCompleted) return displayContent;

              const firstSeenAt =
                chatMessageFirstSeenAtRef.current.get(revealKey) ?? chatEphemeralNowMs;
              const elapsedMs = Math.max(0, chatEphemeralNowMs - firstSeenAt);
              const visibleTokenCount = Math.min(
                tokenTotal,
                resolveVisibleTokenCountAtElapsedMs(
                  revealTokens,
                  elapsedMs,
                  resolveMessageMoodKey(message),
                  effectiveChatRevealTiming
                )
              );
              return revealTokens.slice(0, visibleTokenCount).join("");
            })()
          : displayContent;
      visualLineCount += estimateVisualLineCount(sizingContent);
    }

    return {
      fontSizePx: resolveChatModeMessageFontSizePx(visualLineCount),
      messageIds: new Set(activeMessages.map((message) => message.id)),
    };
  }, [
    assistantRevealActive,
    chatAssistantTypingMechanicsActive,
    chatEphemeralNowMs,
    detail?.id,
    detail?.messages,
    effectiveChatRevealTiming,
    latestAssistantMessageId,
    latestUserMessageIndex,
  ]);
  const setChatArchiveRevealForConversation = useCallback(
    (conversationId: string, reveal: boolean): void => {
      const current =
        chatArchiveRevealByConversationRef.current.get(conversationId) === true;
      if (current === reveal) return;
      chatArchiveRevealByConversationRef.current.set(conversationId, reveal);
      if (!reveal) {
        chatArchiveAnchorMessageByConversationRef.current.delete(conversationId);
      }
      setChatArchiveRevealEpoch((value) => value + 1);
    },
    []
  );
  const setChatArchiveLoadingForConversation = useCallback(
    (conversationId: string, loading: boolean): void => {
      const current = chatArchiveLoadingByConversationRef.current.get(conversationId) === true;
      if (current === loading) return;
      chatArchiveLoadingByConversationRef.current.set(conversationId, loading);
      setChatArchiveRevealEpoch((value) => value + 1);
    },
    []
  );
  const startChatArchiveLoadForConversation = useCallback(
    (conversationId: string, anchorMessageId?: string | null): void => {
      if (chatArchiveRevealByConversationRef.current.get(conversationId) === true) return;
      if (chatArchiveLoadingByConversationRef.current.get(conversationId) === true) return;
      chatArchiveAnchorMessageByConversationRef.current.set(conversationId, anchorMessageId ?? null);
      setChatArchiveLoadingForConversation(conversationId, true);
      const existing = chatArchiveLoadTimerByConversationRef.current.get(conversationId);
      if (existing !== undefined) {
        window.clearTimeout(existing);
      }
      const timer = window.setTimeout(() => {
        chatArchiveLoadTimerByConversationRef.current.delete(conversationId);
        const scrollRoot = messagesScrollRef.current;
        const anchorBeforeTop =
          scrollRoot && anchorMessageId
            ? findMessageRowById(scrollRoot, anchorMessageId)?.offsetTop ?? null
            : null;
        setChatArchiveLoadingForConversation(conversationId, false);
        setChatArchiveRevealForConversation(conversationId, true);
        if (scrollRoot && anchorMessageId && anchorBeforeTop !== null) {
          requestAnimationFrame(() => {
            const anchorAfter = findMessageRowById(scrollRoot, anchorMessageId);
            if (!anchorAfter) return;
            const delta = anchorAfter.offsetTop - anchorBeforeTop;
            if (Math.abs(delta) < 1) return;
            chatProgrammaticScrollUntilMsRef.current = Date.now() + 120;
            scrollRoot.scrollTop += delta;
            chatLastScrollTopByConversationRef.current.set(conversationId, scrollRoot.scrollTop);
            chatLastScrollHeightByConversationRef.current.set(conversationId, scrollRoot.scrollHeight);
          });
        }
      }, CHAT_MODE_ARCHIVE_LOAD_DELAY_MS);
      chatArchiveLoadTimerByConversationRef.current.set(conversationId, timer);
    },
    [setChatArchiveLoadingForConversation, setChatArchiveRevealForConversation]
  );
  const hardResetChatArchiveStateForConversation = useCallback(
    (conversationId: string): void => {
      setChatArchiveRevealForConversation(conversationId, false);
      setChatArchiveLoadingForConversation(conversationId, false);
      const loadingTimer = chatArchiveLoadTimerByConversationRef.current.get(conversationId);
      if (loadingTimer !== undefined) {
        window.clearTimeout(loadingTimer);
        chatArchiveLoadTimerByConversationRef.current.delete(conversationId);
      }
      chatArchiveAnchorMessageByConversationRef.current.delete(conversationId);
      chatArchivePullPxByConversationRef.current.set(conversationId, 0);
      chatArchiveParagraphQuotaByConversationRef.current.set(conversationId, 0);
      chatArchiveInertiaVelocityByConversationRef.current.set(conversationId, 0);
      const activeFrame = chatArchiveInertiaFrameByConversationRef.current.get(conversationId);
      if (activeFrame !== undefined) {
        window.cancelAnimationFrame(activeFrame);
        chatArchiveInertiaFrameByConversationRef.current.delete(conversationId);
      }
      chatLastScrollTopByConversationRef.current.delete(conversationId);
      chatLastScrollHeightByConversationRef.current.delete(conversationId);
      chatAutoscrollArmedByConversationRef.current.set(conversationId, false);
      chatAutoscrollUserDisarmedByConversationRef.current.delete(conversationId);
    },
    [setChatArchiveLoadingForConversation, setChatArchiveRevealForConversation]
  );
  const latestDetailMessageId =
    detail && detail.messages.length > 0
      ? detail.messages[detail.messages.length - 1]?.id ?? null
      : null;
  const chatAssistantRevealInProgress = useMemo(() => {
    if (!chatAssistantTypingMechanicsActive || !detail?.id || !latestAssistantMessageId) return false;
    const revealKey = `${detail.id}:${latestAssistantMessageId}`;
    if (!chatAssistantRevealEligibleKeysRef.current.has(revealKey)) return false;
    if (chatCancelledRevealTokenCountByKeyRef.current.has(revealKey)) return false;
    if (chatCompletedRevealKeysRef.current.has(revealKey)) return false;
    let firstSeenAt = chatMessageFirstSeenAtRef.current.get(revealKey);
    if (firstSeenAt === undefined) {
      firstSeenAt = chatEphemeralNowMs;
      chatMessageFirstSeenAtRef.current.set(revealKey, firstSeenAt);
    }
    const latestAssistantMessage =
      detail.messages.find((message) => message.id === latestAssistantMessageId) ?? null;
    if (!latestAssistantMessage) return false;
    const revealTokens = tokenizeMessageReveal(resolveMessageDisplayContent(latestAssistantMessage));
    const tokenTotal = Math.max(1, revealTokens.length);
    const pacedVisibleTokenCount =
      chatRevealPaceByKeyRef.current.get(revealKey)?.visibleTokenCount;
    if (
      typeof pacedVisibleTokenCount === "number" &&
      pacedVisibleTokenCount < tokenTotal
    ) {
      return true;
    }
    const revealDurationMs = resolveRevealDurationMsForTokens(
      revealTokens,
      DEFAULT_MESSAGE_MOOD,
      effectiveChatRevealTiming
    );
    return chatEphemeralNowMs - firstSeenAt < revealDurationMs;
  }, [
    chatAssistantTypingMechanicsActive,
    detail?.id,
    detail?.messages,
    effectiveChatRevealTiming,
    latestAssistantMessageId,
    chatEphemeralNowMs,
  ]);

  type ActiveAssistantRevealInterruption = {
    conversationId: string;
    assistantMessageId: string;
    revealKey: string;
    visibleTokenCount: number;
    totalTokenCount: number;
    interruptedText: string;
    interruptionContent: string;
    patchedDetail: ConversationDetail;
  };

  function prepareActiveAssistantRevealInterruption(): ActiveAssistantRevealInterruption | null {
    if (
      !chatAssistantTypingMechanicsActive ||
      !chatAssistantRevealInProgress ||
      !detail?.id ||
      !latestAssistantMessageId
    ) {
      return null;
    }
    const latestAssistant =
      detail.messages.find((message) => message.id === latestAssistantMessageId) ?? null;
    if (!latestAssistant) return null;

    const revealKey = `${detail.id}:${latestAssistantMessageId}`;
    const interruptedText = resolveMessageDisplayContent(latestAssistant);
    const revealTokens = tokenizeMessageReveal(interruptedText);
    const firstSeenAt = chatMessageFirstSeenAtRef.current.get(revealKey) ?? Date.now();
    const tokenTotal = Math.max(1, revealTokens.length);
    const pacedVisibleTokenCount =
      chatRevealPaceByKeyRef.current.get(revealKey)?.visibleTokenCount;
    const visibleTokenCount = Math.min(
      tokenTotal,
      typeof pacedVisibleTokenCount === "number"
        ? Math.max(1, pacedVisibleTokenCount)
        : resolveVisibleTokenCountAtElapsedMs(
            revealTokens,
            Math.max(0, Date.now() - firstSeenAt),
            latestAssistant.moodKey ?? DEFAULT_MESSAGE_MOOD,
            effectiveChatRevealTiming
          )
    );
    const interruptionContent = interruptedMidWordSnippet(
      interruptedText,
      visibleTokenCount
    );
    const interruptedAssistantIndex = detail.messages.findIndex(
      (message) => message.id === latestAssistantMessageId
    );
    if (interruptedAssistantIndex < 0) return null;
    const interruptedAssistant = detail.messages[interruptedAssistantIndex];
    if (!interruptedAssistant || interruptedAssistant.role !== "assistant") return null;
    const patchedInterruptedAssistant: Message = {
      ...interruptedAssistant,
      content: interruptionContent,
      moodKey: DEFAULT_MESSAGE_MOOD,
      moodConfidence: undefined,
      askQuestion: undefined,
      sentGeneratedImage: undefined,
    };
    return {
      conversationId: detail.id,
      assistantMessageId: latestAssistantMessageId,
      revealKey,
      visibleTokenCount,
      totalTokenCount: revealTokens.length,
      interruptedText,
      interruptionContent,
      patchedDetail: {
        ...detail,
        hasAssistantReply: true,
        messages: [
          ...detail.messages.slice(0, interruptedAssistantIndex),
          patchedInterruptedAssistant,
          ...detail.messages.slice(interruptedAssistantIndex + 1),
        ],
      },
    };
  }

  function applyActiveAssistantRevealInterruption(
    interruption: ActiveAssistantRevealInterruption
  ): Promise<PrismMoodSnapshot | undefined> | null {
    if (pendingReplyVisible) {
      setPendingReply(false);
      setPendingReplyStartedAtMs(null);
      setPendingReplyDenialRisk(false);
      setPendingReplyConversationId(null);
      setPendingReplyIsNewConversation(false);
      pendingReplyAbortControllerRef.current = null;
    }
    chatCommittedFontLineCountByKeyRef.current.set(
      interruption.revealKey,
      estimateVisualLineCount(interruption.interruptionContent)
    );
    chatCancelledRevealTokenCountByKeyRef.current.delete(interruption.revealKey);
    chatCompletedRevealKeysRef.current.add(interruption.revealKey);
    chatAssistantRevealEligibleKeysRef.current.delete(interruption.revealKey);
    chatRevealPaceByKeyRef.current.delete(interruption.revealKey);
    pulseChatInterruptionSettle(interruption.revealKey);
    setStarterComposerRevealed(false);
    setConversationStarterPrompts(null);
    // Freeze auto-scroll so the pause marker stays where the user interrupted
    // the reply instead of being chased by the dolly.
    chatAutoscrollArmedByConversationRef.current.set(interruption.conversationId, false);
    chatScrollPinnedByConversationRef.current.set(interruption.conversationId, true);
    const nextInterruptCount =
      (chatInterruptCountByConversationRef.current.get(interruption.conversationId) ?? 0) + 1;
    chatInterruptCountByConversationRef.current.set(
      interruption.conversationId,
      nextInterruptCount
    );
    if (chatEphemeralMode) {
      hardResetChatArchiveStateForConversation(interruption.conversationId);
    }
    setDetail((current) =>
      current?.id === interruption.conversationId
        ? interruption.patchedDetail
        : current
    );
    setChatEphemeralNowMs(Date.now());

    if (
      String(interruption.assistantMessageId).startsWith("pending-") ||
      interruption.conversationId === "pending"
    ) {
      return null;
    }
    return api<{ ok: true; prismMood?: PrismMoodSnapshot }>(
      `/api/messages/${encodeURIComponent(interruption.assistantMessageId)}/interrupt`,
      {
        method: "POST",
        body: JSON.stringify({
          content: interruption.interruptionContent,
          prismInterruption: {
            kind: "assistant_reveal",
            assistantMessageId: interruption.assistantMessageId,
            visibleTokenCount: interruption.visibleTokenCount,
            totalTokenCount: interruption.totalTokenCount,
          } satisfies PrismMoodInterruptionInput,
        }),
      }
    ).then(async (result) => {
      if (result.prismMood) {
        setDetail((current) =>
          current?.id === interruption.conversationId
            ? { ...current, prismMood: result.prismMood }
            : current
        );
      }
      await refreshOpenMemoryViews();
      return result.prismMood;
    });
  }

  const handleTypingIndicatorPress = useCallback((): void => {
    const interruption = prepareActiveAssistantRevealInterruption();
    if (!interruption) {
      if (pendingReplyVisible) {
        stopPendingReply();
      }
      return;
    }
    const persistPromise = applyActiveAssistantRevealInterruption(interruption);
    void persistPromise?.catch((err) => {
      setError(
        err instanceof Error
          ? err.message
          : "Prism was interrupted, but the saved thread could not be updated."
      );
    });
  }, [
    pendingReplyVisible,
    stopPendingReply,
    chatAssistantRevealInProgress,
    detail?.id,
    detail?.messages,
    latestAssistantMessageId,
    hardResetChatArchiveStateForConversation,
    chatAssistantTypingMechanicsActive,
    refreshOpenMemoryViews,
    view,
  ]);

  function finishActiveAssistantRevealForCompaction(): void {
    if (
      !chatAssistantTypingMechanicsActive ||
      !chatAssistantRevealInProgress ||
      !detail?.id ||
      !latestAssistantMessageId
    ) {
      return;
    }
    const latestAssistant =
      detail.messages.find((message) => message.id === latestAssistantMessageId) ?? null;
    if (!latestAssistant) return;
    const revealKey = `${detail.id}:${latestAssistantMessageId}`;
    if (!chatAssistantRevealEligibleKeysRef.current.has(revealKey)) return;
    const displayContent = resolveMessageDisplayContent(latestAssistant);
    chatCommittedFontLineCountByKeyRef.current.set(
      revealKey,
      Math.max(
        estimateVisualLineCount(displayContent),
        chatCommittedFontLineCountByKeyRef.current.get(revealKey) ?? 0
      )
    );
    chatCancelledRevealTokenCountByKeyRef.current.delete(revealKey);
    chatCompletedRevealKeysRef.current.add(revealKey);
    chatAssistantRevealEligibleKeysRef.current.delete(revealKey);
    chatRevealPaceByKeyRef.current.delete(revealKey);
    setChatEphemeralNowMs(Date.now());
  }

  function clearReplyWorkForManualCompaction(): void {
    const starterRequest = zenInitialStarterRequestRef.current;
    if (starterRequest) {
      starterRequest.cancelled = true;
      starterRequest.replayWhenReady = false;
    }
    queuedPromptDrainGenerationRef.current += 1;
    setQueuedChatPrompts([]);
    setDispatchingQueuedPrompt(null);
    zenInitialThinkingCancelControllerRef.current = null;
    manualCompactionCancelControllerRef.current = pendingReplyAbortControllerRef.current;
    stopPendingReply();
    finishActiveAssistantRevealForCompaction();
  }

  const handleZenInitialReplyRevealCancel = useCallback(
    (event?: React.MouseEvent<HTMLButtonElement>): void => {
      event?.preventDefault();
      event?.stopPropagation();
      zenInitialStarterLiveEnvelopeRef.current = null;
      clearZenInitialStarterReplyCache();
      handleTypingIndicatorPress();
    },
    [clearZenInitialStarterReplyCache, handleTypingIndicatorPress]
  );

  const zenAssistantReplyCount = useMemo(
    () =>
      detail?.messages.reduce(
        (count, message) => count + (message.role === "assistant" ? 1 : 0),
        0
      ) ?? 0,
    [detail?.messages]
  );
  const zenInitialThinkingActive =
    view === "chat" &&
    zenInitialStarterOverlayActive &&
    pendingReplyVisible &&
    pendingReplyStartMessageCount === 0 &&
    detail?.hasAssistantReply !== true;
  const zenInitialReplyRevealActive =
    view === "chat" &&
    zenInitialStarterOverlayActive &&
    chatAssistantRevealInProgress &&
    pendingReplyStartMessageCount === 0 &&
    zenAssistantReplyCount <= 1;
  useEffect(() => {
    if (zenInitialThinkingActive || zenInitialReplyRevealActive) return;
    zenInitialStatusLabelRef.current = null;
  }, [zenInitialReplyRevealActive, zenInitialThinkingActive]);

  const replyInFlightSignals =
    pendingReplyVisible || chatAssistantRevealInProgress;
  const replyRunwayActive = chatLikeSurface && replyInFlightSignals;
  /** Chat shows the pill during stream + during word-reveal; Sandbox zen only during live API stream (same as ordinary Sandbox stop). */
  const typingIndicatorVisible =
    (pendingReplyVisible && !zenInitialThinkingActive) ||
    (chatEphemeralMode &&
      chatAssistantRevealInProgress &&
      !zenInitialReplyRevealActive);
  const typingIndicatorNode = useMemo(() => {
    if (!typingIndicatorVisible) return null;
    const pendingRespondent =
      composeBotAccentId !== null
        ? bots.find((b) => b.id === composeBotAccentId)
        : null;
    const displayName =
      pendingRespondent?.name?.trim() ??
      headerIdentity?.name ??
      DEFAULT_ASSISTANT_NAME;
    const salt = `${composeBotAccentId ?? "none"}:${detail?.messages.length ?? 0}:${pendingReplyConversationId ?? "new"}`;
    const showFallbackCheckerboardRing =
      chatAssistantRevealInProgress &&
      (
        pendingReplyLikelyFallbackProcessing ||
        (latestAssistantMessageId !== null && fallbackMessageIds.has(latestAssistantMessageId))
      );
    // Keep the "gathering" phase varied, but make active typed reveal explicit.
    const label = chatAssistantRevealInProgress
      ? `${displayName} is replying…`
      : pickGeneratingLabel(displayName, salt);
    const style = selectedComposeBotAccent
      ? ({ ["--typing-accent" as string]: selectedComposeBotAccent } as React.CSSProperties)
      : undefined;
    return (
      <button
        type="button"
        className={`${styles.typingIndicator} ${
          chatLikeSurface ? styles.typingIndicatorChatCenter : ""
        } ${styles.typingIndicatorStopButton} ${
          chatAssistantRevealInProgress ? styles.typingIndicatorReplyingLive : ""
        } ${
          showFallbackCheckerboardRing ? styles.typingIndicatorFallbackProcessing : ""
        }`}
        style={style}
        aria-label={`${label}. Tap or click to stop.`}
        title="Stop reply"
        onClick={handleTypingIndicatorPress}
      >
        <span>{label}</span>
        <span className={styles.typingDots} aria-hidden="true">
          <span />
          <span />
          <span />
        </span>
      </button>
    );
  }, [
    pendingReplyVisible,
    chatAssistantRevealInProgress,
    chatEphemeralMode,
    composeBotAccentId,
    bots,
    headerIdentity?.name,
    detail?.messages.length,
    pendingReplyConversationId,
    pendingReplyLikelyFallbackProcessing,
    latestAssistantMessageId,
    fallbackMessageIds,
    view,
    selectedComposeBotAccent,
    chatLikeSurface,
    handleTypingIndicatorPress,
  ]);
  const zenInitialThinkingNode = useMemo(() => {
    const active = zenInitialThinkingActive || zenInitialReplyRevealActive;
    if (!active) return null;
    const compactPhase = zenInitialReplyRevealActive && !zenInitialThinkingActive;
    if (!zenInitialStatusLabelRef.current) {
      const outputSalt = [
        pendingReplyStartedAtMs ?? "no-start",
        pendingReplyConversationId ?? "new",
        detail?.id ?? "pending",
        latestAssistantMessageId ?? "no-assistant",
        detail?.messages.length ?? 0,
      ].join(":");
      zenInitialStatusLabelRef.current = pickStableStatusLabel(
        ZEN_INITIAL_STATUS_LABELS,
        outputSalt
      );
    }
    const label = zenInitialStatusLabelRef.current;
    const onActivate = compactPhase
      ? handleZenInitialReplyRevealCancel
      : handleZenInitialThinkingCancel;
    return (
      <div
        className={styles.zenInitialThinkingOverlay}
        data-phase={compactPhase ? "compact" : "thinking"}
        role="status"
        aria-live="polite"
      >
        <button
          type="button"
          className={styles.zenInitialThinkingButton}
          onPointerDown={(event) => {
            if (event.pointerType === "mouse" && event.button !== 0) return;
            event.preventDefault();
            event.stopPropagation();
            onActivate();
          }}
          onClick={(event) => {
            if (event.detail !== 0) {
              event.preventDefault();
              event.stopPropagation();
              return;
            }
            onActivate(event);
          }}
          aria-label={
            compactPhase
              ? "Stop reply"
              : "Cancel reply and return to the Zen start"
          }
          title={compactPhase ? "Stop reply" : "Cancel reply"}
        >
          <span className={styles.zenInitialThinkingGlyphHalo} aria-hidden="true">
            <PrismTriangleMark className={styles.zenInitialThinkingGlyph} />
          </span>
          <span className={styles.zenInitialThinkingLabel}>{label}</span>
        </button>
      </div>
    );
  }, [
    handleZenInitialReplyRevealCancel,
    handleZenInitialThinkingCancel,
    detail?.id,
    detail?.messages.length,
    latestAssistantMessageId,
    pendingReplyConversationId,
    pendingReplyStartedAtMs,
    zenInitialReplyRevealActive,
    zenInitialThinkingActive,
  ]);
  const sandboxSummaryIndicatorNode = useMemo(() => {
    if (view !== "sandbox") return null;
    const showCompactionSpinner = sandboxSummaryBusy && !pendingReplyVisible;
    if (!showCompactionSpinner) return null;
    const label = "Summarizing conversation context";
    const style = selectedComposeBotAccent
      ? ({ ["--typing-accent" as string]: selectedComposeBotAccent } as React.CSSProperties)
      : undefined;
    return (
      <div
        className={styles.typingIndicator}
        style={style}
        role="status"
        aria-live="polite"
        aria-label={label}
      >
        <span className={styles.summarySpinnerWheel} aria-hidden="true" />
        <span>{label}</span>
      </div>
    );
  }, [
    sandboxSummaryBusy,
    view,
    pendingReplyVisible,
    selectedComposeBotAccent,
  ]);
  const manualCompactionIndicatorNode = useMemo(() => {
    const activeConversationId =
      detail?.id && detail.id !== "pending" ? detail.id : selectedId;
    const activeMode: "zen" | "sandbox" = view === "chat" ? "zen" : "sandbox";
    if (
      !manualCompactionStatus ||
      manualCompactionStatus.conversationId !== activeConversationId ||
      manualCompactionStatus.mode !== activeMode
    ) {
      return null;
    }
    const style = selectedComposeBotAccent
      ? ({ ["--typing-accent" as string]: selectedComposeBotAccent } as React.CSSProperties)
      : undefined;
    const running = manualCompactionStatus.state === "running";
    const label = running
      ? "Compacting this chat context"
      : "Compacted context is ready";
    return (
      <div
        className={`${styles.askQuestionRecallBubbleDock} ${styles.manualCompactionDock}`}
        data-compaction-state={manualCompactionStatus.state}
      >
        <div
          className={`${styles.typingIndicator} ${styles.manualCompactionIndicator}`}
          style={style}
          role="status"
          aria-live="polite"
          aria-label={label}
        >
          {running ? (
            <span className={styles.summarySpinnerWheel} aria-hidden="true" />
          ) : null}
          <span>{label}</span>
        </div>
      </div>
    );
  }, [
    detail?.id,
    manualCompactionStatus,
    selectedComposeBotAccent,
    selectedId,
    view,
  ]);
  const copyAtmospherePromptToClipboard = useCallback(async (promptText: string) => {
    const trimmedPrompt = promptText.trim();
    if (!trimmedPrompt) return;
    try {
      await writeClipboardText(trimmedPrompt);
      setCopiedAtmospherePromptText(trimmedPrompt);
      if (copiedAtmospherePromptTimerRef.current) {
        clearTimeout(copiedAtmospherePromptTimerRef.current);
      }
      copiedAtmospherePromptTimerRef.current = setTimeout(() => {
        setCopiedAtmospherePromptText((current) =>
          current === trimmedPrompt ? null : current
        );
        copiedAtmospherePromptTimerRef.current = null;
      }, MESSAGE_COPY_FEEDBACK_MS);
    } catch {
      setError("Copy failed. Select the Atmosphere prompt and copy it manually.");
    }
  }, []);

  const compactedSummaryDebugFloatingEnabled =
    viewportWidth >= COMPACTED_SUMMARY_DEBUG_PANEL_FLOATING_MIN_VIEWPORT_WIDTH;
  const compactedSummaryDebugPanelStyle = useMemo(
    () =>
      ({
        "--compacted-summary-debug-left": `${compactedSummaryDebugPanelRect.x}px`,
        "--compacted-summary-debug-top": `${compactedSummaryDebugPanelRect.y}px`,
        "--compacted-summary-debug-width": `${compactedSummaryDebugPanelRect.width}px`,
        "--compacted-summary-debug-height": `${compactedSummaryDebugPanelRect.height}px`,
      }) as React.CSSProperties,
    [compactedSummaryDebugPanelRect]
  );
  const startCompactedSummaryDebugPanelDrag = useCallback(
    (event: React.PointerEvent<HTMLDivElement>) => {
      if (!compactedSummaryDebugFloatingEnabled || event.button !== 0) return;
      const target = event.target;
      if (
        target instanceof Element &&
        target.closest("button, a, input, textarea, select, [role='button']")
      ) {
        return;
      }
      const panel = compactedSummaryDebugDockRef.current;
      if (!panel) return;
      const rect = panel.getBoundingClientRect();
      compactedSummaryDebugPanelDragRef.current = {
        pointerId: event.pointerId,
        offsetX: event.clientX - rect.left,
        offsetY: event.clientY - rect.top,
      };

      try {
        event.currentTarget.setPointerCapture(event.pointerId);
      } catch {
        // Pointer capture is missing in some test environments.
      }
      event.preventDefault();
    },
    [compactedSummaryDebugFloatingEnabled]
  );
  const dragCompactedSummaryDebugPanel = useCallback(
    (event: React.PointerEvent<HTMLDivElement>) => {
      const dragState = compactedSummaryDebugPanelDragRef.current;
      if (!dragState || dragState.pointerId !== event.pointerId) return;
      const panel = compactedSummaryDebugDockRef.current;
      if (!panel) return;

      const rect = panel.getBoundingClientRect();
      const next = clampCompactedSummaryDebugPanelRect(
        {
          x: event.clientX - dragState.offsetX,
          y: event.clientY - dragState.offsetY,
          width: rect.width,
          height: rect.height,
        },
        window.innerWidth,
        window.innerHeight
      );
      panel.style.setProperty("--compacted-summary-debug-left", `${next.x}px`);
      panel.style.setProperty("--compacted-summary-debug-top", `${next.y}px`);
      panel.style.setProperty("--compacted-summary-debug-width", `${next.width}px`);
      panel.style.setProperty("--compacted-summary-debug-height", `${next.height}px`);
      setCompactedSummaryDebugPanelRect(next);
    },
    []
  );
  const endCompactedSummaryDebugPanelDrag = useCallback(
    (event: React.PointerEvent<HTMLDivElement>) => {
      const dragState = compactedSummaryDebugPanelDragRef.current;
      if (!dragState || dragState.pointerId !== event.pointerId) return;
      compactedSummaryDebugPanelDragRef.current = null;

      try {
        event.currentTarget.releasePointerCapture(event.pointerId);
      } catch {
        // Safe no-op for environments without pointer capture support.
      }
    },
    []
  );

  useEffect(() => {
    if (!compactedSummaryDebugFloatingEnabled) return;
    setCompactedSummaryDebugPanelRect((current) => {
      const next = clampCompactedSummaryDebugPanelRect(
        current,
        viewportWidth,
        viewportHeight
      );
      return next.x === current.x &&
        next.y === current.y &&
        next.width === current.width &&
        next.height === current.height
        ? current
        : next;
    });
  }, [compactedSummaryDebugFloatingEnabled, viewportHeight, viewportWidth]);

  useEffect(() => {
    if (
      !compactedSummaryDebugFloatingEnabled ||
      compactedSummaryDebugMinimized ||
      !devShowCompactedSummaryInChat
    ) {
      return;
    }
    const panel = compactedSummaryDebugDockRef.current;
    if (!panel || typeof ResizeObserver === "undefined") return;

    const resizeObserver = new ResizeObserver(([entry]) => {
      const width = Math.round(entry.contentRect.width);
      const height = Math.round(entry.contentRect.height);
      setCompactedSummaryDebugPanelRect((current) => {
        if (Math.abs(width - current.width) < 1 && Math.abs(height - current.height) < 1) {
          return current;
        }
        return clampCompactedSummaryDebugPanelRect(
          { ...current, width, height },
          viewportWidth,
          viewportHeight
        );
      });
    });
    resizeObserver.observe(panel);
    return () => resizeObserver.disconnect();
  }, [
    compactedSummaryDebugFloatingEnabled,
    compactedSummaryDebugMinimized,
    devShowCompactedSummaryInChat,
    viewportHeight,
    viewportWidth,
  ]);

  const compactedSummaryDebugNode = useMemo(() => {
    if (!DEV_TOOLS_ENABLED || !devShowCompactedSummaryInChat) return null;
    if (view !== "chat" || !activeZenConversationId) return null;
    const summaryFromManual =
      manualCompactionStatus?.conversationId === activeZenConversationId &&
      (manualCompactionStatus.mode === "zen" || manualCompactionStatus.mode === "chat")
        ? manualCompactionStatus.summary
        : null;
    const displaySummaryText =
      currentZenDisplaySummary ||
      (summaryFromManual ?? "").trim() ||
      zenSessionBreak?.displaySummary ||
      null;
    const internalSummaryText =
      currentZenInternalSummary ||
      zenSessionBreak?.internalSummary ||
      null;
    const summaryText =
      displaySummaryText ||
      internalSummaryText ||
      "No compacted summary yet.";
    const showInternalSummary =
      Boolean(
        displaySummaryText &&
        internalSummaryText &&
        displaySummaryText.trim() !== internalSummaryText.trim()
      );
    const summaryAt =
      summaryDebugMatchesActiveZen
        ? summaryDebug.latestSummaryAt
        : manualCompactionStatus?.summaryAt ?? null;
    const latestAtmosphereEntry = zenAtmosphereTimeline.reduce<ZenWallpaperHistoryEntry | null>(
      (latest, entry) => {
        if (!entry.promptSeed?.trim()) return latest;
        if (!latest) return entry;
        const countDelta = entry.generationMessageCount - latest.generationMessageCount;
        if (countDelta !== 0) return countDelta > 0 ? entry : latest;
        return (entry.createdAt ?? "").localeCompare(latest.createdAt ?? "") > 0
          ? entry
          : latest;
      },
      null
    );
    const atmospherePromptText =
      latestAtmosphereEntry?.promptSeed?.trim() ||
      detail?.zenWallpaper?.promptSeed?.trim() ||
      null;
    const atmospherePromptCopyText = customAtmospherePromptEnabled
      ? customAtmospherePromptDraft.trim()
      : atmospherePromptText;
    const atmospherePromptLabel =
      customAtmospherePromptEnabled
        ? "custom /atmosphere"
        : latestAtmosphereEntry?.generationMessageCount !== undefined
        ? `message ${latestAtmosphereEntry.generationMessageCount}`
        : detail?.zenWallpaper?.generationMessageCount !== null &&
            detail?.zenWallpaper?.generationMessageCount !== undefined
          ? `message ${detail.zenWallpaper.generationMessageCount}`
          : null;
    return (
      <div
        ref={compactedSummaryDebugDockRef}
        className={styles.compactedSummaryDebugDock}
        role="note"
        data-floating={compactedSummaryDebugFloatingEnabled ? "true" : undefined}
        data-minimized={compactedSummaryDebugMinimized ? "true" : undefined}
        style={compactedSummaryDebugPanelStyle}
      >
        <div
          className={styles.compactedSummaryDebugBubble}
          data-minimized={compactedSummaryDebugMinimized ? "true" : undefined}
          data-empty={
            !displaySummaryText && !internalSummaryText && !atmospherePromptText
              && !customAtmospherePromptEnabled
              ? "true"
              : undefined
          }
        >
          <div
            className={styles.compactedSummaryDebugHeader}
            onPointerDown={startCompactedSummaryDebugPanelDrag}
            onPointerMove={dragCompactedSummaryDebugPanel}
            onPointerUp={endCompactedSummaryDebugPanelDrag}
            onPointerCancel={endCompactedSummaryDebugPanelDrag}
          >
            <div className={styles.compactedSummaryDebugTitle}>
              <strong>Compacted context</strong>
              <span>zen{summaryAt ? ` - ${summaryAt}` : ""}</span>
            </div>
            <button
              type="button"
              className={styles.compactedSummaryDebugMinimizeButton}
              aria-label={
                compactedSummaryDebugMinimized
                  ? "Expand compacted context"
                  : "Minimize compacted context"
              }
              aria-expanded={!compactedSummaryDebugMinimized}
              title={
                compactedSummaryDebugMinimized
                  ? "Expand compacted context"
                  : "Minimize compacted context"
              }
              data-glyph-tooltip={
                compactedSummaryDebugMinimized
                  ? "Expand compacted context"
                  : "Minimize compacted context"
              }
              onClick={() => {
                setCompactedSummaryDebugMinimized((current) => !current);
              }}
            >
              {compactedSummaryDebugMinimized ? (
                <Maximize2 aria-hidden="true" size={14} />
              ) : (
                <Minimize2 aria-hidden="true" size={14} />
              )}
            </button>
          </div>
          {compactedSummaryDebugMinimized ? null : (
            <>
              <pre>{summaryText}</pre>
              {showInternalSummary ? (
                <div className={styles.compactedSummaryDebugDetails}>
                  <span>Internal compact</span>
                  <pre>{internalSummaryText}</pre>
                </div>
              ) : null}
              <div
                className={styles.compactedSummaryDebugDetails}
                data-kind="atmosphere"
                data-custom={customAtmospherePromptEnabled ? "true" : undefined}
                data-copy-state={
                  atmospherePromptCopyText &&
                  copiedAtmospherePromptText === atmospherePromptCopyText
                    ? "copied"
                    : undefined
                }
              >
                <div className={styles.compactedSummaryDebugDetailsHeader}>
                  <span>
                    Atmosphere prompt
                    {atmospherePromptLabel ? ` - ${atmospherePromptLabel}` : ""}
                  </span>
                  <span className={styles.compactedSummaryDebugHeaderActions}>
                    <label className={styles.compactedSummaryDebugToggle}>
                      <input
                        type="checkbox"
                        checked={customAtmospherePromptEnabled}
                        onChange={(event) => {
                          const next = event.target.checked;
                          setCustomAtmospherePromptEnabled(next);
                          if (next) {
                            setCustomAtmospherePromptDraft("");
                          }
                        }}
                      />
                      Custom
                    </label>
                    <button
                      type="button"
                      className={styles.compactedSummaryDebugCopyButton}
                      disabled={!atmospherePromptCopyText}
                      title="Copy Atmosphere prompt to clipboard"
                      aria-label="Copy Atmosphere prompt to clipboard"
                      onClick={() => {
                        if (!atmospherePromptCopyText) return;
                        void copyAtmospherePromptToClipboard(atmospherePromptCopyText);
                      }}
                    >
                      {atmospherePromptCopyText &&
                      copiedAtmospherePromptText === atmospherePromptCopyText
                        ? "Copied"
                        : "Copy"}
                    </button>
                  </span>
                </div>
                {customAtmospherePromptEnabled ? (
                  <textarea
                    className={styles.compactedSummaryDebugPromptEditor}
                    value={customAtmospherePromptDraft}
                    onChange={(event) => setCustomAtmospherePromptDraft(event.target.value)}
                    placeholder="Type the exact Atmosphere prompt to test with /atmosphere..."
                    aria-label="Custom Atmosphere prompt"
                  />
                ) : (
                  <pre data-empty={atmospherePromptText ? undefined : "true"}>
                    {atmospherePromptText ?? "No Atmosphere prompt yet."}
                  </pre>
                )}
              </div>
            </>
          )}
        </div>
      </div>
    );
  }, [
    activeZenConversationId,
    compactedSummaryDebugMinimized,
    compactedSummaryDebugFloatingEnabled,
    compactedSummaryDebugPanelStyle,
    copiedAtmospherePromptText,
    copyAtmospherePromptToClipboard,
    currentZenDisplaySummary,
    currentZenInternalSummary,
    customAtmospherePromptDraft,
    customAtmospherePromptEnabled,
    detail?.zenWallpaper?.generationMessageCount,
    detail?.zenWallpaper?.promptSeed,
    detail?.id,
    devShowCompactedSummaryInChat,
    manualCompactionStatus,
    dragCompactedSummaryDebugPanel,
    endCompactedSummaryDebugPanelDrag,
    startCompactedSummaryDebugPanelDrag,
    summaryDebug,
    summaryDebugMatchesActiveZen,
    view,
    zenAtmosphereTimeline,
    zenSessionBreak,
  ]);
  // Metrics now live in the floating developer terminal, not inside the chat transcript.
  const devChatDebugEventsNode = null;

  const clearConversationUnread = useCallback((conversationId: string) => {
    setUnreadConversationIds(previous => {
      if (!previous.has(conversationId)) return previous;
      const next = new Set(previous);
      next.delete(conversationId);
      return next;
    });
    setUnreadConversationOrder(previous =>
      previous.includes(conversationId)
        ? previous.filter(id => id !== conversationId)
        : previous
    );
  }, []);

  const clearConversationGroupDragState = useCallback(() => {
    conversationGroupPointerDragRef.current = null;
    setDraggingConversationGroupKey(null);
  }, []);

  const abortConversationGroupPointerDrag = useCallback(() => {
    conversationGroupPointerDragRef.current = null;
    suppressConversationGroupClickRef.current = false;
    setDraggingConversationGroupKey(null);
  }, []);

  const moveConversationGroup = useCallback((
    draggedKey: string,
    targetKey: string,
    position: ConversationGroupDropPosition
  ) => {
    if (!user || draggedKey === targetKey) return;
    setConversationGroupOrder((previous) => {
      const knownKeys = new Set(availableConversationGroupKeys);
      const normalizedOrder = [
        ...previous.filter((key) => knownKeys.has(key)),
        ...availableConversationGroupKeys.filter((key) => !previous.includes(key)),
      ];
      const next = reorderConversationGroupKeys(
        normalizedOrder,
        draggedKey,
        targetKey,
        position
      );
      if (
        next.length === previous.length &&
        next.every((key, index) => key === previous[index])
      ) {
        return previous;
      }
      persistConversationGroupOrder(user.id, next);
      return next;
    });
  }, [availableConversationGroupKeys, user]);

  const conversationRowGlowStyle = useCallback((index: number): React.CSSProperties => {
    const estimatedRowStridePx = 42;
    const rowHeightPx = 36;
    const glowFalloffPx = 1200;
    const rowTopInViewport = Math.max(0, index * estimatedRowStridePx - conversationListScrollTop);
    // Linear intensity (no easing) so adjacent rows differ by a constant
    // delta and the gradient feels continuous across tiles. The raw
    // viewport-derived value is remapped from [0, 1] to [0, 0.45] so
    // the bottom of the list resolves to fully transparent fill and
    // the top peaks at a calm 45% color band.
    const baseIntensity = Math.max(0, Math.min(1, 1 - rowTopInViewport / glowFalloffPx));
    const privateDepthCurve = Math.pow(baseIntensity, 2.45);
    const privateGlareFactor = Math.max(0, (baseIntensity - 0.28) / 0.72);
    const privateGlareCurve = Math.pow(privateGlareFactor, 2.2);
    // Light mode should keep the top rows calmer (less dark/tinted) so
    // the first visible groups don't overpower the sidebar. Dark mode
    // keeps the original stronger depth envelope.
    const intensity = baseIntensity * (resolvedTheme === "light" ? 0.32 : 0.45);
    const baseFill = intensity * 60;
    const innerGlow = intensity * 90;
    const outerGlow = intensity * 40;
    const fillGlow = intensity * 22;
    // Bottom-of-list shade: pulls each row toward black as its row
    // color band fades out, so the very bottom rows feel slightly
    // darker than the sidebar surface instead of disappearing.
    const bottomShade = (1 - baseIntensity) * 14;
    // Anchor the diagonal "bright" and "counter" spots to absolute
    // viewport positions in the conversation list so each row only
    // exposes its own slice of a single continuous gradient.
    const sunYInRow = 4 - rowTopInViewport;
    const sunYPct = (sunYInRow / rowHeightPx) * 100;
    const counterYInRow = 320 - rowTopInViewport;
    const counterYPct = (counterYInRow / rowHeightPx) * 100;
    // Theme-aware text ramp matched to the fill intensity curve:
    // - Light mode: top/new rows are darker fills, so text should start
    //   light and taper darker as fill intensity drops.
    // - Dark mode: keep the existing near-black -> white ramp.
    const textChannel = resolvedTheme === "light"
      ? Math.round(42 + baseIntensity * 206)
      : Math.round(255 - baseIntensity * 244);
    const textChannelHex = textChannel.toString(16).padStart(2, "0");
    const rowText = `#${textChannelHex}${textChannelHex}${textChannelHex}`;
    const privateRowGlare = privateGlareCurve * 48;
    const privateRowTint = 2 + privateDepthCurve * 26;
    const privateRowTintSoft = privateRowTint * 0.45;
    const privateRowGlareHover = privateRowGlare > 0 ? Math.min(100, privateRowGlare + 10) : 0;
    const privateRowTintHover = Math.min(100, privateRowTint + 6);
    const privateRowTintSoftHover = privateRowTint * 0.62;
    const privateRowSurfaceOpacity = 68 + (1 - baseIntensity) * 30;
    const privateRowBgOpacity = 66 + (1 - baseIntensity) * 32;
    return {
      "--row-depth-base": `${baseFill.toFixed(1)}%`,
      "--row-depth-glow": `${innerGlow.toFixed(1)}%`,
      "--row-depth-glow-outer": `${outerGlow.toFixed(1)}%`,
      "--row-depth-fill": `${fillGlow.toFixed(1)}%`,
      "--row-depth-shade": `${bottomShade.toFixed(1)}%`,
      "--row-glow-y": `${sunYPct.toFixed(1)}%`,
      "--row-counter-y": `${counterYPct.toFixed(1)}%`,
      "--row-text-color": rowText,
      "--private-row-glare": `${privateRowGlare.toFixed(1)}%`,
      "--private-row-tint": `${privateRowTint.toFixed(1)}%`,
      "--private-row-tint-soft": `${privateRowTintSoft.toFixed(1)}%`,
      "--private-row-glare-hover": `${privateRowGlareHover.toFixed(1)}%`,
      "--private-row-tint-hover": `${privateRowTintHover.toFixed(1)}%`,
      "--private-row-tint-soft-hover": `${privateRowTintSoftHover.toFixed(1)}%`,
      "--private-row-surface-opacity": `${privateRowSurfaceOpacity.toFixed(1)}%`,
      "--private-row-bg-opacity": `${privateRowBgOpacity.toFixed(1)}%`,
    } as React.CSSProperties;
  }, [conversationListScrollTop, resolvedTheme]);

  const panelColorHarmonyActive = bots.length >= BOT_PANEL_COLOR_HARMONY_MIN_BOTS;
  // ── Coffee mode hooks ──
  // Keep these with the rest of HomeContent's top-level state/memos so
  // React's hook order stays stable across auth, hub, and mode returns.
  const [coffeeSelectedSeatBotIds, setCoffeeSelectedSeatBotIds] =
    useState<Array<string | null>>(() => emptyCoffeeSeatBotIds());
  const [coffeeConversation, setCoffeeConversation] =
    useState<CoffeeConversationState | null>(null);
  const [coffeeSelectedSessionId, setCoffeeSelectedSessionId] = useState<string | null>(null);
  const [coffeeGroups, setCoffeeGroups] = useState<CoffeeGroupState[]>([]);
  const [coffeeSelectedGroupId, setCoffeeSelectedGroupId] = useState<string | null>(null);
  const [coffeeCollapsedGroupIds, setCoffeeCollapsedGroupIds] = useState<Set<string>>(
    () => new Set()
  );
  const [coffeeGroupsLoading, setCoffeeGroupsLoading] = useState(false);
  const [coffeePresets, setCoffeePresets] = useState<CoffeePresetState[]>([]);
  const [coffeePresetsLoading, setCoffeePresetsLoading] = useState(false);
  const [coffeeSelectedDurationMinutes, setCoffeeSelectedDurationMinutes] =
    useState<CoffeeSessionDurationMinutes>(COFFEE_DEFAULT_SESSION_DURATION_MINUTES);
  const [coffeeSelectedPresetId, setCoffeeSelectedPresetId] = useState("");
  const [coffeeOpeningPollModalOpen, setCoffeeOpeningPollModalOpen] = useState(false);
  const [coffeeOpeningPollQuestion, setCoffeeOpeningPollQuestion] = useState("");
  const [coffeeOpeningPollOptions, setCoffeeOpeningPollOptions] = useState<string[]>(() =>
    buildDefaultCoffeePollOptionDraft()
  );
  const [coffeeActivePoll, setCoffeeActivePoll] = useState<CoffeePollState | null>(null);
  const coffeeActivePollRef = useRef<CoffeePollState | null>(null);
  const [coffeePollResultsOpen, setCoffeePollResultsOpen] = useState(false);
  const [coffeePollPanelMinimized, setCoffeePollPanelMinimized] = useState(false);
  const [coffeePollVoteBusy, setCoffeePollVoteBusy] = useState(false);
  const [coffeePollPanelPosition, setCoffeePollPanelPosition] =
    useState<CoffeePollPanelPosition>(COFFEE_POLL_PANEL_DEFAULT_POSITION);
  const coffeePollPanelRef = useRef<HTMLDivElement | null>(null);
  const coffeePollBubbleRef = useRef<HTMLButtonElement | null>(null);
  const coffeePollPanelDragRef = useRef<CoffeePollPanelDragState | null>(null);
  const coffeePollPanelSuppressClickRef = useRef(false);
  const [coffeeSettingsModalOpen, setCoffeeSettingsModalOpen] = useState(false);
  const [coffeeSettingsDraft, setCoffeeSettingsDraft] = useState<CoffeeSessionSettings>(() =>
    loadCoffeeSettingsFromBrowser()
  );
  const [coffeeGroupNameDraft, setCoffeeGroupNameDraft] = useState("");
  const [coffeePresetNameDraft, setCoffeePresetNameDraft] = useState("");
  const [coffeeSettingsSaving, setCoffeeSettingsSaving] = useState(false);
  const [coffeeGroupOverviewRenameBusy, setCoffeeGroupOverviewRenameBusy] = useState(false);
  const [coffeeAutoTopicToggleBusy, setCoffeeAutoTopicToggleBusy] = useState(false);
  const [coffeeSearch, setCoffeeSearch] = useState("");
  const [coffeeDraft, setCoffeeDraft] = useState<string>("");
  const coffeeComposerRichRef = useRef<DesktopMarkdownComposerHandle | null>(null);
  const coffeeComposerFormRef = useRef<HTMLFormElement | null>(null);
  const coffeeLastSubmittedDraftRef = useRef<string | null>(null);
  const coffeeMentionBotsRef = useRef<BotMentionPick[]>([]);
  const [coffeeBusy, setCoffeeBusy] = useState<boolean>(false);
  const [coffeeAutoBusy, setCoffeeAutoBusy] = useState<boolean>(false);
  const [coffeePausedSessionIds, setCoffeePausedSessionIds] = useState<Set<string>>(() =>
    loadCoffeePausedSessionIdsFromBrowser()
  );
  const [coffeePausedSessionRemainingMsById, setCoffeePausedSessionRemainingMsById] = useState<
    Record<string, number>
