  async function refreshZenSessionMemory() {
    const conversationId =
      detailIdRef.current && detailIdRef.current !== "pending"
        ? detailIdRef.current
        : selectedIdRef.current;
    const query = conversationId
      ? `?conversationId=${encodeURIComponent(conversationId)}`
      : "";
    const d = await api<ZenSessionMemoryOverview>(`/api/zen/session-memory${query}`);
    setZenPreviousContext(d.previousContext ?? null);
    setZenSessionMemories(d.sessionMemories ?? []);
  }
  async function refreshPrismMemoryPanel() {
    await refreshDefaultMemories();
    if (view === "chat") {
      await refreshZenSessionMemory();
    }
  }
  async function runMemoryPanelLoad(
    label: string,
    load: () => Promise<void>
  ): Promise<boolean> {
    const runId = memoryPanelLoadRunRef.current + 1;
    memoryPanelLoadRunRef.current = runId;
    const isCurrent = () => memoryPanelLoadRunRef.current === runId;
    const shouldShowLoading = panel === "memories";

    setPanelError(null);
    setMemoryPanelLoadingText(label);
    if (shouldShowLoading) {
      setMemoryPanelLoading(true);
    }

    try {
      await load();
      return true;
    } catch (err) {
      if (isCurrent()) {
        setPanelError(err instanceof Error ? err.message : "Memory load failed.");
      }
      return false;
    } finally {
      if (isCurrent()) {
        setMemoryPanelLoading(false);
      }
    }
  }
  async function refreshOpenMemoryViews() {
    await refreshMemories();
    if (memoryPanelScope === "default") {
      await refreshPrismMemoryPanel();
    } else if (memoryPanelScope === "session") {
      await refreshZenSessionMemory();
    } else if (memoryPanelBot?.id) {
      await refreshBotMemories(memoryPanelBot.id);
    }
  }
  async function refreshSummaryDebug(modeOverride?: "zen" | "sandbox"): Promise<void> {
    const conversationId =
      detailIdRef.current && detailIdRef.current !== "pending"
        ? detailIdRef.current
        : selectedIdRef.current;
    if (!conversationId) {
      setSummaryDebug(null);
      return;
    }
    const modeForDebug =
      modeOverride ??
      (view === "chat" ? "zen" : "sandbox");
    try {
      const d = await api<{ debug: SummaryCompactionDebug }>(
        `/api/conversations/${encodeURIComponent(
          conversationId
        )}/summarization-debug?mode=${modeForDebug}`
      );
      setSummaryDebug(d.debug);
    } catch {
      // Developer-only surface; ignore read failures.
    }
  }
  const appendDevChatDebugLines = useCallback((entries: Array<{
    kind: DevChatDebugEvent["kind"];
    text: string;
  }>) => {
    if (!devChatMetricsEnabled || entries.length === 0) return;
    const createdAt = new Date().toISOString();
    const nextEvents = entries.map((entry, index) => ({
      id: `dev-metric-${createdAt}-${index}-${Math.random().toString(36).slice(2, 9)}`,
      createdAt,
      kind: entry.kind,
      text: entry.text,
    }));
    setDevChatDebugEvents((current) => [...current.slice(-60), ...nextEvents]);
  }, [devChatMetricsEnabled]);

  function collectDebugLinesFromEnvelope(
    envelope: ChatPostEnvelope,
    source: "send" | "edit"
  ): Array<{ kind: DevChatDebugEvent["kind"]; text: string }> {
    const lines: Array<{ kind: DevChatDebugEvent["kind"]; text: string }> = [];
    const prefix = source === "edit" ? "[edit]" : "[send]";
    for (const event of envelope.backendEvents ?? []) {
      lines.push({
        kind: devDebugKindForBackendEvent(event.kind),
        text: formatBackendDebugLine(prefix, event),
      });
    }
    if (envelope.summaryCompaction?.triggered) {
      const summaryPreview = envelope.summaryCompaction.latestSummary?.trim();
      lines.push({
        kind: "summary",
        text: `${prefix} summary (${envelope.summaryCompaction.mode}, ${envelope.summaryCompaction.reason}) triggered.`,
      });
      if (summaryPreview && summaryPreview.length > 0) {
        lines.push({ kind: "summary", text: `${prefix} summary text: ${summaryPreview}` });
      }
    }
    const createdMemories = envelope.memoryLearned?.created ?? [];
    const retractedMemories = envelope.memoryLearned?.retracted ?? [];
    const rejectedMemories = envelope.memoryLearned?.rejected ?? [];
    if (createdMemories.length > 0) {
      lines.push({
        kind: "memory",
        text: `${prefix} memories created (${createdMemories.length}): ${createdMemories
          .map((memory) => memory.text)
          .join(" | ")}`,
      });
    }
    if (retractedMemories.length > 0) {
      lines.push({
        kind: "memory",
        text: `${prefix} memories retracted (${retractedMemories.length}): ${retractedMemories
          .map((memory) => memory.text)
          .join(" | ")}`,
      });
    }
    if (rejectedMemories.length > 0) {
      lines.push({ kind: "memory", text: `${prefix} memories rejected (${rejectedMemories.length}).` });
    }
    if (envelope.opinion) {
      lines.push({
        kind: "opinion",
        text: `${prefix} session opinion: ${envelope.opinion.band} ${envelope.opinion.score}% (${envelope.opinion.trend})`,
      });
    }
    if (envelope.botOpinion) {
      lines.push({
        kind: "opinion",
        text: `${prefix} bot opinion: ${envelope.botOpinion.band} ${envelope.botOpinion.score}% (${envelope.botOpinion.trend})`,
      });
    }
    if (envelope.fallbackInvocation) {
      const invocation = envelope.fallbackInvocation;
      lines.push({
        kind: "summary",
        text:
          `${prefix} lenient fallback invoked (${invocation.trigger}). ` +
          `${invocation.primaryProvider}:${invocation.primaryModel} -> local:${invocation.fallbackModel}`,
      });
    }
    const toolCallEvents = envelope.toolCalls ?? [];
    for (const event of toolCallEvents) {
      lines.push({
        kind: "tool",
        text: formatChatToolCallDebugLine(prefix, event),
      });
    }
    if (envelope.pendingImageJob) {
      lines.push({
        kind: "tool",
        text:
          `${prefix} tool sendGeneratedImage queued — pending image job ` +
          `${envelope.pendingImageJob.jobId} ` +
          `(conversation ${envelope.pendingImageJob.conversationId ?? "incognito"})`,
      });
    }
    return lines;
  }
  function captureFallbackMessageIdFromEnvelope(envelope: ChatPostEnvelope): void {
    if (!envelope.fallbackInvocation) return;
    const latestAssistant = [...envelope.conversation.messages]
      .reverse()
      .find((message) => message.role === "assistant");
    if (!latestAssistant) return;
    setFallbackMessageIds((current) => {
      if (current.has(latestAssistant.id)) return current;
      const next = new Set(current);
      next.add(latestAssistant.id);
      return next;
    });
  }
  async function refreshBots() { const d = await api<{ bots: Bot[] }>("/api/bots"); setBots(d.bots); }
  async function refreshImages(botFilter?: string | null) {
    const path =
      botFilter === "general"
        ? "/api/images?general=1"
        : typeof botFilter === "string" && botFilter.length > 0
          ? `/api/images?botId=${encodeURIComponent(botFilter)}`
          : "/api/images";
    const filtered =
      botFilter === "general" ||
      (typeof botFilter === "string" && botFilter.length > 0);
    const d = await api<{ images: ImageRecord[] }>(path);
    setImages(d.images);
    if (!filtered) {
      setImageBotDirectorySnapshot(d.images);
    }
  }

  /** Zen mode: never load the global multi-bot mix into the Images grid. */
  async function refreshImagesChatGallery(): Promise<void> {
    if (chatScopedGalleryBotId) {
      await refreshImages(chatScopedGalleryBotId);
      return;
    }
    await refreshImages("general");
  }

  /** Refreshes bot tallies for the Images dropdown without changing the filtered grid. */
  async function refreshImageBotDirectorySnapshot(): Promise<void> {
    try {
      const d = await api<{ images: ImageRecord[] }>("/api/images");
      setImageBotDirectorySnapshot(d.images);
    } catch {
      /* Errors surface via other panel flows; directory tallies are best-effort. */
    }
  }

  async function deleteGalleryImage(img: ImageRecord) {
    setPanelError(null);
    setPanelNotice(null);
    try {
      await api(`/api/images/${encodeURIComponent(img.id)}`, { method: "DELETE" });
      setImagePrivateGeneratedIds((current) => current.filter((id) => id !== img.id));
      setImagePrivateRevealedIds((current) => {
        if (!current.has(img.id)) return current;
        const next = new Set(current);
        next.delete(img.id);
        return next;
      });
      setImageLightbox((current) => (current?.id === img.id ? null : current));
      if (imagePanelScope === "general") {
        await refreshImages("general");
      } else if (imagePanelScope === "bot" && imagePanelBotId) {
        await refreshImages(imagePanelBotId);
      } else if (view === "chat") {
        await refreshImagesChatGallery();
      } else {
        await refreshImages(null);
      }
      await refreshImageBotDirectorySnapshot();
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Could not delete image.");
    }
  }

  async function deleteAllGalleryImages() {
    if (imagesDeleteAllBusy) return;
    setImagesDeleteAllBusy(true);
    setPanelError(null);
    setPanelNotice(null);
    try {
      const isBotScopedDelete = imagePanelScope === "bot" && imagePanelBotId != null;
      const endpoint = isBotScopedDelete
        ? `/api/images?botId=${encodeURIComponent(imagePanelBotId)}`
        : "/api/images";
      const result = await api<{ ok: boolean; deleted?: number }>(endpoint, {
        method: "DELETE",
      });
      setImagePrivateGeneratedIds([]);
      setImagePrivateRevealedIds(new Set());
      setImageLightbox(null);
      if (imagePanelScope === "general") {
        await refreshImages("general");
      } else if (imagePanelScope === "bot" && imagePanelBotId) {
        await refreshImages(imagePanelBotId);
      } else if (view === "chat") {
        await refreshImagesChatGallery();
      } else {
        await refreshImages(null);
      }
      await refreshImageBotDirectorySnapshot();
      const deleted = typeof result.deleted === "number" ? result.deleted : 0;
      setPanelNotice(
        deleted === 0
          ? "No images to delete."
          : deleted === 1
            ? "Deleted 1 image."
            : `Deleted ${deleted} images.`
      );
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Could not delete images.");
    } finally {
      setImagesDeleteAllBusy(false);
      setImagesDeleteAllConfirmOpen(false);
    }
  }

  async function downloadGalleryImage(img: ImageRecord) {
    setPanelError(null);
    try {
      const resolvedBot =
        img.botId != null ? bots.find((b) => b.id === img.botId) : undefined;
      const botLabel =
        resolvedBot?.name ??
        (imagePanelScope === "bot" ? imagePanelBot?.name : null) ??
        (imagePanelScope === "general" ? "PRISM-general" : null) ??
        "bot";
      await downloadBotImageFile(img, botLabel);
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Could not download image.");
    }
  }

  useEffect(() => {
    if (!imagesDeleteAllConfirmOpen) return;
    const hasAnyImages =
      imagePanelScope === "bot"
        ? images.length > 0
        : Math.max(images.length, imageBotDirectorySnapshot.length) > 0;
    if (panel !== "images" || !hasAnyImages) {
      setImagesDeleteAllConfirmOpen(false);
    }
  }, [imagesDeleteAllConfirmOpen, panel, imagePanelScope, images.length, imageBotDirectorySnapshot.length]);

  useEffect(() => {
    setImagePrivateRevealedIds((current) => {
      if (current.size === 0) return current;
      const privateIdSet = new Set(imagePrivateGeneratedIds);
      const next = new Set<string>();
      for (const id of current) {
        if (privateIdSet.has(id)) next.add(id);
      }
      return next.size === current.size ? current : next;
    });
  }, [imagePrivateGeneratedIds]);

  useEffect(() => {
    if (!imageLightbox) return;
    function onKeyDown(event: KeyboardEvent) {
      if (event.key === "Escape") {
        event.preventDefault();
        setImageLightbox(null);
      }
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [imageLightbox]);
  async function openAllImagesPanel() {
    if (view === "chat" && privateChatActive) {
      setImagePrivateMode(true);
    }
    if (view === "chat") {
      if (chatScopedGalleryBotId) {
        const bot = bots.find((b) => b.id === chatScopedGalleryBotId);
        if (bot) {
          await openImagesPanelForBot(bot);
          return;
        }
      }
      setImagePanelScope("general");
      setImagePanelBotId(null);
      await refreshImages("general");
      await refreshImageBotDirectorySnapshot();
      openRightPanel("images");
      return;
    }
    setImagePanelScope("all");
    setImagePanelBotId(null);
    await refreshImages();
    openRightPanel("images");
  }

  async function openImagesPanelForBot(bot: Bot) {
    if (view === "chat" && privateChatActive) {
      setImagePrivateMode(true);
    }
    setImagePanelScope("bot");
    setImagePanelBotId(bot.id);
    await refreshImages(bot.id);
    await refreshImageBotDirectorySnapshot();
    openRightPanel("images");
  }

  /**
   * Opens the Images panel so `imageFormScopeKey` matches `scopeKey`
   * (conversation + bot identity used by `/api/images/generate`).
   * Used when generation is already in flight so the header Images control
   * always surfaces the blocking overlay instead of a fresh form scope.
   */
  async function openImagesPanelForScopeKey(scopeKey: string): Promise<void> {
    if (view === "chat" && privateChatActive) {
      setImagePrivateMode(true);
    }
    const { conversationId, botId } = parseImageGenerationScopeKey(scopeKey);
    if (conversationId.length > 0) {
      try {
        await refreshConversation(conversationId);
      } catch {
        // Stale key if the thread was deleted — still open Images for feedback.
      }
    }
    if (botId) {
      const bot = bots.find((b) => b.id === botId);
      if (bot) {
        await openImagesPanelForBot(bot);
        return;
      }
      setImagePanelScope("bot");
      setImagePanelBotId(botId);
      await refreshImages(botId);
      await refreshImageBotDirectorySnapshot();
      openRightPanel("images");
      return;
    }
    if (view === "chat") {
      setImagePanelScope("general");
      setImagePanelBotId(null);
      await refreshImages("general");
      await refreshImageBotDirectorySnapshot();
      openRightPanel("images");
      return;
    }
    setImagePanelScope("all");
    setImagePanelBotId(null);
    await refreshImages();
    await refreshImageBotDirectorySnapshot();
    openRightPanel("images");
  }

  useEffect(() => {
    if (panel !== "images" || view !== "chat") return;
    if (privateChatActive) {
      setImagePrivateMode(true);
    }
    if (imagePanelScope !== "all") return;
    let cancelled = false;
    void (async () => {
      if (chatScopedGalleryBotId) {
        const bot = bots.find((b) => b.id === chatScopedGalleryBotId);
        if (bot) {
          setImagePanelScope("bot");
          setImagePanelBotId(chatScopedGalleryBotId);
          await refreshImages(chatScopedGalleryBotId);
        } else {
          setImagePanelScope("general");
          setImagePanelBotId(null);
          await refreshImages("general");
        }
      } else {
        setImagePanelScope("general");
        setImagePanelBotId(null);
        await refreshImages("general");
      }
      if (!cancelled) await refreshImageBotDirectorySnapshot();
    })();
    return () => {
      cancelled = true;
    };
  }, [panel, view, imagePanelScope, chatScopedGalleryBotId, bots, privateChatActive]);

  async function runMemoryTransition(
    work: () => void | Promise<void>,
    direction: "forward" | "backward",
  ) {
    // A monotonic run id lets a fresher navigation pre-empt an older one
    // (e.g. rapid back-back-back) without the older run flipping the
    // phase back to "idle" out from under it.
    const runId = memoryTransitionRunRef.current + 1;
    memoryTransitionRunRef.current = runId;
    const isCurrent = () => memoryTransitionRunRef.current === runId;

    setMemoryTransitionDirection(direction);
    setMemoryTransitionPhase("exiting");

    await new Promise<void>((resolve) =>
      window.setTimeout(resolve, MEMORY_TRANSITION_EXIT_MS),
    );
    if (!isCurrent()) return;

    try {
      await work();
    } catch (err) {
      if (isCurrent()) setMemoryTransitionPhase("idle");
      throw err;
    }
    if (!isCurrent()) return;

    // Give React one frame to commit the new content at the enter
    // animation's keyframe-0 (scaled + transparent) before we trigger the
    // animation. Without this, the new content can flash at full size.
    await new Promise<void>((resolve) =>
      window.requestAnimationFrame(() => resolve()),
    );
    if (!isCurrent()) return;

    setMemoryTransitionPhase("entering");

    await new Promise<void>((resolve) =>
      window.setTimeout(resolve, MEMORY_TRANSITION_ENTER_MS),
    );
    if (!isCurrent()) return;

    setMemoryTransitionPhase("idle");
  }

  async function submitAuth(e: React.FormEvent) {
    e.preventDefault(); setBusy(true); setError(null);
    try {
      const normalizedUsername = normalizeAuthUsername(username);
      if (!normalizedUsername) {
        throw new Error("Username is required.");
      }
      if (authMode === "register") {
        if (password !== confirmPassword) {
          throw new Error("Passwords do not match.");
        }
        await api("/api/auth/register", {
          method: "POST",
          body: JSON.stringify({ username: normalizedUsername, password, theme: preAuthTheme }),
        });
      } else {
        await api("/api/auth/login", {
          method: "POST",
          body: JSON.stringify({ username: normalizedUsername, password }),
        });
      }
      clearNativeSessionToken();
      await bootstrap();
      setUsername(normalizedUsername);
      setPassword("");
      setConfirmPassword("");
    } catch (err) { setError(err instanceof Error ? err.message : "Auth failed."); }
    finally { setBusy(false); }
  }

  async function logout() {
    await api("/api/auth/logout", { method: "POST", body: "{}" });
    clearNativeSessionToken();
    setUser(null);
    setPreAuthChecklistComplete(false);
    setConversations([]);
    setDetail(null);
    setSessionOpinion(null);
    setBotOpinion(null);
    setMemories([]);
    setBotMemories([]);
    setSettings(null);
    setModelCatalog(null);
    setBots([]);
    setImages([]);
    // Drop any ?view= param so the next login lands on the Hub instead
    // of whichever mode the user was last browsing.
    navigateToView("hub");
  }

